using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        // Calculate header metrics
        var totalValue = holdings.Sum(h => h.TotalValue);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken);
            var totalValue = holding.Quantity * currentPrice;
            var totalInvested = holding.Quantity * holding.AverageCost;

            var holdingDto = new HoldingDto
            {
                Id = holding.Id,
                Ticker = holding.Ticker,
                EtfName = holding.EtfName,
                Quantity = holding.Quantity,
                AverageCost = holding.AverageCost,
                CurrentPrice = currentPrice,
                TotalValue = totalValue,
                DailyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 1, cancellationToken),
                WeeklyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 7, cancellationToken),
                MonthlyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 30, cancellationToken),
                YtdMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, DaysSinceYearStart(), cancellationToken)
            };

            holdingDtos.Add(holdingDto);
        }

        return holdingDtos;
    }

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderByDescending(t => t.PurchaseDate)
            .Select(t => new TransactionDto
            {
                Id = t.Id,
                HoldingId = t.HoldingId,
                Quantity = t.Quantity,
                PurchasePrice = t.PurchasePrice,
                PurchaseDate = t.PurchaseDate,
                CreatedAt = t.CreatedAt
            })
            .ToListAsync(cancellationToken);

        return transactions;
    }

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var transaction = await _context.Database.BeginTransactionAsync(cancellationToken);

        try
        {
            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                holding = new Holding
                {
                    UserId = userId,
                    Ticker = dto.Ticker,
                    Quantity = 0,
                    AverageCost = 0
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Add transaction
            var newTransaction = new Transaction
            {
                HoldingId = holding.Id,
                Quantity = dto.Quantity,
                PurchasePrice = dto.PurchasePrice,
                PurchaseDate = dto.PurchaseDate
            };
            _context.Transactions.Add(newTransaction);
            await _context.SaveChangesAsync(cancellationToken);

            // Update holding average cost and quantity
            var allTransactions = await _context.Transactions
                .Where(t => t.HoldingId == holding.Id)
                .ToListAsync(cancellationToken);

            var totalQuantity = allTransactions.Sum(t => t.Quantity);
            var totalCost = allTransactions.Sum(t => t.Quantity * t.PurchasePrice);

            holding.Quantity = totalQuantity;
            holding.AverageCost = totalQuantity > 0 ? totalCost / totalQuantity : 0;
            holding.UpdatedAt = DateTime.UtcNow;

            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);

            await transaction.CommitAsync(cancellationToken);
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal totalInvested, int days, CancellationToken cancellationToken)
    {
        var currentPrice = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!priceFromDaysAgo.HasValue)
        {
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0 };
        }

        var totalValue = Decimal.MaxValue; // Quantity would be needed, using placeholder
        var gainLossEur = totalValue - totalInvested;
        var gainLossPercent = priceFromDaysAgo.Value > 0 
            ? ((currentPrice - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100 
            : 0;

        return new PeriodMetrics
        {
            GainLossEur = gainLossEur,
            GainLossPercent = gainLossPercent
        };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        // Try to get exact date first
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null)
            return snapshot.Price;

        // If not found, get the closest earlier snapshot
        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;

        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private int DaysSinceYearStart()
    {
        var today = DateTime.UtcNow.Date;
        var yearStart = new DateTime(today.Year, 1, 1);
        return (today - yearStart).Days;
    }
}

using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        // Calculate header metrics
        var totalValue = holdings.Sum(h => h.TotalValue);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken);
            var totalValue = holding.Quantity * currentPrice;
            var totalInvested = holding.Quantity * holding.AverageCost;

            var holdingDto = new HoldingDto
            {
                Id = holding.Id,
                Ticker = holding.Ticker,
                EtfName = holding.EtfName,
                Quantity = holding.Quantity,
                AverageCost = holding.AverageCost,
                CurrentPrice = currentPrice,
                TotalValue = totalValue,
                DailyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 1, cancellationToken),
                WeeklyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 7, cancellationToken),
                MonthlyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 30, cancellationToken),
                YtdMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, DaysSinceYearStart(), cancellationToken)
            };

            holdingDtos.Add(holdingDto);
        }

        return holdingDtos;
    }

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderByDescending(t => t.PurchaseDate)
            .Select(t => new TransactionDto
            {
                Id = t.Id,
                HoldingId = t.HoldingId,
                Quantity = t.Quantity,
                PurchasePrice = t.PurchasePrice,
                PurchaseDate = t.PurchaseDate,
                CreatedAt = t.CreatedAt
            })
            .ToListAsync(cancellationToken);

        return transactions;
    }

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var transaction = await _context.Database.BeginTransactionAsync(cancellationToken);

        try
        {
            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                holding = new Holding
                {
                    UserId = userId,
                    Ticker = dto.Ticker,
                    Quantity = 0,
                    AverageCost = 0
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Add transaction
            var newTransaction = new Transaction
            {
                HoldingId = holding.Id,
                Quantity = dto.Quantity,
                PurchasePrice = dto.PurchasePrice,
                PurchaseDate = dto.PurchaseDate
            };
            _context.Transactions.Add(newTransaction);
            await _context.SaveChangesAsync(cancellationToken);

            // Update holding average cost and quantity
            var allTransactions = await _context.Transactions
                .Where(t => t.HoldingId == holding.Id)
                .ToListAsync(cancellationToken);

            var totalQuantity = allTransactions.Sum(t => t.Quantity);
            var totalCost = allTransactions.Sum(t => t.Quantity * t.PurchasePrice);

            holding.Quantity = totalQuantity;
            holding.AverageCost = totalQuantity > 0 ? totalCost / totalQuantity : 0;
            holding.UpdatedAt = DateTime.UtcNow;

            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);

            await transaction.CommitAsync(cancellationToken);
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal quantity, int days, CancellationToken cancellationToken)
    {
        var currentPrice = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!priceFromDaysAgo.HasValue)
        {
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0 };
        }

        var gainLossEur = (currentPrice - priceFromDaysAgo.Value) * quantity;
        var gainLossPercent = priceFromDaysAgo.Value > 0 
            ? ((currentPrice - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100 
            : 0;

        return new PeriodMetrics
        {
            GainLossEur = gainLossEur,
            GainLossPercent = gainLossPercent
        };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        // Try to get exact date first
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null)
            return snapshot.Price;

        // If not found, get the closest earlier snapshot
        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;

        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private int DaysSinceYearStart()
    {
        var today = DateTime.UtcNow.Date;
        var yearStart = new DateTime(today.Year, 1, 1);
        return (today - yearStart).Days;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Services;

namespace ETFTracker.Api.Controllers;

/// <summary>
/// Handles ETF holdings management, portfolio data, and transaction history.
/// Requires JWT authentication.
/// </summary>
[Authorize]
[ApiController]
[Route("api/[controller]")]
public class HoldingsController : ControllerBase
{
    private readonly IHoldingsService _holdingsService;
    private readonly IPriceService _priceService;
    private readonly ISharingContextService _sharingContext;
    private readonly ILogger<HoldingsController> _logger;

    public HoldingsController(
        IHoldingsService holdingsService,
        IPriceService priceService,
        ISharingContextService sharingContext,
        ILogger<HoldingsController> logger)
    {
        _holdingsService = holdingsService;
        _priceService    = priceService;
        _sharingContext  = sharingContext;
        _logger          = logger;
    }

    private int GetUserId() => _sharingContext.GetEffectiveUserId();

    /// <summary>
    /// Searches for tickers/instruments via Yahoo Finance.
    /// </summary>
    /// <param name="q">Search query (e.g., "apple", "VWRL")</param>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>List of matching instruments with symbol, name, exchange and type</returns>
    [HttpGet("search")]
    public async Task<ActionResult<List<TickerSearchResult>>> SearchTickers([FromQuery] string q, CancellationToken cancellationToken = default)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(q) || q.Trim().Length < 1)
                return Ok(new List<TickerSearchResult>());

            var results = await _priceService.SearchTickersAsync(q.Trim(), cancellationToken);
            return Ok(results);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error searching tickers for query '{q}'");
            return StatusCode(500, new { message = "Error searching tickers" });
        }
    }

    /// <summary>
    /// Gets the description for a given ETF ticker.
    /// </summary>
    /// <param name="ticker">The ETF ticker symbol (e.g., "VGRO", "XGRO")</param>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>ETF description or "ETF not found" message</returns>
    [HttpGet("etf-description/{ticker}")]
    public async Task<ActionResult<object>> GetEtfDescription(string ticker, CancellationToken cancellationToken = default)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(ticker))
                return BadRequest(new { message = "Ticker is required" });

            var description = await _priceService.GetEtfDescriptionAsync(ticker.ToUpper(), cancellationToken);
            return Ok(new { description = description ?? "ETF not found" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting ETF description for {ticker}");
            return StatusCode(500, new { message = "Error retrieving ETF description" });
        }
    }

    /// <summary>
    /// Gets the portfolio evolution data showing how the portfolio has grown over time.
    /// </summary>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>Portfolio evolution data with historical values</returns>
    [HttpGet("portfolio-evolution")]
    public async Task<ActionResult<PortfolioEvolutionDto>> GetPortfolioEvolution(CancellationToken cancellationToken = default)
    {
        try
        {
            var evolution = await _holdingsService.GetPortfolioEvolutionAsync(GetUserId(), cancellationToken);
            return Ok(evolution);
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting portfolio evolution");
            return StatusCode(500, new { message = "Error retrieving portfolio evolution" });
        }
    }

    /// <summary>
    /// Gets the complete dashboard data including all holdings and portfolio summary.
    /// </summary>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>Dashboard object with portfolio overview and holdings list</returns>
    [HttpGet("dashboard")]
    public async Task<ActionResult<DashboardDto>> GetDashboard(CancellationToken cancellationToken = default)
    {
        try
        {
            _logger.LogInformation("Getting dashboard for user {UserId}", GetUserId());
            var dashboard = await _holdingsService.GetDashboardAsync(GetUserId(), cancellationToken);
            _logger.LogInformation("Dashboard retrieved successfully");
            return Ok(dashboard);
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting dashboard");
            return StatusCode(500, new { message = "Error retrieving dashboard" });
        }
    }

    /// <summary>
    /// Gets all holdings for the authenticated user.
    /// </summary>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>List of holdings with current values and performance data</returns>
    [HttpGet]
    public async Task<ActionResult<List<HoldingDto>>> GetHoldings(CancellationToken cancellationToken = default)
    {
        try
        {
            var holdings = await _holdingsService.GetHoldingsAsync(GetUserId(), cancellationToken);
            return Ok(holdings);
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting holdings");
            return StatusCode(500, new { message = "Error retrieving holdings" });
        }
    }

    /// <summary>
    /// Gets the transaction history for a specific holding.
    /// </summary>
    /// <param name="holdingId">The ID of the holding</param>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>List of transactions (buys/sells) for the holding</returns>
    [HttpGet("{holdingId}/history")]
    public async Task<ActionResult<List<TransactionDto>>> GetHoldingHistory(int holdingId, CancellationToken cancellationToken = default)
    {
        try
        {
            var history = await _holdingsService.GetHoldingHistoryAsync(holdingId, cancellationToken);
            return Ok(history);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting history for holding {holdingId}");
            return StatusCode(500, new { message = "Error retrieving holding history" });
        }
    }

    /// <summary>Adds a new transaction (buy or sell) for a holding.</summary>
    [HttpPost("transaction")]
    public async Task<ActionResult> AddTransaction([FromBody] CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "This profile is shared as read-only. You cannot add transactions." });

            if (!ModelState.IsValid)
                return BadRequest(ModelState);

            await _holdingsService.AddTransactionAsync(GetUserId(), dto, cancellationToken);
            return Ok(new { message = "Transaction added successfully" });
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error adding transaction");
            return StatusCode(500, new { message = "Error adding transaction" });
        }
    }

    /// <summary>Deletes a transaction and recalculates the holding.</summary>
    [HttpDelete("transactions/{transactionId}")]
    public async Task<ActionResult> DeleteTransaction(int transactionId, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "This profile is shared as read-only. You cannot delete transactions." });

            await _holdingsService.DeleteTransactionAsync(transactionId, GetUserId(), cancellationToken);
            return NoContent();
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error deleting transaction {transactionId}");
            return StatusCode(500, new { message = "Error deleting transaction" });
        }
    }

    /// <summary>Updates a transaction's quantity, price and date; recalculates the holding.</summary>
    [HttpPatch("transactions/{transactionId}")]
    public async Task<ActionResult> UpdateTransaction(int transactionId, [FromBody] UpdateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "This profile is shared as read-only. You cannot edit transactions." });

            await _holdingsService.UpdateTransactionAsync(transactionId, GetUserId(), dto, cancellationToken);
            return NoContent();
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error updating transaction {transactionId}");
            return StatusCode(500, new { message = "Error updating transaction" });
        }
    }

    // ── Asset Tax Rates ───────────────────────────────────────────────────────

    /// <summary>Returns all Exit Tax rates by security type.</summary>
    [HttpGet("tax-rates")]
    public async Task<ActionResult<List<AssetTaxRateDto>>> GetTaxRates(CancellationToken cancellationToken = default)
    {
        try
        {
            var rates = await _holdingsService.GetAssetTaxRatesAsync(cancellationToken);
            return Ok(rates);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting tax rates");
            return StatusCode(500, new { message = "Error retrieving tax rates" });
        }
    }

    /// <summary>Creates or updates an Exit Tax rate for a security type.</summary>
    [HttpPut("tax-rates")]
    public async Task<ActionResult<AssetTaxRateDto>> UpsertTaxRate([FromBody] AssetTaxRateDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "Read-only access." });

            if (string.IsNullOrWhiteSpace(dto.SecurityType))
                return BadRequest(new { message = "SecurityType is required." });

            var result = await _holdingsService.UpsertAssetTaxRateAsync(dto, cancellationToken);
            return Ok(result);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error upserting tax rate");
            return StatusCode(500, new { message = "Error saving tax rate" });
        }
    }

    /// <summary>Deletes an Exit Tax rate for a security type.</summary>
    [HttpDelete("tax-rates/{securityType}")]
    public async Task<ActionResult> DeleteTaxRate(string securityType, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "Read-only access." });

            await _holdingsService.DeleteAssetTaxRateAsync(securityType, cancellationToken);
            return NoContent();
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error deleting tax rate for {securityType}");
            return StatusCode(500, new { message = "Error deleting tax rate" });
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Services;

namespace ETFTracker.Api.Controllers;

/// <summary>
/// Handles ETF holdings management, portfolio data, and transaction history.
/// Requires JWT authentication.
/// </summary>
[Authorize]
[ApiController]
[Route("api/[controller]")]
public class HoldingsController : ControllerBase
{
    private readonly IHoldingsService _holdingsService;
    private readonly IPriceService _priceService;
    private readonly ISharingContextService _sharingContext;
    private readonly ILogger<HoldingsController> _logger;

    public HoldingsController(
        IHoldingsService holdingsService,
        IPriceService priceService,
        ISharingContextService sharingContext,
        ILogger<HoldingsController> logger)
    {
        _holdingsService = holdingsService;
        _priceService    = priceService;
        _sharingContext  = sharingContext;
        _logger          = logger;
    }

    private int GetUserId() => _sharingContext.GetEffectiveUserId();

    /// <summary>
    /// Searches for tickers/instruments via Yahoo Finance.
    /// </summary>
    /// <param name="q">Search query (e.g., "apple", "VWRL")</param>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>List of matching instruments with symbol, name, exchange and type</returns>
    [HttpGet("search")]
    public async Task<ActionResult<List<TickerSearchResult>>> SearchTickers([FromQuery] string q, CancellationToken cancellationToken = default)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(q) || q.Trim().Length < 1)
                return Ok(new List<TickerSearchResult>());

            var results = await _priceService.SearchTickersAsync(q.Trim(), cancellationToken);
            return Ok(results);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error searching tickers for query '{q}'");
            return StatusCode(500, new { message = "Error searching tickers" });
        }
    }

    /// <summary>
    /// Gets the description for a given ETF ticker.
    /// </summary>
    /// <param name="ticker">The ETF ticker symbol (e.g., "VGRO", "XGRO")</param>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>ETF description or "ETF not found" message</returns>
    [HttpGet("etf-description/{ticker}")]
    public async Task<ActionResult<object>> GetEtfDescription(string ticker, CancellationToken cancellationToken = default)
    {
        try
        {
            if (string.IsNullOrWhiteSpace(ticker))
                return BadRequest(new { message = "Ticker is required" });

            var description = await _priceService.GetEtfDescriptionAsync(ticker.ToUpper(), cancellationToken);
            return Ok(new { description = description ?? "ETF not found" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting ETF description for {ticker}");
            return StatusCode(500, new { message = "Error retrieving ETF description" });
        }
    }

    /// <summary>
    /// Gets the portfolio evolution data showing how the portfolio has grown over time.
    /// </summary>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>Portfolio evolution data with historical values</returns>
    [HttpGet("portfolio-evolution")]
    public async Task<ActionResult<PortfolioEvolutionDto>> GetPortfolioEvolution(CancellationToken cancellationToken = default)
    {
        try
        {
            var evolution = await _holdingsService.GetPortfolioEvolutionAsync(GetUserId(), cancellationToken);
            return Ok(evolution);
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting portfolio evolution");
            return StatusCode(500, new { message = "Error retrieving portfolio evolution" });
        }
    }

    /// <summary>
    /// Gets the complete dashboard data including all holdings and portfolio summary.
    /// </summary>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>Dashboard object with portfolio overview and holdings list</returns>
    [HttpGet("dashboard")]
    public async Task<ActionResult<DashboardDto>> GetDashboard(CancellationToken cancellationToken = default)
    {
        try
        {
            _logger.LogInformation("Getting dashboard for user {UserId}", GetUserId());
            var dashboard = await _holdingsService.GetDashboardAsync(GetUserId(), cancellationToken);
            _logger.LogInformation("Dashboard retrieved successfully");
            return Ok(dashboard);
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting dashboard");
            return StatusCode(500, new { message = "Error retrieving dashboard" });
        }
    }

    /// <summary>
    /// Gets all holdings for the authenticated user.
    /// </summary>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>List of holdings with current values and performance data</returns>
    [HttpGet]
    public async Task<ActionResult<List<HoldingDto>>> GetHoldings(CancellationToken cancellationToken = default)
    {
        try
        {
            var holdings = await _holdingsService.GetHoldingsAsync(GetUserId(), cancellationToken);
            return Ok(holdings);
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting holdings");
            return StatusCode(500, new { message = "Error retrieving holdings" });
        }
    }

    /// <summary>
    /// Gets the transaction history for a specific holding.
    /// </summary>
    /// <param name="holdingId">The ID of the holding</param>
    /// <param name="cancellationToken">Cancellation token</param>
    /// <returns>List of transactions (buys/sells) for the holding</returns>
    [HttpGet("{holdingId}/history")]
    public async Task<ActionResult<List<TransactionDto>>> GetHoldingHistory(int holdingId, CancellationToken cancellationToken = default)
    {
        try
        {
            var history = await _holdingsService.GetHoldingHistoryAsync(holdingId, cancellationToken);
            return Ok(history);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting history for holding {holdingId}");
            return StatusCode(500, new { message = "Error retrieving holding history" });
        }
    }

    /// <summary>Adds a new transaction (buy or sell) for a holding.</summary>
    [HttpPost("transaction")]
    public async Task<ActionResult> AddTransaction([FromBody] CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "This profile is shared as read-only. You cannot add transactions." });

            if (!ModelState.IsValid)
                return BadRequest(ModelState);

            await _holdingsService.AddTransactionAsync(GetUserId(), dto, cancellationToken);
            return Ok(new { message = "Transaction added successfully" });
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error adding transaction");
            return StatusCode(500, new { message = "Error adding transaction" });
        }
    }

    /// <summary>Deletes a transaction and recalculates the holding.</summary>
    [HttpDelete("transactions/{transactionId}")]
    public async Task<ActionResult> DeleteTransaction(int transactionId, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "This profile is shared as read-only. You cannot delete transactions." });

            await _holdingsService.DeleteTransactionAsync(transactionId, GetUserId(), cancellationToken);
            return NoContent();
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error deleting transaction {transactionId}");
            return StatusCode(500, new { message = "Error deleting transaction" });
        }
    }

    /// <summary>Updates a transaction's quantity, price and date; recalculates the holding.</summary>
    [HttpPatch("transactions/{transactionId}")]
    public async Task<ActionResult> UpdateTransaction(int transactionId, [FromBody] UpdateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "This profile is shared as read-only. You cannot edit transactions." });

            await _holdingsService.UpdateTransactionAsync(transactionId, GetUserId(), dto, cancellationToken);
            return NoContent();
        }
        catch (UnauthorizedAccessException ex)
        {
            return StatusCode(403, new { message = ex.Message });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error updating transaction {transactionId}");
            return StatusCode(500, new { message = "Error updating transaction" });
        }
    }

    // ── Asset Tax Rates ───────────────────────────────────────────────────────

    /// <summary>Returns all Exit Tax rates by security type.</summary>
    [HttpGet("tax-rates")]
    public async Task<ActionResult<List<AssetTaxRateDto>>> GetTaxRates(CancellationToken cancellationToken = default)
    {
        try
        {
            var rates = await _holdingsService.GetAssetTaxRatesAsync(cancellationToken);
            return Ok(rates);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting tax rates");
            return StatusCode(500, new { message = "Error retrieving tax rates" });
        }
    }

    /// <summary>Creates or updates an Exit Tax rate for a security type.</summary>
    [HttpPut("tax-rates")]
    public async Task<ActionResult<AssetTaxRateDto>> UpsertTaxRate([FromBody] AssetTaxRateDto dto, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "Read-only access." });

            if (string.IsNullOrWhiteSpace(dto.SecurityType))
                return BadRequest(new { message = "SecurityType is required." });

            var result = await _holdingsService.UpsertAssetTaxRateAsync(dto, cancellationToken);
            return Ok(result);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error upserting tax rate");
            return StatusCode(500, new { message = "Error saving tax rate" });
        }
    }

    /// <summary>Deletes an Exit Tax rate for a security type.</summary>
    [HttpDelete("tax-rates/{securityType}")]
    public async Task<ActionResult> DeleteTaxRate(string securityType, CancellationToken cancellationToken = default)
    {
        try
        {
            if (_sharingContext.IsReadOnly())
                return StatusCode(403, new { message = "Read-only access." });

            await _holdingsService.DeleteAssetTaxRateAsync(securityType, cancellationToken);
            return NoContent();
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error deleting tax rate for {securityType}");
            return StatusCode(500, new { message = "Error deleting tax rate" });
        }
    }

    // ── Tax Year Summary ───────────────────────────────────────────────────────

    /// <summary>Returns the list of years that have at least one sell transaction.</summary>
    [HttpGet("tax-years")]
    public async Task<ActionResult<List<int>>> GetTaxYears(CancellationToken cancellationToken = default)
    {
        try
        {
            var years = await _holdingsService.GetTaxYearsAsync(GetUserId(), cancellationToken);
            return Ok(years);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error getting tax years");
            return StatusCode(500, new { message = "Error retrieving tax years" });
        }
    }

    /// <summary>Returns all realized gains and exit tax due for the specified year.</summary>
    /// <param name="year">Tax year (e.g., 2026)</param>
    [HttpGet("tax-summary")]
    public async Task<ActionResult<TaxYearSummaryDto>> GetTaxSummary([FromQuery] int year, CancellationToken cancellationToken = default)
    {
        try
        {
            if (year < 2000 || year > 2100)
                return BadRequest(new { message = "Invalid year." });

            var summary = await _holdingsService.GetTaxYearSummaryAsync(GetUserId(), year, cancellationToken);
            return Ok(summary);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, $"Error getting tax summary for year {year}");
            return StatusCode(500, new { message = "Error retrieving tax summary" });
        }
    }
}

namespace ETFTracker.Api.Dtos;

public class TaxSellEntryDto
{
    public int TransactionId { get; set; }
    public string Ticker { get; set; } = string.Empty;
    public string? EtfName { get; set; }
    /// <summary>ISO date string (yyyy-MM-dd)</summary>
    public string SellDate { get; set; } = string.Empty;
    public decimal QuantitySold { get; set; }
    public decimal SellPrice { get; set; }
    /// <summary>FIFO-weighted average buy price for the sold units.</summary>
    public decimal WeightedBuyPrice { get; set; }
    public decimal TaxableProfit { get; set; }
    public decimal? ExitTaxPercent { get; set; }
    public decimal? ExitTaxDue { get; set; }
    public string? SecurityType { get; set; }
}

public class TaxYearSummaryDto
{
    public int Year { get; set; }
    public List<TaxSellEntryDto> Entries { get; set; } = new();
    public decimal TotalTaxableProfit { get; set; }
    /// <summary>Sum of exit tax due across all entries that have a rate configured.</summary>
    public decimal TotalExitTaxDue { get; set; }
    /// <summary>True when at least one entry has no exit-tax rate configured.</summary>
    public bool HasMissingRates { get; set; }
}

using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
    Task DeleteTransactionAsync(int transactionId, int userId, CancellationToken cancellationToken = default);
    Task UpdateTransactionAsync(int transactionId, int userId, UpdateTransactionDto dto, CancellationToken cancellationToken = default);
    Task<PortfolioEvolutionDto> GetPortfolioEvolutionAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<AssetTaxRateDto>> GetAssetTaxRatesAsync(CancellationToken cancellationToken = default);
    Task<AssetTaxRateDto> UpsertAssetTaxRateAsync(AssetTaxRateDto dto, CancellationToken cancellationToken = default);
    Task DeleteAssetTaxRateAsync(string securityType, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    // ── Dashboard ─────────────────────────────────────────────────────────────

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        var totalValue    = holdings.Sum(h => h.TotalValue);
        var totalInvested = holdings.Sum(h => h.Quantity * h.AverageCost);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        var totalVariationEur     = totalValue - totalInvested;
        var totalVariationPercent = totalInvested > 0 ? (totalVariationEur / totalInvested) * 100 : 0;
        dashboard.Header.TotalVariation = new PeriodMetrics
        {
            GainLossEur     = totalVariationEur,
            GainLossPercent = totalVariationPercent
        };

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.DailyMetrics.PricesUnavailable)
        };
        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.WeeklyMetrics.PricesUnavailable)
        };
        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.MonthlyMetrics.PricesUnavailable)
        };
        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.YtdMetrics.PricesUnavailable)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    // ── Holdings ──────────────────────────────────────────────────────────────

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var priceResult    = await _priceService.GetPriceWithSourceAsync(holding.Ticker, cancellationToken);
            var priceUnavailable = !priceResult.Price.HasValue;
            var displayPrice   = priceResult.Price ?? 0;
            var totalValue     = holding.Quantity * displayPrice;

            if (priceResult.Source != null)
            {
                holding.PriceSource = priceResult.Source;
                _context.Holdings.Update(holding);
            }

            if (holding.SecurityType == null)
            {
                var secType = await _priceService.GetSecurityTypeAsync(holding.Ticker, cancellationToken);
                if (secType != null)
                {
                    holding.SecurityType = secType;
                    _context.Holdings.Update(holding);
                }
            }

            // Deemed Disposal: only from buy transactions
            DateOnly? deemedDisposalDueDate = null;
            if (IsSubjectToDeemedDisposal(holding.SecurityType))
            {
                var today = DateOnly.FromDateTime(DateTime.UtcNow);
                var futureDates = holding.Transactions
                    .Where(t => t.TransactionType == TransactionType.Buy)
                    .Select(t => t.PurchaseDate.AddYears(8))
                    .Where(d => d > today)
                    .OrderBy(d => d)
                    .ToList();
                deemedDisposalDueDate = futureDates.Count > 0 ? futureDates[0] : (DateOnly?)null;
            }

            holdingDtos.Add(new HoldingDto
            {
                Id                   = holding.Id,
                Ticker               = holding.Ticker,
                EtfName              = holding.EtfName,
                Quantity             = holding.Quantity,
                AverageCost          = holding.AverageCost,
                CurrentPrice         = displayPrice,
                TotalValue           = totalValue,
                PriceUnavailable     = priceUnavailable,
                PriceSource          = priceResult.Source,
                SecurityType         = holding.SecurityType,
                DeemedDisposalDueDate = deemedDisposalDueDate,
                DailyMetrics         = await CalculatePeriodMetricsAsync(holding.Ticker, holding.Quantity, 1,  cancellationToken),
                WeeklyMetrics        = await CalculatePeriodMetricsAsync(holding.Ticker, holding.Quantity, 7,  cancellationToken),
                MonthlyMetrics       = await CalculatePeriodMetricsAsync(holding.Ticker, holding.Quantity, 30, cancellationToken),
                YtdMetrics           = await CalculateYtdMetricsAsync(holding.Ticker, holding.Quantity, cancellationToken)
            });
        }

        await _context.SaveChangesAsync(cancellationToken);
        return holdingDtos;
    }

    // ── History ───────────────────────────────────────────────────────────────

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var holding = await _context.Holdings
            .FirstOrDefaultAsync(h => h.Id == holdingId, cancellationToken);

        if (holding == null) return new List<TransactionDto>();

        var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken) ?? 0;

        // Look up exit-tax rate for this security type
        decimal? taxRate = null;
        if (holding.SecurityType != null)
        {
            var taxRateRecord = await _context.AssetTaxRates
                .FindAsync(new object[] { holding.SecurityType }, cancellationToken);
            taxRate = taxRateRecord?.ExitTaxPercent;
        }

        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderBy(t => t.PurchaseDate)
            .ThenBy(t => t.Id)
            .ToListAsync(cancellationToken);

        // Pre-load all sell allocations for this holding's sells
        var sellIds = transactions
            .Where(t => t.TransactionType == TransactionType.Sell)
            .Select(t => t.Id)
            .ToList();

        var allAllocations = sellIds.Count > 0
            ? await _context.SellAllocations
                .Where(a => sellIds.Contains(a.SellTransactionId))
                .ToListAsync(cancellationToken)
            : new List<SellAllocation>();

        // Build buy-transaction lookup for dates (buys are already in transactions list)
        var buyDict = transactions.ToDictionary(t => t.Id);

        var dtos = transactions.Select(t =>
        {
            if (t.TransactionType == TransactionType.Sell)
            {
                var txAllocs       = allAllocations.Where(a => a.SellTransactionId == t.Id).ToList();
                var totalAllocQty  = txAllocs.Sum(a => a.AllocatedQuantity);
                var totalBuyCost   = txAllocs.Sum(a => a.AllocatedQuantity * a.BuyPrice);
                var avgBuyPrice    = totalAllocQty > 0 ? totalBuyCost / totalAllocQty : 0m;
                var taxableProfit  = (t.PurchasePrice - avgBuyPrice) * t.Quantity;
                var exitTaxDue     = taxRate.HasValue ? taxableProfit * (taxRate.Value / 100m) : (decimal?)null;

                return new TransactionDto
                {
                    Id              = t.Id,
                    HoldingId       = t.HoldingId,
                    TransactionType = "Sell",
                    Quantity        = t.Quantity,
                    PurchasePrice   = t.PurchasePrice,
                    PurchaseDate    = t.PurchaseDate,
                    CreatedAt       = t.CreatedAt,
                    CurrentPrice    = currentPrice,
                    VariationEur    = 0,
                    VariationPercent = 0,
                    TaxableProfitEur = taxableProfit,
                    ExitTaxPercent   = taxRate,
                    ExitTaxDueEur    = exitTaxDue,
                    Allocations      = txAllocs.Select(a => new SellAllocationDto
                    {
                        BuyTransactionId = a.BuyTransactionId,
                        BuyDate          = buyDict.TryGetValue(a.BuyTransactionId, out var bt) ? bt.PurchaseDate : default,
                        BuyPrice         = a.BuyPrice,
                        AllocatedQuantity = a.AllocatedQuantity,
                        ProfitEur        = (t.PurchasePrice - a.BuyPrice) * a.AllocatedQuantity
                    }).ToList()
                };
            }
            else // Buy
            {
                var variationEur     = (currentPrice - t.PurchasePrice) * t.Quantity;
                var variationPercent = t.PurchasePrice > 0
                    ? ((currentPrice - t.PurchasePrice) / t.PurchasePrice) * 100
                    : 0;

                return new TransactionDto
                {
                    Id               = t.Id,
                    HoldingId        = t.HoldingId,
                    TransactionType  = "Buy",
                    Quantity         = t.Quantity,
                    PurchasePrice    = t.PurchasePrice,
                    PurchaseDate     = t.PurchaseDate,
                    CreatedAt        = t.CreatedAt,
                    CurrentPrice     = currentPrice,
                    VariationEur     = variationEur,
                    VariationPercent = variationPercent,
                    TaxableProfitEur = null,
                    ExitTaxPercent   = null,
                    ExitTaxDueEur    = null,
                    Allocations      = null
                };
            }
        }).ToList();

        return dtos;
    }

    // ── Add Transaction ───────────────────────────────────────────────────────

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var dbTx = await _context.Database.BeginTransactionAsync(cancellationToken);
        try
        {
            var utcNow = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);

            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                if (dto.TransactionType == TransactionType.Sell)
                    throw new InvalidOperationException($"No existing holding found for {dto.Ticker}. Cannot sell units you don't own.");

                var etfName      = await _priceService.GetEtfDescriptionAsync(dto.Ticker, cancellationToken);
                var securityType = await _priceService.GetSecurityTypeAsync(dto.Ticker, cancellationToken);

                holding = new Holding
                {
                    UserId       = userId,
                    Ticker       = dto.Ticker,
                    EtfName      = etfName,
                    SecurityType = securityType,
                    Quantity     = 0,
                    AverageCost  = 0,
                    CreatedAt    = utcNow,
                    UpdatedAt    = utcNow
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Validate sell quantity
            if (dto.TransactionType == TransactionType.Sell && dto.Quantity > holding.Quantity)
                throw new InvalidOperationException(
                    $"Cannot sell {dto.Quantity} units; only {holding.Quantity} available for {dto.Ticker}.");

            // Record transaction
            var newTxn = new Transaction
            {
                HoldingId       = holding.Id,
                TransactionType = dto.TransactionType,
                Quantity        = dto.Quantity,
                PurchasePrice   = dto.PurchasePrice,
                PurchaseDate    = dto.PurchaseDate,
                CreatedAt       = utcNow,
                UpdatedAt       = utcNow
            };
            _context.Transactions.Add(newTxn);
            await _context.SaveChangesAsync(cancellationToken);

            // FIFO allocation for sells
            if (dto.TransactionType == TransactionType.Sell)
                await AllocateSellFifoAsync(newTxn.Id, holding.Id, dto.Quantity, cancellationToken);

            // Recalculate holding
            await RecalculateHoldingAsync(holding.Id, utcNow, cancellationToken);

            await dbTx.CommitAsync(cancellationToken);

            // Backfill historical prices (outside DB transaction — failure is non-fatal)
            if (dto.TransactionType == TransactionType.Buy)
                await BackfillHistoricalPricesIfNeededAsync(dto.Ticker, dto.PurchaseDate, cancellationToken);
        }
        catch (Exception ex)
        {
            await dbTx.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    // ── Delete Transaction ────────────────────────────────────────────────────

    public async Task DeleteTransactionAsync(int transactionId, int userId, CancellationToken cancellationToken = default)
    {
        using var dbTx = await _context.Database.BeginTransactionAsync(cancellationToken);
        try
        {
            var txn = await _context.Transactions
                .Include(t => t.Holding)
                .FirstOrDefaultAsync(t => t.Id == transactionId, cancellationToken);

            if (txn == null || txn.Holding?.UserId != userId)
                throw new UnauthorizedAccessException("Transaction not found or access denied.");

            var holdingId = txn.HoldingId;
            var utcNow    = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);

            if (txn.TransactionType == TransactionType.Buy)
            {
                // Block deletion if this buy has been consumed by any sell
                var hasAllocations = await _context.SellAllocations
                    .AnyAsync(a => a.BuyTransactionId == transactionId, cancellationToken);
                if (hasAllocations)
                    throw new InvalidOperationException(
                        "Cannot delete a buy that has been partially or fully sold — delete the linked sell transactions first.");
            }
            else // Sell — remove FIFO allocations first
            {
                var allocations = await _context.SellAllocations
                    .Where(a => a.SellTransactionId == transactionId)
                    .ToListAsync(cancellationToken);
                _context.SellAllocations.RemoveRange(allocations);
                await _context.SaveChangesAsync(cancellationToken);
            }

            _context.Transactions.Remove(txn);
            await _context.SaveChangesAsync(cancellationToken);

            var remaining = await _context.Transactions
                .Where(t => t.HoldingId == holdingId)
                .ToListAsync(cancellationToken);

            var holding = await _context.Holdings.FindAsync(new object[] { holdingId }, cancellationToken);
            if (holding != null)
            {
                if (remaining.Count == 0)
                {
                    _context.Holdings.Remove(holding);
                    await _context.SaveChangesAsync(cancellationToken);
                }
                else
                {
                    await RecalculateHoldingAsync(holdingId, utcNow, cancellationToken);
                }
            }

            await dbTx.CommitAsync(cancellationToken);
        }
        catch
        {
            await dbTx.RollbackAsync(cancellationToken);
            throw;
        }
    }

    // ── Update Transaction ────────────────────────────────────────────────────

    public async Task UpdateTransactionAsync(int transactionId, int userId, UpdateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var dbTx = await _context.Database.BeginTransactionAsync(cancellationToken);
        try
        {
            var txn = await _context.Transactions
                .Include(t => t.Holding)
                .FirstOrDefaultAsync(t => t.Id == transactionId, cancellationToken);

            if (txn == null || txn.Holding?.UserId != userId)
                throw new UnauthorizedAccessException("Transaction not found or access denied.");

            var utcNow    = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);
            var holdingId = txn.HoldingId;

            txn.Quantity      = dto.Quantity;
            txn.PurchasePrice = dto.PurchasePrice;
            txn.PurchaseDate  = dto.PurchaseDate;
            txn.UpdatedAt     = utcNow;
            _context.Transactions.Update(txn);
            await _context.SaveChangesAsync(cancellationToken);

            if (txn.TransactionType == TransactionType.Buy)
            {
                // Find all sells that consumed this buy and re-run their FIFO allocations
                var affectedSellIds = await _context.SellAllocations
                    .Where(a => a.BuyTransactionId == transactionId)
                    .Select(a => a.SellTransactionId)
                    .Distinct()
                    .ToListAsync(cancellationToken);

                if (affectedSellIds.Count > 0)
                {
                    var affectedSells = await _context.Transactions
                        .Where(t => affectedSellIds.Contains(t.Id))
                        .OrderBy(t => t.PurchaseDate)
                        .ThenBy(t => t.Id)
                        .ToListAsync(cancellationToken);

                    foreach (var sell in affectedSells)
                    {
                        var existing = await _context.SellAllocations
                            .Where(a => a.SellTransactionId == sell.Id)
                            .ToListAsync(cancellationToken);
                        _context.SellAllocations.RemoveRange(existing);
                        await _context.SaveChangesAsync(cancellationToken);

                        await AllocateSellFifoAsync(sell.Id, holdingId, sell.Quantity, cancellationToken);
                    }
                }
            }

            await RecalculateHoldingAsync(holdingId, utcNow, cancellationToken);
            await dbTx.CommitAsync(cancellationToken);
        }
        catch
        {
            await dbTx.RollbackAsync(cancellationToken);
            throw;
        }
    }

    // ── Portfolio Evolution ───────────────────────────────────────────────────

    public async Task<PortfolioEvolutionDto> GetPortfolioEvolutionAsync(int userId, CancellationToken cancellationToken = default)
    {
        var today = DateOnly.FromDateTime(DateTime.UtcNow.Date);

        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .ToListAsync(cancellationToken);

        var allTransactions = dbHoldings.SelectMany(h => h.Transactions).ToList();

        var startDate = allTransactions.Count > 0
            ? allTransactions.Min(t => t.PurchaseDate)
            : today;

        var tickers = dbHoldings.Select(h => h.Ticker).Distinct().ToList();

        var snapshotStart = new DateTime(startDate.Year, startDate.Month, startDate.Day, 0, 0, 0, DateTimeKind.Utc).AddDays(-30);
        var snapshotEnd   = new DateTime(today.Year, today.Month, today.Day, 23, 59, 59, DateTimeKind.Utc);

        var allSnapshots = await _context.PriceSnapshots
            .Where(ps => tickers.Contains(ps.Ticker) && ps.SnapshotDate >= snapshotStart && ps.SnapshotDate <= snapshotEnd)
            .ToListAsync(cancellationToken);

        var priceByTicker = allSnapshots
            .GroupBy(ps => ps.Ticker)
            .ToDictionary(
                g => g.Key,
                g => g.OrderBy(ps => ps.SnapshotDate)
                      .Select(ps => (Date: DateOnly.FromDateTime(ps.SnapshotDate.Date), Price: ps.Price))
                      .ToList()
            );

        var buyDates  = allTransactions.Where(t => t.TransactionType == TransactionType.Buy) .Select(t => t.PurchaseDate).ToHashSet();
        var sellDates = allTransactions.Where(t => t.TransactionType == TransactionType.Sell).Select(t => t.PurchaseDate).ToHashSet();

        var dataPoints = new List<PortfolioEvolutionDataPointDto>();

        for (var date = startDate; date <= today; date = date.AddDays(1))
        {
            decimal totalValue = 0m;

            foreach (var holding in dbHoldings)
            {
                var buyQty  = holding.Transactions.Where(t => t.TransactionType == TransactionType.Buy  && t.PurchaseDate <= date).Sum(t => t.Quantity);
                var sellQty = holding.Transactions.Where(t => t.TransactionType == TransactionType.Sell && t.PurchaseDate <= date).Sum(t => t.Quantity);
                var quantity = buyQty - sellQty;

                if (quantity <= 0) continue;
                if (!priceByTicker.TryGetValue(holding.Ticker, out var prices)) continue;

                var price = prices
                    .Where(p => p.Date <= date)
                    .Select(p => (decimal?)p.Price)
                    .LastOrDefault();

                if (price.HasValue)
                    totalValue += quantity * price.Value;
            }

            dataPoints.Add(new PortfolioEvolutionDataPointDto
            {
                Date       = date.ToString("yyyy-MM-dd"),
                TotalValue = totalValue,
                HasBuy     = buyDates.Contains(date),
                HasSell    = sellDates.Contains(date)
            });
        }

        return new PortfolioEvolutionDto { DataPoints = dataPoints };
    }

    // ── Asset Tax Rates ───────────────────────────────────────────────────────

    public async Task<List<AssetTaxRateDto>> GetAssetTaxRatesAsync(CancellationToken cancellationToken = default)
    {
        return await _context.AssetTaxRates
            .OrderBy(r => r.SecurityType)
            .Select(r => new AssetTaxRateDto
            {
                SecurityType   = r.SecurityType,
                ExitTaxPercent = r.ExitTaxPercent,
                Label          = r.Label
            })
            .ToListAsync(cancellationToken);
    }

    public async Task<AssetTaxRateDto> UpsertAssetTaxRateAsync(AssetTaxRateDto dto, CancellationToken cancellationToken = default)
    {
        var utcNow   = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);
        var existing = await _context.AssetTaxRates.FindAsync(new object[] { dto.SecurityType }, cancellationToken);

        if (existing == null)
        {
            existing = new AssetTaxRate
            {
                SecurityType   = dto.SecurityType.ToUpperInvariant(),
                ExitTaxPercent = dto.ExitTaxPercent,
                Label          = dto.Label,
                CreatedAt      = utcNow,
                UpdatedAt      = utcNow
            };
            _context.AssetTaxRates.Add(existing);
        }
        else
        {
            existing.ExitTaxPercent = dto.ExitTaxPercent;
            existing.Label          = dto.Label;
            existing.UpdatedAt      = utcNow;
            _context.AssetTaxRates.Update(existing);
        }

        await _context.SaveChangesAsync(cancellationToken);
        return new AssetTaxRateDto { SecurityType = existing.SecurityType, ExitTaxPercent = existing.ExitTaxPercent, Label = existing.Label };
    }

    public async Task DeleteAssetTaxRateAsync(string securityType, CancellationToken cancellationToken = default)
    {
        var record = await _context.AssetTaxRates.FindAsync(new object[] { securityType }, cancellationToken);
        if (record == null) return;
        _context.AssetTaxRates.Remove(record);
        await _context.SaveChangesAsync(cancellationToken);
    }

    // ── FIFO helpers ──────────────────────────────────────────────────────────

    private async Task AllocateSellFifoAsync(int sellTransactionId, int holdingId, decimal sellQty, CancellationToken cancellationToken)
    {
        var buys = await _context.Transactions
            .Where(t => t.HoldingId == holdingId && t.TransactionType == TransactionType.Buy)
            .OrderBy(t => t.PurchaseDate)
            .ThenBy(t => t.Id)
            .ToListAsync(cancellationToken);

        var buyIds = buys.Select(b => b.Id).ToList();
        var alreadyAllocated = await _context.SellAllocations
            .Where(a => buyIds.Contains(a.BuyTransactionId))
            .GroupBy(a => a.BuyTransactionId)
            .Select(g => new { BuyId = g.Key, Qty = g.Sum(a => a.AllocatedQuantity) })
            .ToDictionaryAsync(x => x.BuyId, x => x.Qty, cancellationToken);

        var remaining    = sellQty;
        var newAllocations = new List<SellAllocation>();

        foreach (var buy in buys)
        {
            if (remaining <= 0) break;

            var consumed  = alreadyAllocated.GetValueOrDefault(buy.Id, 0m);
            var available = buy.Quantity - consumed;
            if (available <= 0) continue;

            var toAllocate = Math.Min(available, remaining);
            newAllocations.Add(new SellAllocation
            {
                SellTransactionId = sellTransactionId,
                BuyTransactionId  = buy.Id,
                AllocatedQuantity = toAllocate,
                BuyPrice          = buy.PurchasePrice
            });
            remaining -= toAllocate;
        }

        _context.SellAllocations.AddRange(newAllocations);
        await _context.SaveChangesAsync(cancellationToken);
    }

    private async Task RecalculateHoldingAsync(int holdingId, DateTime utcNow, CancellationToken cancellationToken)
    {
        var allTxns = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .ToListAsync(cancellationToken);

        var buys     = allTxns.Where(t => t.TransactionType == TransactionType.Buy).ToList();
        var buyIds   = buys.Select(b => b.Id).ToList();
        var sellQty  = allTxns.Where(t => t.TransactionType == TransactionType.Sell).Sum(t => t.Quantity);

        var allocations = await _context.SellAllocations
            .Where(a => buyIds.Contains(a.BuyTransactionId))
            .GroupBy(a => a.BuyTransactionId)
            .Select(g => new { BuyId = g.Key, Qty = g.Sum(a => a.AllocatedQuantity) })
            .ToDictionaryAsync(x => x.BuyId, x => x.Qty, cancellationToken);

        decimal remainingCost = 0m;
        decimal remainingQty  = 0m;
        foreach (var buy in buys)
        {
            var allocated = allocations.GetValueOrDefault(buy.Id, 0m);
            var leftover  = buy.Quantity - allocated;
            if (leftover > 0)
            {
                remainingQty  += leftover;
                remainingCost += leftover * buy.PurchasePrice;
            }
        }

        var holding = await _context.Holdings.FindAsync(new object[] { holdingId }, cancellationToken);
        if (holding != null)
        {
            holding.Quantity    = buys.Sum(b => b.Quantity) - sellQty;
            holding.AverageCost = remainingQty > 0 ? remainingCost / remainingQty : 0m;
            holding.UpdatedAt   = utcNow;
            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);
        }
    }

    // ── Historical price backfill ─────────────────────────────────────────────

    private async Task BackfillHistoricalPricesIfNeededAsync(string ticker, DateOnly purchaseDate, CancellationToken cancellationToken)
    {
        try
        {
            var purchaseDateUtc = purchaseDate.ToDateTime(TimeOnly.MinValue, DateTimeKind.Utc);

            var earliestSnapshotDate = await _context.PriceSnapshots
                .Where(ps => ps.Ticker == ticker)
                .MinAsync(ps => (DateTime?)ps.SnapshotDate, cancellationToken);

            bool needsBackfill = earliestSnapshotDate == null
                                 || earliestSnapshotDate.Value.Date > purchaseDateUtc.Date;

            if (!needsBackfill) return;

            _logger.LogInformation("Starting historical price backfill for {Ticker} from {PurchaseDate}", ticker, purchaseDate);
            var saved = await _priceService.FetchAndSaveHistoricalPricesAsync(ticker, purchaseDate, cancellationToken);
            _logger.LogInformation("Backfill complete for {Ticker}: {Count} snapshots saved", ticker, saved);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error during historical price backfill for {Ticker}", ticker);
        }
    }

    // ── Period metric helpers ─────────────────────────────────────────────────

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal quantity, int days, CancellationToken cancellationToken)
    {
        var currentPrice     = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!currentPrice.HasValue || !priceFromDaysAgo.HasValue)
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0, PricesUnavailable = true };

        var gainLossEur     = (currentPrice.Value - priceFromDaysAgo.Value) * quantity;
        var gainLossPercent = priceFromDaysAgo.Value > 0
            ? ((currentPrice.Value - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100
            : 0;

        return new PeriodMetrics { GainLossEur = gainLossEur, GainLossPercent = gainLossPercent, PricesUnavailable = false };
    }

    private async Task<PeriodMetrics> CalculateYtdMetricsAsync(string ticker, decimal quantity, CancellationToken cancellationToken)
    {
        var currentPrice     = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var firstPriceOfYear = await GetFirstPriceOfYearAsync(ticker, cancellationToken);

        if (!currentPrice.HasValue || !firstPriceOfYear.HasValue)
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0, PricesUnavailable = true };

        var gainLossEur     = (currentPrice.Value - firstPriceOfYear.Value) * quantity;
        var gainLossPercent = firstPriceOfYear.Value > 0
            ? ((currentPrice.Value - firstPriceOfYear.Value) / firstPriceOfYear.Value) * 100
            : 0;

        return new PeriodMetrics { GainLossEur = gainLossEur, GainLossPercent = gainLossPercent, PricesUnavailable = false };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null) return snapshot.Price;

        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private async Task<decimal?> GetFirstPriceOfYearAsync(string ticker, CancellationToken cancellationToken)
    {
        var currentYear = DateTime.UtcNow.Year;
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate.Year == currentYear)
            .OrderBy(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;
        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private static bool IsSubjectToDeemedDisposal(string? securityType)
        => securityType?.ToUpperInvariant() is "ETF" or "MUTUALFUND" or "FUND";
}

using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
    Task DeleteTransactionAsync(int transactionId, int userId, CancellationToken cancellationToken = default);
    Task UpdateTransactionAsync(int transactionId, int userId, UpdateTransactionDto dto, CancellationToken cancellationToken = default);
    Task<PortfolioEvolutionDto> GetPortfolioEvolutionAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<AssetTaxRateDto>> GetAssetTaxRatesAsync(CancellationToken cancellationToken = default);
    Task<AssetTaxRateDto> UpsertAssetTaxRateAsync(AssetTaxRateDto dto, CancellationToken cancellationToken = default);
    Task DeleteAssetTaxRateAsync(string securityType, CancellationToken cancellationToken = default);
    Task<TaxYearSummaryDto> GetTaxYearSummaryAsync(int userId, int year, CancellationToken cancellationToken = default);
    Task<List<int>> GetTaxYearsAsync(int userId, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    // ── Dashboard ─────────────────────────────────────────────────────────────

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        var totalValue    = holdings.Sum(h => h.TotalValue);
        var totalInvested = holdings.Sum(h => h.Quantity * h.AverageCost);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        var totalVariationEur     = totalValue - totalInvested;
        var totalVariationPercent = totalInvested > 0 ? (totalVariationEur / totalInvested) * 100 : 0;
        dashboard.Header.TotalVariation = new PeriodMetrics
        {
            GainLossEur     = totalVariationEur,
            GainLossPercent = totalVariationPercent
        };

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.DailyMetrics.PricesUnavailable)
        };
        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.WeeklyMetrics.PricesUnavailable)
        };
        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.MonthlyMetrics.PricesUnavailable)
        };
        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur       = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent   = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue),
            PricesUnavailable = holdings.Any(h => h.YtdMetrics.PricesUnavailable)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    // ── Holdings ──────────────────────────────────────────────────────────────

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var priceResult    = await _priceService.GetPriceWithSourceAsync(holding.Ticker, cancellationToken);
            var priceUnavailable = !priceResult.Price.HasValue;
            var displayPrice   = priceResult.Price ?? 0;
            var totalValue     = holding.Quantity * displayPrice;

            if (priceResult.Source != null)
            {
                holding.PriceSource = priceResult.Source;
                _context.Holdings.Update(holding);
            }

            if (holding.SecurityType == null)
            {
                var secType = await _priceService.GetSecurityTypeAsync(holding.Ticker, cancellationToken);
                if (secType != null)
                {
                    holding.SecurityType = secType;
                    _context.Holdings.Update(holding);
                }
            }

            // Deemed Disposal: only from buy transactions
            DateOnly? deemedDisposalDueDate = null;
            if (IsSubjectToDeemedDisposal(holding.SecurityType))
            {
                var today = DateOnly.FromDateTime(DateTime.UtcNow);
                var futureDates = holding.Transactions
                    .Where(t => t.TransactionType == TransactionType.Buy)
                    .Select(t => t.PurchaseDate.AddYears(8))
                    .Where(d => d > today)
                    .OrderBy(d => d)
                    .ToList();
                deemedDisposalDueDate = futureDates.Count > 0 ? futureDates[0] : (DateOnly?)null;
            }

            holdingDtos.Add(new HoldingDto
            {
                Id                   = holding.Id,
                Ticker               = holding.Ticker,
                EtfName              = holding.EtfName,
                Quantity             = holding.Quantity,
                AverageCost          = holding.AverageCost,
                CurrentPrice         = displayPrice,
                TotalValue           = totalValue,
                PriceUnavailable     = priceUnavailable,
                PriceSource          = priceResult.Source,
                SecurityType         = holding.SecurityType,
                DeemedDisposalDueDate = deemedDisposalDueDate,
                DailyMetrics         = await CalculatePeriodMetricsAsync(holding.Ticker, holding.Quantity, 1,  cancellationToken),
                WeeklyMetrics        = await CalculatePeriodMetricsAsync(holding.Ticker, holding.Quantity, 7,  cancellationToken),
                MonthlyMetrics       = await CalculatePeriodMetricsAsync(holding.Ticker, holding.Quantity, 30, cancellationToken),
                YtdMetrics           = await CalculateYtdMetricsAsync(holding.Ticker, holding.Quantity, cancellationToken)
            });
        }

        await _context.SaveChangesAsync(cancellationToken);
        return holdingDtos;
    }

    // ── History ───────────────────────────────────────────────────────────────

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var holding = await _context.Holdings
            .FirstOrDefaultAsync(h => h.Id == holdingId, cancellationToken);

        if (holding == null) return new List<TransactionDto>();

        var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken) ?? 0;

        // Look up exit-tax rate for this security type
        decimal? taxRate = null;
        if (holding.SecurityType != null)
        {
            var taxRateRecord = await _context.AssetTaxRates
                .FindAsync(new object[] { holding.SecurityType }, cancellationToken);
            taxRate = taxRateRecord?.ExitTaxPercent;
        }

        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderBy(t => t.PurchaseDate)
            .ThenBy(t => t.Id)
            .ToListAsync(cancellationToken);

        // Pre-load all sell allocations for this holding's sells
        var sellIds = transactions
            .Where(t => t.TransactionType == TransactionType.Sell)
            .Select(t => t.Id)
            .ToList();

        var allAllocations = sellIds.Count > 0
            ? await _context.SellAllocations
                .Where(a => sellIds.Contains(a.SellTransactionId))
                .ToListAsync(cancellationToken)
            : new List<SellAllocation>();

        // Build buy-transaction lookup for dates (buys are already in transactions list)
        var buyDict = transactions.ToDictionary(t => t.Id);

        var dtos = transactions.Select(t =>
        {
            if (t.TransactionType == TransactionType.Sell)
            {
                var txAllocs       = allAllocations.Where(a => a.SellTransactionId == t.Id).ToList();
                var totalAllocQty  = txAllocs.Sum(a => a.AllocatedQuantity);
                var totalBuyCost   = txAllocs.Sum(a => a.AllocatedQuantity * a.BuyPrice);
                var avgBuyPrice    = totalAllocQty > 0 ? totalBuyCost / totalAllocQty : 0m;
                var taxableProfit  = (t.PurchasePrice - avgBuyPrice) * t.Quantity;
                var exitTaxDue     = taxRate.HasValue ? taxableProfit * (taxRate.Value / 100m) : (decimal?)null;

                return new TransactionDto
                {
                    Id              = t.Id,
                    HoldingId       = t.HoldingId,
                    TransactionType = "Sell",
                    Quantity        = t.Quantity,
                    PurchasePrice   = t.PurchasePrice,
                    PurchaseDate    = t.PurchaseDate,
                    CreatedAt       = t.CreatedAt,
                    CurrentPrice    = currentPrice,
                    VariationEur    = 0,
                    VariationPercent = 0,
                    TaxableProfitEur = taxableProfit,
                    ExitTaxPercent   = taxRate,
                    ExitTaxDueEur    = exitTaxDue,
                    Allocations      = txAllocs.Select(a => new SellAllocationDto
                    {
                        BuyTransactionId = a.BuyTransactionId,
                        BuyDate          = buyDict.TryGetValue(a.BuyTransactionId, out var bt) ? bt.PurchaseDate : default,
                        BuyPrice         = a.BuyPrice,
                        AllocatedQuantity = a.AllocatedQuantity,
                        ProfitEur        = (t.PurchasePrice - a.BuyPrice) * a.AllocatedQuantity
                    }).ToList()
                };
            }
            else // Buy
            {
                var variationEur     = (currentPrice - t.PurchasePrice) * t.Quantity;
                var variationPercent = t.PurchasePrice > 0
                    ? ((currentPrice - t.PurchasePrice) / t.PurchasePrice) * 100
                    : 0;

                return new TransactionDto
                {
                    Id               = t.Id,
                    HoldingId        = t.HoldingId,
                    TransactionType  = "Buy",
                    Quantity         = t.Quantity,
                    PurchasePrice    = t.PurchasePrice,
                    PurchaseDate     = t.PurchaseDate,
                    CreatedAt        = t.CreatedAt,
                    CurrentPrice     = currentPrice,
                    VariationEur     = variationEur,
                    VariationPercent = variationPercent,
                    TaxableProfitEur = null,
                    ExitTaxPercent   = null,
                    ExitTaxDueEur    = null,
                    Allocations      = null
                };
            }
        }).ToList();

        return dtos;
    }

    // ── Add Transaction ───────────────────────────────────────────────────────

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var dbTx = await _context.Database.BeginTransactionAsync(cancellationToken);
        try
        {
            var utcNow = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);

            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                if (dto.TransactionType == TransactionType.Sell)
                    throw new InvalidOperationException($"No existing holding found for {dto.Ticker}. Cannot sell units you don't own.");

                var etfName      = await _priceService.GetEtfDescriptionAsync(dto.Ticker, cancellationToken);
                var securityType = await _priceService.GetSecurityTypeAsync(dto.Ticker, cancellationToken);

                holding = new Holding
                {
                    UserId       = userId,
                    Ticker       = dto.Ticker,
                    EtfName      = etfName,
                    SecurityType = securityType,
                    Quantity     = 0,
                    AverageCost  = 0,
                    CreatedAt    = utcNow,
                    UpdatedAt    = utcNow
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Validate sell quantity
            if (dto.TransactionType == TransactionType.Sell && dto.Quantity > holding.Quantity)
                throw new InvalidOperationException(
                    $"Cannot sell {dto.Quantity} units; only {holding.Quantity} available for {dto.Ticker}.");

            // Record transaction
            var newTxn = new Transaction
            {
                HoldingId       = holding.Id,
                TransactionType = dto.TransactionType,
                Quantity        = dto.Quantity,
                PurchasePrice   = dto.PurchasePrice,
                PurchaseDate    = dto.PurchaseDate,
                CreatedAt       = utcNow,
                UpdatedAt       = utcNow
            };
            _context.Transactions.Add(newTxn);
            await _context.SaveChangesAsync(cancellationToken);

            // FIFO allocation for sells
            if (dto.TransactionType == TransactionType.Sell)
                await AllocateSellFifoAsync(newTxn.Id, holding.Id, dto.Quantity, cancellationToken);

            // Recalculate holding
            await RecalculateHoldingAsync(holding.Id, utcNow, cancellationToken);

            await dbTx.CommitAsync(cancellationToken);

            // Backfill historical prices (outside DB transaction — failure is non-fatal)
            if (dto.TransactionType == TransactionType.Buy)
                await BackfillHistoricalPricesIfNeededAsync(dto.Ticker, dto.PurchaseDate, cancellationToken);
        }
        catch (Exception ex)
        {
            await dbTx.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    // ── Delete Transaction ────────────────────────────────────────────────────

    public async Task DeleteTransactionAsync(int transactionId, int userId, CancellationToken cancellationToken = default)
    {
        using var dbTx = await _context.Database.BeginTransactionAsync(cancellationToken);
        try
        {
            var txn = await _context.Transactions
                .Include(t => t.Holding)
                .FirstOrDefaultAsync(t => t.Id == transactionId, cancellationToken);

            if (txn == null || txn.Holding?.UserId != userId)
                throw new UnauthorizedAccessException("Transaction not found or access denied.");

            var holdingId = txn.HoldingId;
            var utcNow    = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);

            if (txn.TransactionType == TransactionType.Buy)
            {
                // Block deletion if this buy has been consumed by any sell
                var hasAllocations = await _context.SellAllocations
                    .AnyAsync(a => a.BuyTransactionId == transactionId, cancellationToken);
                if (hasAllocations)
                    throw new InvalidOperationException(
                        "Cannot delete a buy that has been partially or fully sold — delete the linked sell transactions first.");
            }
            else // Sell — remove FIFO allocations first
            {
                var allocations = await _context.SellAllocations
                    .Where(a => a.SellTransactionId == transactionId)
                    .ToListAsync(cancellationToken);
                _context.SellAllocations.RemoveRange(allocations);
                await _context.SaveChangesAsync(cancellationToken);
            }

            _context.Transactions.Remove(txn);
            await _context.SaveChangesAsync(cancellationToken);

            var remaining = await _context.Transactions
                .Where(t => t.HoldingId == holdingId)
                .ToListAsync(cancellationToken);

            var holding = await _context.Holdings.FindAsync(new object[] { holdingId }, cancellationToken);
            if (holding != null)
            {
                if (remaining.Count == 0)
                {
                    _context.Holdings.Remove(holding);
                    await _context.SaveChangesAsync(cancellationToken);
                }
                else
                {
                    await RecalculateHoldingAsync(holdingId, utcNow, cancellationToken);
                }
            }

            await dbTx.CommitAsync(cancellationToken);
        }
        catch
        {
            await dbTx.RollbackAsync(cancellationToken);
            throw;
        }
    }

    // ── Update Transaction ────────────────────────────────────────────────────

    public async Task UpdateTransactionAsync(int transactionId, int userId, UpdateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var dbTx = await _context.Database.BeginTransactionAsync(cancellationToken);
        try
        {
            var txn = await _context.Transactions
                .Include(t => t.Holding)
                .FirstOrDefaultAsync(t => t.Id == transactionId, cancellationToken);

            if (txn == null || txn.Holding?.UserId != userId)
                throw new UnauthorizedAccessException("Transaction not found or access denied.");

            var utcNow    = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);
            var holdingId = txn.HoldingId;

            txn.Quantity      = dto.Quantity;
            txn.PurchasePrice = dto.PurchasePrice;
            txn.PurchaseDate  = dto.PurchaseDate;
            txn.UpdatedAt     = utcNow;
            _context.Transactions.Update(txn);
            await _context.SaveChangesAsync(cancellationToken);

            if (txn.TransactionType == TransactionType.Buy)
            {
                // Find all sells that consumed this buy and re-run their FIFO allocations
                var affectedSellIds = await _context.SellAllocations
                    .Where(a => a.BuyTransactionId == transactionId)
                    .Select(a => a.SellTransactionId)
                    .Distinct()
                    .ToListAsync(cancellationToken);

                if (affectedSellIds.Count > 0)
                {
                    var affectedSells = await _context.Transactions
                        .Where(t => affectedSellIds.Contains(t.Id))
                        .OrderBy(t => t.PurchaseDate)
                        .ThenBy(t => t.Id)
                        .ToListAsync(cancellationToken);

                    foreach (var sell in affectedSells)
                    {
                        var existing = await _context.SellAllocations
                            .Where(a => a.SellTransactionId == sell.Id)
                            .ToListAsync(cancellationToken);
                        _context.SellAllocations.RemoveRange(existing);
                        await _context.SaveChangesAsync(cancellationToken);

                        await AllocateSellFifoAsync(sell.Id, holdingId, sell.Quantity, cancellationToken);
                    }
                }
            }

            await RecalculateHoldingAsync(holdingId, utcNow, cancellationToken);
            await dbTx.CommitAsync(cancellationToken);
        }
        catch
        {
            await dbTx.RollbackAsync(cancellationToken);
            throw;
        }
    }

    // ── Portfolio Evolution ───────────────────────────────────────────────────

    public async Task<PortfolioEvolutionDto> GetPortfolioEvolutionAsync(int userId, CancellationToken cancellationToken = default)
    {
        var today = DateOnly.FromDateTime(DateTime.UtcNow.Date);

        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .ToListAsync(cancellationToken);

        var allTransactions = dbHoldings.SelectMany(h => h.Transactions).ToList();

        var startDate = allTransactions.Count > 0
            ? allTransactions.Min(t => t.PurchaseDate)
            : today;

        var tickers = dbHoldings.Select(h => h.Ticker).Distinct().ToList();

        var snapshotStart = new DateTime(startDate.Year, startDate.Month, startDate.Day, 0, 0, 0, DateTimeKind.Utc).AddDays(-30);
        var snapshotEnd   = new DateTime(today.Year, today.Month, today.Day, 23, 59, 59, DateTimeKind.Utc);

        var allSnapshots = await _context.PriceSnapshots
            .Where(ps => tickers.Contains(ps.Ticker) && ps.SnapshotDate >= snapshotStart && ps.SnapshotDate <= snapshotEnd)
            .ToListAsync(cancellationToken);

        var priceByTicker = allSnapshots
            .GroupBy(ps => ps.Ticker)
            .ToDictionary(
                g => g.Key,
                g => g.OrderBy(ps => ps.SnapshotDate)
                      .Select(ps => (Date: DateOnly.FromDateTime(ps.SnapshotDate.Date), Price: ps.Price))
                      .ToList()
            );

        var buyDates  = allTransactions.Where(t => t.TransactionType == TransactionType.Buy) .Select(t => t.PurchaseDate).ToHashSet();
        var sellDates = allTransactions.Where(t => t.TransactionType == TransactionType.Sell).Select(t => t.PurchaseDate).ToHashSet();

        var dataPoints = new List<PortfolioEvolutionDataPointDto>();

        for (var date = startDate; date <= today; date = date.AddDays(1))
        {
            decimal totalValue = 0m;

            foreach (var holding in dbHoldings)
            {
                var buyQty  = holding.Transactions.Where(t => t.TransactionType == TransactionType.Buy  && t.PurchaseDate <= date).Sum(t => t.Quantity);
                var sellQty = holding.Transactions.Where(t => t.TransactionType == TransactionType.Sell && t.PurchaseDate <= date).Sum(t => t.Quantity);
                var quantity = buyQty - sellQty;

                if (quantity <= 0) continue;
                if (!priceByTicker.TryGetValue(holding.Ticker, out var prices)) continue;

                var price = prices
                    .Where(p => p.Date <= date)
                    .Select(p => (decimal?)p.Price)
                    .LastOrDefault();

                if (price.HasValue)
                    totalValue += quantity * price.Value;
            }

            dataPoints.Add(new PortfolioEvolutionDataPointDto
            {
                Date       = date.ToString("yyyy-MM-dd"),
                TotalValue = totalValue,
                HasBuy     = buyDates.Contains(date),
                HasSell    = sellDates.Contains(date)
            });
        }

        return new PortfolioEvolutionDto { DataPoints = dataPoints };
    }

    // ── Asset Tax Rates ───────────────────────────────────────────────────────

    public async Task<List<AssetTaxRateDto>> GetAssetTaxRatesAsync(CancellationToken cancellationToken = default)
    {
        return await _context.AssetTaxRates
            .OrderBy(r => r.SecurityType)
            .Select(r => new AssetTaxRateDto
            {
                SecurityType   = r.SecurityType,
                ExitTaxPercent = r.ExitTaxPercent,
                Label          = r.Label
            })
            .ToListAsync(cancellationToken);
    }

    public async Task<AssetTaxRateDto> UpsertAssetTaxRateAsync(AssetTaxRateDto dto, CancellationToken cancellationToken = default)
    {
        var utcNow   = new DateTime(DateTime.UtcNow.Ticks, DateTimeKind.Utc);
        var existing = await _context.AssetTaxRates.FindAsync(new object[] { dto.SecurityType }, cancellationToken);

        if (existing == null)
        {
            existing = new AssetTaxRate
            {
                SecurityType   = dto.SecurityType.ToUpperInvariant(),
                ExitTaxPercent = dto.ExitTaxPercent,
                Label          = dto.Label,
                CreatedAt      = utcNow,
                UpdatedAt      = utcNow
            };
            _context.AssetTaxRates.Add(existing);
        }
        else
        {
            existing.ExitTaxPercent = dto.ExitTaxPercent;
            existing.Label          = dto.Label;
            existing.UpdatedAt      = utcNow;
            _context.AssetTaxRates.Update(existing);
        }

        await _context.SaveChangesAsync(cancellationToken);
        return new AssetTaxRateDto { SecurityType = existing.SecurityType, ExitTaxPercent = existing.ExitTaxPercent, Label = existing.Label };
    }

    public async Task DeleteAssetTaxRateAsync(string securityType, CancellationToken cancellationToken = default)
    {
        var record = await _context.AssetTaxRates.FindAsync(new object[] { securityType }, cancellationToken);
        if (record == null) return;
        _context.AssetTaxRates.Remove(record);
        await _context.SaveChangesAsync(cancellationToken);
    }

    // ── Tax Year Summary ──────────────────────────────────────────────────────

    public async Task<List<int>> GetTaxYearsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdingIds = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Select(h => h.Id)
            .ToListAsync(cancellationToken);

        if (holdingIds.Count == 0) return new List<int>();

        var years = await _context.Transactions
            .Where(t => holdingIds.Contains(t.HoldingId) && t.TransactionType == TransactionType.Sell)
            .Select(t => t.PurchaseDate.Year)
            .Distinct()
            .OrderByDescending(y => y)
            .ToListAsync(cancellationToken);

        return years;
    }

    public async Task<TaxYearSummaryDto> GetTaxYearSummaryAsync(int userId, int year, CancellationToken cancellationToken = default)
    {
        var holdingMeta = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Select(h => new { h.Id, h.Ticker, h.EtfName, h.SecurityType })
            .ToListAsync(cancellationToken);

        var holdingMap = holdingMeta.ToDictionary(h => h.Id);
        var holdingIds = holdingMeta.Select(h => h.Id).ToList();

        if (holdingIds.Count == 0)
            return new TaxYearSummaryDto { Year = year };

        var yearStart = new DateOnly(year, 1, 1);
        var yearEnd   = new DateOnly(year, 12, 31);

        var sells = await _context.Transactions
            .Where(t => holdingIds.Contains(t.HoldingId)
                     && t.TransactionType == TransactionType.Sell
                     && t.PurchaseDate >= yearStart
                     && t.PurchaseDate <= yearEnd)
            .OrderBy(t => t.PurchaseDate)
            .ThenBy(t => t.Id)
            .ToListAsync(cancellationToken);

        if (sells.Count == 0)
            return new TaxYearSummaryDto { Year = year };

        var sellIds = sells.Select(s => s.Id).ToList();
        var allocations = await _context.SellAllocations
            .Where(a => sellIds.Contains(a.SellTransactionId))
            .ToListAsync(cancellationToken);

        var taxRates = await _context.AssetTaxRates
            .ToDictionaryAsync(r => r.SecurityType.ToUpperInvariant(), r => r.ExitTaxPercent, cancellationToken);

        var entries = new List<TaxSellEntryDto>();

        foreach (var sell in sells)
        {
            holdingMap.TryGetValue(sell.HoldingId, out var holding);

            var txAllocs       = allocations.Where(a => a.SellTransactionId == sell.Id).ToList();
            var totalAllocQty  = txAllocs.Sum(a => a.AllocatedQuantity);
            var totalBuyCost   = txAllocs.Sum(a => a.AllocatedQuantity * a.BuyPrice);
            var weightedBuy    = totalAllocQty > 0 ? totalBuyCost / totalAllocQty : 0m;
            var taxableProfit  = (sell.PurchasePrice - weightedBuy) * sell.Quantity;

            decimal? exitTaxPct = null;
            decimal? exitTaxDue = null;
            var secType = holding?.SecurityType?.ToUpperInvariant();
            if (secType != null && taxRates.TryGetValue(secType, out var rate))
            {
                exitTaxPct = rate;
                exitTaxDue = taxableProfit * (rate / 100m);
            }

            entries.Add(new TaxSellEntryDto
            {
                TransactionId    = sell.Id,
                Ticker           = holding?.Ticker ?? "—",
                EtfName          = holding?.EtfName,
                SellDate         = sell.PurchaseDate.ToString("yyyy-MM-dd"),
                QuantitySold     = sell.Quantity,
                SellPrice        = sell.PurchasePrice,
                WeightedBuyPrice = weightedBuy,
                TaxableProfit    = taxableProfit,
                ExitTaxPercent   = exitTaxPct,
                ExitTaxDue       = exitTaxDue,
                SecurityType     = holding?.SecurityType
            });
        }

        return new TaxYearSummaryDto
        {
            Year               = year,
            Entries            = entries,
            TotalTaxableProfit = entries.Sum(e => e.TaxableProfit),
            TotalExitTaxDue    = entries.Sum(e => e.ExitTaxDue ?? 0m),
            HasMissingRates    = entries.Any(e => e.ExitTaxPercent == null)
        };
    }

    // ── FIFO helpers ──────────────────────────────────────────────────────────

    private async Task AllocateSellFifoAsync(int sellTransactionId, int holdingId, decimal sellQty, CancellationToken cancellationToken)
    {
        var buys = await _context.Transactions
            .Where(t => t.HoldingId == holdingId && t.TransactionType == TransactionType.Buy)
            .OrderBy(t => t.PurchaseDate)
            .ThenBy(t => t.Id)
            .ToListAsync(cancellationToken);

        var buyIds = buys.Select(b => b.Id).ToList();
        var alreadyAllocated = await _context.SellAllocations
            .Where(a => buyIds.Contains(a.BuyTransactionId))
            .GroupBy(a => a.BuyTransactionId)
            .Select(g => new { BuyId = g.Key, Qty = g.Sum(a => a.AllocatedQuantity) })
            .ToDictionaryAsync(x => x.BuyId, x => x.Qty, cancellationToken);

        var remaining    = sellQty;
        var newAllocations = new List<SellAllocation>();

        foreach (var buy in buys)
        {
            if (remaining <= 0) break;

            var consumed  = alreadyAllocated.GetValueOrDefault(buy.Id, 0m);
            var available = buy.Quantity - consumed;
            if (available <= 0) continue;

            var toAllocate = Math.Min(available, remaining);
            newAllocations.Add(new SellAllocation
            {
                SellTransactionId = sellTransactionId,
                BuyTransactionId  = buy.Id,
                AllocatedQuantity = toAllocate,
                BuyPrice          = buy.PurchasePrice
            });
            remaining -= toAllocate;
        }

        _context.SellAllocations.AddRange(newAllocations);
        await _context.SaveChangesAsync(cancellationToken);
    }

    private async Task RecalculateHoldingAsync(int holdingId, DateTime utcNow, CancellationToken cancellationToken)
    {
        var allTxns = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .ToListAsync(cancellationToken);

        var buys     = allTxns.Where(t => t.TransactionType == TransactionType.Buy).ToList();
        var buyIds   = buys.Select(b => b.Id).ToList();
        var sellQty  = allTxns.Where(t => t.TransactionType == TransactionType.Sell).Sum(t => t.Quantity);

        var allocations = await _context.SellAllocations
            .Where(a => buyIds.Contains(a.BuyTransactionId))
            .GroupBy(a => a.BuyTransactionId)
            .Select(g => new { BuyId = g.Key, Qty = g.Sum(a => a.AllocatedQuantity) })
            .ToDictionaryAsync(x => x.BuyId, x => x.Qty, cancellationToken);

        decimal remainingCost = 0m;
        decimal remainingQty  = 0m;
        foreach (var buy in buys)
        {
            var allocated = allocations.GetValueOrDefault(buy.Id, 0m);
            var leftover  = buy.Quantity - allocated;
            if (leftover > 0)
            {
                remainingQty  += leftover;
                remainingCost += leftover * buy.PurchasePrice;
            }
        }

        var holding = await _context.Holdings.FindAsync(new object[] { holdingId }, cancellationToken);
        if (holding != null)
        {
            holding.Quantity    = buys.Sum(b => b.Quantity) - sellQty;
            holding.AverageCost = remainingQty > 0 ? remainingCost / remainingQty : 0m;
            holding.UpdatedAt   = utcNow;
            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);
        }
    }

    // ── Historical price backfill ─────────────────────────────────────────────

    private async Task BackfillHistoricalPricesIfNeededAsync(string ticker, DateOnly purchaseDate, CancellationToken cancellationToken)
    {
        try
        {
            var purchaseDateUtc = purchaseDate.ToDateTime(TimeOnly.MinValue, DateTimeKind.Utc);

            var earliestSnapshotDate = await _context.PriceSnapshots
                .Where(ps => ps.Ticker == ticker)
                .MinAsync(ps => (DateTime?)ps.SnapshotDate, cancellationToken);

            bool needsBackfill = earliestSnapshotDate == null
                                 || earliestSnapshotDate.Value.Date > purchaseDateUtc.Date;

            if (!needsBackfill) return;

            _logger.LogInformation("Starting historical price backfill for {Ticker} from {PurchaseDate}", ticker, purchaseDate);
            var saved = await _priceService.FetchAndSaveHistoricalPricesAsync(ticker, purchaseDate, cancellationToken);
            _logger.LogInformation("Backfill complete for {Ticker}: {Count} snapshots saved", ticker, saved);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error during historical price backfill for {Ticker}", ticker);
        }
    }

    // ── Period metric helpers ─────────────────────────────────────────────────

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal quantity, int days, CancellationToken cancellationToken)
    {
        var currentPrice     = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!currentPrice.HasValue || !priceFromDaysAgo.HasValue)
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0, PricesUnavailable = true };

        var gainLossEur     = (currentPrice.Value - priceFromDaysAgo.Value) * quantity;
        var gainLossPercent = priceFromDaysAgo.Value > 0
            ? ((currentPrice.Value - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100
            : 0;

        return new PeriodMetrics { GainLossEur = gainLossEur, GainLossPercent = gainLossPercent, PricesUnavailable = false };
    }

    private async Task<PeriodMetrics> CalculateYtdMetricsAsync(string ticker, decimal quantity, CancellationToken cancellationToken)
    {
        var currentPrice     = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var firstPriceOfYear = await GetFirstPriceOfYearAsync(ticker, cancellationToken);

        if (!currentPrice.HasValue || !firstPriceOfYear.HasValue)
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0, PricesUnavailable = true };

        var gainLossEur     = (currentPrice.Value - firstPriceOfYear.Value) * quantity;
        var gainLossPercent = firstPriceOfYear.Value > 0
            ? ((currentPrice.Value - firstPriceOfYear.Value) / firstPriceOfYear.Value) * 100
            : 0;

        return new PeriodMetrics { GainLossEur = gainLossEur, GainLossPercent = gainLossPercent, PricesUnavailable = false };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null) return snapshot.Price;

        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private async Task<decimal?> GetFirstPriceOfYearAsync(string ticker, CancellationToken cancellationToken)
    {
        var currentYear = DateTime.UtcNow.Year;
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate.Year == currentYear)
            .OrderBy(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;
        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private static bool IsSubjectToDeemedDisposal(string? securityType)
        => securityType?.ToUpperInvariant() is "ETF" or "MUTUALFUND" or "FUND";
}

// ── STICKY HEADER WRAPPER ────────────────────────────────────────────────────
// Wraps both the viewing-as banner and the nav so they stick together at top.
.sticky-header {
  position: sticky;
  top: 0;
  z-index: 1000;
  margin: -2rem -2.5rem 2rem -2.5rem;

  @media (max-width: 768px) {
    margin: -2rem -1rem 1.5rem -1rem;
  }
}

// ── VIEWING-AS BANNER ────────────────────────────────────────────────────────
.viewing-as-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.7rem 2.5rem;
  background: linear-gradient(135deg, rgba(79, 142, 247, 0.15) 0%, rgba(124, 92, 252, 0.15) 100%);
  border-bottom: 1px solid rgba(79, 142, 247, 0.3);

  .viewing-as-label {
    font-size: 0.9rem;
    color: #8da0bf;
    display: flex;
    align-items: center;
    gap: 0.6rem;

    strong { color: #4f8ef7; }

    .readonly-chip {
      font-size: 0.75rem;
      padding: 0.15rem 0.55rem;
      background: rgba(248, 155, 41, 0.15);
      color: #f89b29;
      border-radius: 999px;
      border: 1px solid rgba(248, 155, 41, 0.3);
    }
  }

  .btn-stop-viewing {
    flex-shrink: 0;
    padding: 0.4rem 0.9rem;
    background: rgba(255, 255, 255, 0.07);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 8px;
    color: #c9d6ea;
    font-size: 0.83rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;

    &:hover {
      background: rgba(255, 255, 255, 0.12);
      color: #fff;
    }
  }

  @media (max-width: 768px) {
    padding: 0.6rem 1rem;
    flex-wrap: wrap;
  }
}

// ── TOP NAVIGATION ──────────────────────────────────────────────────────────
.top-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 2.5rem;
  background: linear-gradient(135deg, #0d1526 0%, #111d35 100%);
  border-bottom: 1px solid var(--border);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3);
  // sticky + margins moved to .sticky-header wrapper

  .nav-left {
    flex: 0 0 auto;

    .app-brand {
      font-size: 1.3rem;
      font-weight: 800;
      color: var(--text-primary);
      letter-spacing: -0.02em;
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }
  }

  .nav-right {
    flex: 0 0 auto;

    .user-menu {
      display: flex;
      align-items: center;
      gap: 1.25rem;
      padding: 0.5rem 1rem 0.5rem 1.25rem;
      background: rgba(255, 255, 255, 0.03);
      border: 1px solid rgba(79, 142, 247, 0.1);
      border-radius: 12px;
      transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);

      &:hover {
        background: rgba(255, 255, 255, 0.06);
        border-color: rgba(79, 142, 247, 0.25);
        box-shadow: 0 0 0 3px rgba(79, 142, 247, 0.08);
      }

      .user-info {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        min-width: 0;

        .avatar-wrapper {
          flex-shrink: 0;
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background: var(--bg-elevated);
          border: 2px solid var(--border-light);
          overflow: hidden;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: all 0.2s;

          .avatar {
            width: 100%;
            height: 100%;
            object-fit: cover;
          }

          .avatar-placeholder {
            width: 100%;
            height: 100%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 700;
            font-size: 1rem;
            background: linear-gradient(135deg, var(--accent-purple) 0%, var(--accent) 100%);
            color: #fff;
          }

          &:hover {
            border-color: var(--accent);
            box-shadow: 0 0 0 2px rgba(79, 142, 247, 0.2);
            transform: scale(1.05);
          }
        }

        .user-details {
          display: flex;
          flex-direction: column;
          gap: 0.15rem;
          min-width: 0;

          .user-name {
            font-weight: 600;
            font-size: 0.95rem;
            color: var(--text-primary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }

          .user-email {
            font-size: 0.78rem;
            color: var(--text-secondary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }
        }
      }

      .btn-share {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(124, 92, 252, 0.12);
        color: #a78bfa;
        border: 1px solid rgba(124, 92, 252, 0.25);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .share-text { display: inline; }

        &:hover {
          background: rgba(124, 92, 252, 0.22);
          border-color: rgba(124, 92, 252, 0.45);
          color: #c4b5fd;
          transform: translateY(-1px);
        }
      }

      .btn-settings {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(79, 142, 247, 0.08);
        color: var(--accent);
        border: 1px solid rgba(79, 142, 247, 0.2);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        text-decoration: none;
        transition: all 0.2s;
        white-space: nowrap;

        .settings-text { display: inline; }

        &:hover {
          background: rgba(79, 142, 247, 0.16);
          border-color: rgba(79, 142, 247, 0.4);
          transform: translateY(-1px);
        }
      }

      .btn-logout {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.5rem;
        padding: 0.5rem 1rem;
        background: var(--accent);
        color: #fff;
        border: none;
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .logout-icon {
          font-size: 1rem;
        }

        &:hover {
          background: var(--accent-hover);
          transform: translateY(-2px);
          box-shadow: 0 4px 12px rgba(79, 142, 247, 0.3);
        }

        &:active {
          transform: translateY(0);
        }
      }
    }
  }

  @media (max-width: 768px) {
    padding: 0.8rem 1rem;
    flex-wrap: wrap;
    gap: 0.75rem;

    .nav-left .app-brand {
      font-size: 1.1rem;
    }

    .nav-right .user-menu {
      gap: 0.75rem;
      padding: 0.4rem 0.8rem;

      .user-info .avatar-wrapper {
        width: 36px;
        height: 36px;
      }

      .user-details {
        display: none;
      }

      .btn-share .share-text {
        display: none;
      }

      .btn-settings .settings-text {
        display: none;
      }

      .btn-logout {
        padding: 0.4rem 0.8rem;
        font-size: 0.78rem;

        .logout-text {
          display: none;
        }
      }
    }
  }
}

// ── Shared helpers ──────────────────────────────────────────────────────────
%card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
}

%section-heading {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin-bottom: 1.25rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;

  &::before {
    content: '';
    display: inline-block;
    width: 3px;
    height: 1em;
    border-radius: 2px;
    background: var(--accent);
  }
}

// ── Sortable table header ───────────────────────────────────────────────────
th.sortable {
  cursor: pointer;
  user-select: none;
  white-space: nowrap;

  &::after {
    content: ' ⇅';
    font-size: 0.7em;
    opacity: 0.35;
    transition: opacity 0.15s;
  }

  &:hover::after { opacity: 0.7; }

  &.sort-asc::after  { content: ' ▲'; opacity: 0.85; color: var(--accent); }
  &.sort-desc::after { content: ' ▼'; opacity: 0.85; color: var(--accent); }

  &:hover { color: var(--accent); }
}

// ── Dashboard shell ─────────────────────────────────────────────────────────
.dashboard-container {
  padding: 2rem 2.5rem;
  max-width: 1700px;
  margin: 0 auto;

  // Loading & error states
  .loading, .error {
    text-align: center;
    padding: 4rem 2rem;
    font-size: 1rem;
    color: var(--text-secondary);

    button {
      margin-top: 1.25rem;
      padding: 0.6rem 1.75rem;
      background: var(--accent);
      color: #fff;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-weight: 600;
      transition: background 0.2s;

      &:hover { background: var(--accent-hover); }
    }
  }

  .error {
    @extend %card;
    color: var(--negative);
    border-color: rgba(240, 82, 82, 0.3);
    background: rgba(240, 82, 82, 0.06);
  }

  // ── Dashboard content ──────────────────────────────────────────────────────
  .dashboard-content {

    // ── HEADER ────────────────────────────────────────────────────────────────
    .dashboard-header {
      margin-bottom: 2.5rem;

      h1 {
        font-size: 1.65rem;
        font-weight: 800;
        letter-spacing: -0.03em;
        color: var(--text-primary);
        margin-bottom: 1.75rem;
        display: flex;
        align-items: center;
        gap: 0.75rem;

        &::after {
          content: '';
          flex: 1;
          height: 1px;
          background: var(--border);
        }
      }

      // Metric cards grid
      .metrics-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 1rem;
        margin-bottom: 1.5rem;

        .metric-card {
          @extend %card;
          padding: 1.35rem 1.5rem;
          position: relative;
          overflow: hidden;
          transition: transform 0.18s, box-shadow 0.18s;

          &::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2px;
            background: var(--border-light);
            transition: background 0.2s;
          }

          &:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 28px rgba(0,0,0,0.55);
            &::before { background: var(--accent); }
          }

          .metric-label {
            font-size: 0.72rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .exclamation-mark {
              display: inline-flex;
              align-items: center;
              justify-content: center;
              width: 1.15rem;
              height: 1.15rem;
              background: var(--negative);
              color: #fff;
              border-radius: 50%;
              font-size: 0.7rem;
              font-weight: 700;
              flex-shrink: 0;
            }
          }

          .metric-value {
            font-size: 1.65rem;
            font-weight: 800;
            letter-spacing: -0.03em;
            color: var(--text-primary);
            margin-bottom: 0.25rem;
            font-variant-numeric: tabular-nums;
          }

          .metric-percent {
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--text-secondary);
          }

          .price-unavailable-message {
            font-size: 0.75rem;
            color: var(--negative);
            margin-top: 0.6rem;
            font-style: italic;
            background: var(--negative-bg);
            padding: 0.35rem 0.6rem;
            border-radius: 5px;
          }

          // Total Holdings – blue gradient hero card
          &.total {
            background: linear-gradient(135deg, #1a3a6e 0%, #0f224d 100%);
            border-color: rgba(79, 142, 247, 0.3);

            &::before { background: var(--accent); }

            .metric-label { color: rgba(228, 234, 245, 0.6); }
            .metric-value { color: #fff; font-size: 1.9rem; }
          }

          &.positive {
            .metric-value, .metric-percent { color: var(--positive); }
            &::before { background: var(--positive); }
          }

          &.negative {
            .metric-value, .metric-percent { color: var(--negative); }
            &::before { background: var(--negative); }
          }
        }
      }

      .action-buttons {
        display: flex;
        gap: 0.75rem;

        .btn {
          padding: 0.55rem 1.35rem;
          font-size: 0.88rem;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          font-weight: 600;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;
            box-shadow: 0 0 0 0 var(--accent-glow);

            &:hover {
              background: var(--accent-hover);
              box-shadow: 0 0 0 4px var(--accent-glow);
            }
          }
        }
      }
    }

    // ── PROJECTION SECTION ─────────────────────────────────────────────────
    .projection-section {
      @extend %card;
      padding: 1.75rem;
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Parameter inputs row
      .projection-params {
        display: flex;
        flex-wrap: wrap;
        align-items: flex-end;
        gap: 1rem;
        margin-bottom: 1.75rem;
        padding: 1.25rem;
        background: var(--bg-surface);
        border: 1px solid var(--border);
        border-radius: 8px;

        .param-group {
          display: flex;
          flex-direction: column;
          gap: 0.35rem;

          label {
            font-size: 0.68rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.07em;
          }

          input[type='number'] {
            width: 130px;
            padding: 0.5rem 0.7rem;
            border: 1px solid var(--border-light);
            border-radius: 7px;
            font-size: 0.9rem;
            color: var(--text-primary);
            background: var(--bg-input);
            transition: border-color 0.18s, box-shadow 0.18s;
            font-variant-numeric: tabular-nums;

            &:focus {
              outline: none;
              border-color: var(--accent);
              box-shadow: 0 0 0 3px var(--accent-glow);
            }
          }

          &.checkbox-group {
            justify-content: flex-end;

            .checkbox-label {
              display: flex;
              align-items: center;
              gap: 0.5rem;
              font-size: 0.82rem;
              font-weight: 500;
              color: var(--text-secondary);
              text-transform: none;
              letter-spacing: normal;
              cursor: pointer;
              white-space: nowrap;

              input[type='checkbox'] {
                width: 16px;
                height: 16px;
                accent-color: var(--accent);
                cursor: pointer;
              }
            }
          }

          &.start-amount-group {
            .start-amount-input-row {
              display: flex;
              align-items: center;
              gap: 0.4rem;

              input[type='number'] {
                width: 130px;
              }

              .btn-copy-portfolio {
                flex-shrink: 0;
                display: flex;
                align-items: center;
                justify-content: center;
                width: 32px;
                height: 32px;
                padding: 0;
                background: var(--bg-elevated);
                border: 1px solid var(--border-light);
                border-radius: 7px;
                font-size: 0.9rem;
                cursor: pointer;
                transition: all 0.18s;
                color: var(--text-secondary);

                &:hover {
                  background: rgba(79, 142, 247, 0.12);
                  border-color: var(--accent);
                  color: var(--accent);
                  transform: scale(1.1);
                }

                &:active {
                  transform: scale(0.96);
                }
              }
            }

            .start-amount-hint {
              font-size: 0.65rem;
              color: var(--text-muted);
              font-style: italic;
              margin-top: 0.15rem;
              display: block;
            }
          }
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }

          &.btn-secondary {
            background: transparent;
            border: 1px solid var(--accent);
            color: var(--accent);

            &:hover:not(:disabled) { background: rgba(79, 142, 247, 0.10); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }

        .save-version-row {
          display: flex;
          align-items: center;
          gap: 0.5rem;
          align-self: flex-end;

          .version-name-input {
            height: 36px;
            padding: 0.3rem 0.75rem;
            background: var(--bg-elevated);
            border: 1px solid var(--border-light);
            border-radius: 7px;
            color: var(--text-primary);
            font-size: 0.85rem;
            min-width: 160px;
            transition: border-color 0.18s;

            &::placeholder { color: var(--text-muted); }

            &:focus {
              outline: none;
              border-color: var(--accent);
            }
          }

          .btn { align-self: unset; }
        }

        // Tax section grouping
        .tax-section {
          width: 100%;
          padding: 0.75rem 0 0.25rem 0;

          .tax-section-header {
            font-size: 0.72rem;
            font-weight: 700;
            color: var(--accent);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .sia-tooltip {
              font-size: 0.85rem;
              cursor: help;
              opacity: 0.7;
              transition: opacity 0.18s;

              &:hover {
                opacity: 1;
              }
            }
          }

          .tax-section-fields {
            display: flex;
            flex-wrap: wrap;
            align-items: flex-end;
            gap: 1rem;
          }
        }

        .tax-section-separator {
          width: 100%;
          border-top: 1px dashed var(--border);
          margin: 0.25rem 0;
        }
      }

      // Default-version banner (top of params box)
      .params-default-banner {
        width: 100%;
        padding: 0.55rem 0.9rem;
        background: rgba(248, 155, 41, 0.07);
        border: 1px solid rgba(248, 155, 41, 0.22);
        border-left: 3px solid #f89b29;
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);

        strong { color: #f89b29; font-weight: 700; }
      }

      // Tab nav
      .projection-tab-nav {
        display: flex;
        gap: 0;
        align-items: center;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }

        // Right-aligned default version badge
        .default-version-badge {
          margin-left: auto;
          padding: 0.22rem 0.75rem;
          background: rgba(248, 155, 41, 0.10);
          border: 1px solid rgba(248, 155, 41, 0.28);
          border-radius: 999px;
          font-size: 0.76rem;
          color: #f89b29;
          white-space: nowrap;
          flex-shrink: 0;

          strong { color: #f89b29; font-weight: 700; }
        }
      }

      // Params-link hint bar (Graph & Table tabs)
      .params-link-hint {
        width: 100%;
        padding: 0.5rem 0.9rem;
        margin-bottom: 1rem;
        background: rgba(79, 142, 247, 0.06);
        border: 1px solid rgba(79, 142, 247, 0.14);
        border-left: 3px solid var(--accent);
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);
        box-sizing: border-box;

        strong { color: var(--text-primary); font-weight: 600; }
        em { font-style: normal; font-weight: 600; color: var(--accent); }

        // Version-specific variant (amber)
        &.params-link-hint--versioned {
          background: rgba(248, 155, 41, 0.06);
          border-color: rgba(248, 155, 41, 0.18);
          border-left-color: #f89b29;

          strong { color: #f89b29; }
          em     { color: var(--accent); }
        }
      }

      .tab-panel { /* intentionally bare */ }

      .projection-chart-wrapper {
        height: 380px;
        position: relative;
      }

      .projection-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Data table
      .projection-table-wrapper {
        overflow-x: auto;
        border-radius: 7px;
        border: 1px solid var(--border);

        .table-controls {
          display: flex;
          align-items: center;
          padding: 0.6rem 0.9rem;
          border-bottom: 1px solid var(--border);
          background: var(--bg-elevated);

          .show-sia-checkbox {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            font-size: 0.82rem;
            font-weight: 500;
            color: var(--text-secondary);
            cursor: pointer;

            input[type='checkbox'] {
              width: 16px;
              height: 16px;
              accent-color: #2ec4b6;
              cursor: pointer;
            }
          }
        }
      }

      .projection-table {
        // ...existing projection-table styles...
        width: 100%;
        border-collapse: collapse;
        font-size: 0.77rem;

        thead {
          background: var(--bg-elevated);
          border-bottom: 1px solid var(--border);

          th {
            padding: 0.65rem 0.9rem;
            text-align: left;
            font-weight: 600;
            color: var(--text-muted);
            white-space: nowrap;
            text-transform: uppercase;
            font-size: 0.68rem;
            letter-spacing: 0.06em;
          }
        }

        tbody tr {
          border-bottom: 1px solid var(--border);
          transition: background 0.15s;

          &:last-child { border-bottom: none; }
          &:hover { background: var(--bg-elevated); }
        }

        td {
          padding: 0.55rem 0.9rem;

          &.year-col {
            font-weight: 700;
            color: var(--accent);
          }

          &.value-col {
            font-family: 'Monaco', 'Courier New', monospace;
            text-align: right;
            color: var(--text-secondary);
          }

          &.buys-col { color: var(--accent-purple); }

          &.profit-col {
            font-weight: 600;
            &.positive { color: var(--positive); }
            &.negative { color: var(--negative); }
          }

          &.eoy-col {
            font-weight: 700;
            color: var(--text-primary);
          }

          &.inflation-col { color: #f89b29; }

          &.tax-col {
            position: relative;

            &.tax-due {
              color: var(--negative);
              font-weight: 600;
            }

            .exit-tax-badge {
              display: inline-block;
              margin-left: 0.3rem;
              padding: 0.1rem 0.3rem;
              background: var(--accent-purple);
              color: #fff;
              border-radius: 3px;
              font-size: 0.62rem;
              font-weight: 700;
              vertical-align: middle;
              cursor: help;
            }
          }

          &.after-tax-col {
            font-weight: 700;
            color: var(--accent-cyan);
          }

          &.after-tax-inflation-col {
            font-weight: 700;
            color: var(--text-secondary);
          }

          &.sia-col {
            font-weight: 600;
            color: #2ec4b6;
          }
        }

        .sia-col-header {
          color: #2ec4b6 !important;
          border-left: 2px solid rgba(46, 196, 182, 0.25);
        }
      }

      // ── Versions tab ──────────────────────────────────────────────────────
      .versions-panel {
        .versions-layout {
          display: flex;
          flex-direction: column;
          gap: 1.75rem;

          .versions-table-container {
            width: 100%;
            overflow-x: auto;

            .no-versions-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 1rem 0;
              font-size: 0.88rem;
            }

            .versions-table {
              width: 100%;
              border-collapse: collapse;
              font-size: 0.78rem;

              thead {
                background: var(--bg-elevated);
                border-bottom: 1px solid var(--border);

                th {
                  padding: 0.5rem 0.75rem;
                  text-align: left;
                  font-weight: 600;
                  color: var(--text-muted);
                  white-space: nowrap;
                  text-transform: uppercase;
                  font-size: 0.66rem;
                  letter-spacing: 0.06em;
                }
              }

              tbody tr {
                border-bottom: 1px solid var(--border);
                transition: background 0.15s;

                &:last-child { border-bottom: none; }
                &:hover { background: var(--bg-elevated); cursor: pointer; }

                &.version-selected td {
                  background: rgba(79, 142, 247, 0.08);
                }

                &.version-default td {
                  background: rgba(248, 155, 41, 0.05);
                }
              }

              td {
                padding: 0.45rem 0.75rem;
                color: var(--text-secondary);
                white-space: nowrap;

                &.version-check-col {
                  text-align: center;
                  width: 36px;

                  input[type='checkbox'] {
                    accent-color: var(--accent);
                    width: 14px;
                    height: 14px;
                    cursor: pointer;
                  }
                }

                &.version-num-col {
                  color: var(--text-primary);
                  font-size: 0.82rem;
                  display: flex;
                  align-items: center;
                  gap: 0.4rem;
                  flex-wrap: wrap;

                  .default-badge {
                    display: inline-flex;
                    align-items: center;
                    font-size: 0.68rem;
                    font-weight: 600;
                    color: #f89b29;
                    background: rgba(248, 155, 41, 0.12);
                    border: 1px solid rgba(248, 155, 41, 0.3);
                    border-radius: 999px;
                    padding: 0.1rem 0.45rem;
                    white-space: nowrap;
                  }
                }

                &.version-date-col {
                  font-size: 0.76rem;
                  color: var(--text-muted);
                }

                &.version-stat-col {
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.76rem;
                  text-align: right;
                }

                &.version-bool-col {
                  text-align: center;
                  font-weight: 700;
                  font-family: inherit;
                  color: var(--positive);
                }

                &.version-delete-col {
                  text-align: center;
                  width: 72px;
                  white-space: nowrap;
                }
              }

              .btn-set-default {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.5;
                margin-right: 0.15rem;

                &:hover:not(:disabled) {
                  background: rgba(248, 155, 41, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.3;
                }
              }

              .btn-delete-version {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.6;

                &:hover:not(:disabled) {
                  background: rgba(240, 82, 82, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.35;
                }
              }

              .delete-confirm-inline {
                display: flex;
                align-items: center;
                gap: 0.2rem;

                .btn-confirm-yes {
                  background: rgba(240, 82, 82, 0.2);
                  border: 1px solid rgba(240, 82, 82, 0.5);
                  color: #f05252;
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(240, 82, 82, 0.4); }
                  &:disabled { opacity: 0.4; cursor: not-allowed; }
                }

                .btn-confirm-no {
                  background: rgba(141, 160, 191, 0.1);
                  border: 1px solid rgba(141, 160, 191, 0.3);
                  color: #8da0bf;
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(141, 160, 191, 0.25); }
                }
              }
            }
          }

          .versions-chart-container {
            width: 100%;
            min-height: 540px;
            position: relative;

            canvas {
              width: 100% !important;
              height: 540px !important;
            }

            .versions-chart-hint {
              font-size: 0.8rem;
              color: var(--text-muted);
              margin-bottom: 0.85rem;
              padding: 0.45rem 0.75rem;
              background: var(--bg-surface);
              border-radius: 6px;
              border: 1px solid var(--border);
              display: inline-block;

              strong { color: var(--accent); }
            }

            .no-selection-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 4rem 1rem;
              text-align: center;
              font-size: 0.88rem;
            }
          }
        }
      }
    }

    // ── ALLOCATION SECTION ────────────────────────────────────────────────
    .allocation-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .allocation-content {
        @extend %card;
        display: flex;
        gap: 2.5rem;
        align-items: flex-start;
        padding: 1.75rem;

        .pie-wrapper {
          flex: 0 0 280px;
          height: 280px;
          position: relative;
        }

        .allocation-legend {
          flex: 1;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
          gap: 0.75rem;
          align-content: start;

          .legend-item {
            display: flex;
            align-items: flex-start;
            gap: 0.65rem;
            padding: 0.75rem;
            border-radius: 8px;
            background: var(--bg-surface);
            border: 1px solid var(--border);
            transition: border-color 0.18s, box-shadow 0.18s;

            &:hover {
              border-color: var(--accent);
              box-shadow: 0 0 0 1px var(--accent-glow);
            }

            .legend-color {
              flex-shrink: 0;
              width: 13px;
              height: 13px;
              border-radius: 3px;
              margin-top: 4px;
            }

            .legend-details {
              display: flex;
              flex-direction: column;
              gap: 0.15rem;
              min-width: 0;

              .legend-ticker {
                font-weight: 700;
                font-size: 0.88rem;
                color: var(--accent);
              }

              .legend-name {
                font-size: 0.74rem;
                color: var(--text-muted);
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }

              .legend-metrics {
                display: flex;
                align-items: center;
                gap: 0.4rem;
                margin-top: 0.2rem;

                .legend-amount {
                  font-weight: 600;
                  font-size: 0.88rem;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                .legend-percent {
                  font-size: 0.8rem;
                  color: var(--accent-purple);
                  font-weight: 600;
                  background: rgba(124, 92, 252, 0.12);
                  border-radius: 4px;
                  padding: 1px 6px;
                }
              }
            }
          }
        }
      }
    }

    // ── HOLDINGS SECTION ──────────────────────────────────────────────────
    .holdings-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .action-buttons {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        margin-bottom: 1.25rem;

        .readonly-notice {
          font-size: 0.85rem;
          color: #f89b29;
          padding: 0.45rem 0.9rem;
          background: rgba(248, 155, 41, 0.08);
          border: 1px solid rgba(248, 155, 41, 0.2);
          border-radius: 7px;
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }
      }

      // Tab nav (same pattern)
      .holdings-tab-nav {
        display: flex;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      // Evolution chart
      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot   { background: #f05252; border: 2px solid #c0392b; }
          &.sell-dot  { background: #f08252; border: 2px solid #c96035; margin-left: 0.25rem; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      // Period filter buttons
      .evolution-period-nav {
        display: flex;
        gap: 0.5rem;
        flex-wrap: wrap;
        margin-bottom: 1rem;

        .period-btn {
          padding: 0.35rem 0.9rem;
          border-radius: 999px;
          border: 1px solid var(--border);
          background: transparent;
          color: var(--text-secondary);
          font-size: 0.82rem;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.18s;

          &:hover {
            border-color: var(--accent);
            color: var(--accent);
          }

          &.active {
            background: var(--accent);
            border-color: var(--accent);
            color: #fff;
            font-weight: 600;
          }
        }
      }

      .evolution-no-data {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Holdings table
      .table-wrapper {
        overflow-x: auto;
        border-radius: var(--radius);
        border: 1px solid var(--border);
        background: var(--bg-card);

        .holdings-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.88rem;

          thead {
            background: var(--bg-elevated);
            border-bottom: 1px solid var(--border);

            th {
              padding: 0.85rem 1rem;
              text-align: left;
              font-weight: 600;
              color: var(--text-muted);
              white-space: nowrap;
              text-transform: uppercase;
              font-size: 0.68rem;
              letter-spacing: 0.06em;
              border-right: 1px solid var(--border);

              &:last-child { border-right: none; }
            }

            .periods-header th {
              border-bottom: 1px solid var(--border);
              padding: 0.45rem 1rem;
              font-size: 0.65rem;
            }
          }

          tbody {
            tr.holding-row {
              border-bottom: 1px solid var(--border);
              transition: background 0.15s;
              border-left: 3px solid transparent;

              &:hover { background: var(--bg-elevated); }

              &.price-unavailable {
                border-left-color: var(--negative);
                background: var(--negative-bg);
              }

              td {
                padding: 0.85rem 1rem;
                border-right: 1px solid var(--border);

                &:last-child { border-right: none; }

                &.ticker {
                  font-weight: 700;
                  color: var(--accent);
                  font-size: 0.95rem;
                }

                &.quantity, &.price {
                  text-align: right;
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.85rem;
                  color: var(--text-secondary);
                }


                &.total-value {
                  text-align: right;
                  font-weight: 700;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                &.positive {
                  color: var(--positive);
                  font-weight: 600;
                  background: var(--positive-bg);
                }

                &.negative {
                  color: var(--negative);
                  font-weight: 600;
                  background: var(--negative-bg);
                }

                .gain-loss {
                  display: flex;
                  flex-direction: column;
                  align-items: flex-end;
                  gap: 0.2rem;
                  font-variant-numeric: tabular-nums;

                  .percent {
                    font-size: 0.78rem;
                    opacity: 0.75;
                  }
                }

                &.actions {
                  text-align: center;
                  white-space: nowrap;

                  .btn-link {
                    background: none;
                    border: 1px solid var(--border-light);
                    color: var(--accent);
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;
                    margin-right: 0.25rem;

                    &:hover {
                      background: var(--accent-glow);
                      border-color: var(--accent);
                    }
                  }

                  .btn-sell-action {
                    background: rgba(240, 130, 82, 0.1);
                    border: 1px solid rgba(240, 130, 82, 0.3);
                    color: #f08252;
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;

                    &:hover {
                      background: rgba(240, 130, 82, 0.2);
                      border-color: #f08252;
                    }
                  }
                }

                &.deemed-disposal-cell {
                  text-align: center;
                  white-space: nowrap;

                  .deemed-disposal-date {
                    display: inline-flex;
                    align-items: center;
                    gap: 0.3rem;
                    font-size: 0.82rem;
                    font-weight: 600;
                    color: #f89b29;
                    cursor: help;
                    position: relative;

                    // Tooltip
                    &::after {
                      content: attr(data-tooltip);
                      position: absolute;
                      bottom: calc(100% + 8px);
                      left: 50%;
                      transform: translateX(-50%);
                      background: #172040;
                      color: #c9d6ea;
                      border: 1px solid #1f2e4a;
                      border-radius: 8px;
                      padding: 0.6rem 0.8rem;
                      font-size: 0.78rem;
                      font-weight: 400;
                      line-height: 1.4;
                      white-space: normal;
                      width: 260px;
                      text-align: center;
                      box-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
                      opacity: 0;
                      pointer-events: none;
                      transition: opacity 0.18s ease;
                      z-index: 100;
                    }

                    &::before {
                      content: '';
                      position: absolute;
                      bottom: calc(100% + 2px);
                      left: 50%;
                      transform: translateX(-50%);
                      border: 6px solid transparent;
                      border-top-color: #1f2e4a;
                      opacity: 0;
                      pointer-events: none;
                      transition: opacity 0.18s ease;
                      z-index: 101;
                    }

                    &:hover::after,
                    &:hover::before {
                      opacity: 1;
                    }
                  }

                  .deemed-disposal-na {
                    color: var(--text-muted);
                    font-size: 0.82rem;
                  }
                }
              }
            }
          }
        }

        // Holdings table header: Deemed Disposal column
        .deemed-disposal-th {
          white-space: nowrap;

          .col-info-icon {
            margin-left: 0.3rem;
            cursor: help;
            font-size: 0.8rem;
            opacity: 0.7;
          }
        }
      }
    }
  }
}

// ── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 768px) {
  .dashboard-container {
    padding: 1rem;

    .dashboard-content {
      .dashboard-header h1 { font-size: 1.3rem; }

      .allocation-section .allocation-content {
        flex-direction: column;
        align-items: center;

        .pie-wrapper {
          flex: 0 0 220px;
          height: 220px;
          width: 220px;
        }

        .allocation-legend {
          grid-template-columns: 1fr 1fr;
          width: 100%;
        }
      }

      .holdings-section .table-wrapper {
        font-size: 0.8rem;

        .holdings-table {
          thead th { padding: 0.6rem 0.5rem; }
          tbody td { padding: 0.6rem 0.5rem; }
        }
      }
    }
  }
}

// ── STICKY HEADER WRAPPER ────────────────────────────────────────────────────
// Wraps both the viewing-as banner and the nav so they stick together at top.
.sticky-header {
  position: sticky;
  top: 0;
  z-index: 1000;
  margin: -2rem -2.5rem 2rem -2.5rem;

  @media (max-width: 768px) {
    margin: -2rem -1rem 1.5rem -1rem;
  }
}

// ── VIEWING-AS BANNER ────────────────────────────────────────────────────────
.viewing-as-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.7rem 2.5rem;
  background: linear-gradient(135deg, rgba(79, 142, 247, 0.15) 0%, rgba(124, 92, 252, 0.15) 100%);
  border-bottom: 1px solid rgba(79, 142, 247, 0.3);

  .viewing-as-label {
    font-size: 0.9rem;
    color: #8da0bf;
    display: flex;
    align-items: center;
    gap: 0.6rem;

    strong { color: #4f8ef7; }

    .readonly-chip {
      font-size: 0.75rem;
      padding: 0.15rem 0.55rem;
      background: rgba(248, 155, 41, 0.15);
      color: #f89b29;
      border-radius: 999px;
      border: 1px solid rgba(248, 155, 41, 0.3);
    }
  }

  .btn-stop-viewing {
    flex-shrink: 0;
    padding: 0.4rem 0.9rem;
    background: rgba(255, 255, 255, 0.07);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 8px;
    color: #c9d6ea;
    font-size: 0.83rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;

    &:hover {
      background: rgba(255, 255, 255, 0.12);
      color: #fff;
    }
  }

  @media (max-width: 768px) {
    padding: 0.6rem 1rem;
    flex-wrap: wrap;
  }
}

// ── TOP NAVIGATION ──────────────────────────────────────────────────────────
.top-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 2.5rem;
  background: linear-gradient(135deg, #0d1526 0%, #111d35 100%);
  border-bottom: 1px solid var(--border);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3);
  // sticky + margins moved to .sticky-header wrapper

  .nav-left {
    flex: 0 0 auto;

    .app-brand {
      font-size: 1.3rem;
      font-weight: 800;
      color: var(--text-primary);
      letter-spacing: -0.02em;
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }
  }

  .nav-right {
    flex: 0 0 auto;

    .user-menu {
      display: flex;
      align-items: center;
      gap: 1.25rem;
      padding: 0.5rem 1rem 0.5rem 1.25rem;
      background: rgba(255, 255, 255, 0.03);
      border: 1px solid rgba(79, 142, 247, 0.1);
      border-radius: 12px;
      transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);

      &:hover {
        background: rgba(255, 255, 255, 0.06);
        border-color: rgba(79, 142, 247, 0.25);
        box-shadow: 0 0 0 3px rgba(79, 142, 247, 0.08);
      }

      .user-info {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        min-width: 0;

        .avatar-wrapper {
          flex-shrink: 0;
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background: var(--bg-elevated);
          border: 2px solid var(--border-light);
          overflow: hidden;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: all 0.2s;

          .avatar {
            width: 100%;
            height: 100%;
            object-fit: cover;
          }

          .avatar-placeholder {
            width: 100%;
            height: 100%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 700;
            font-size: 1rem;
            background: linear-gradient(135deg, var(--accent-purple) 0%, var(--accent) 100%);
            color: #fff;
          }

          &:hover {
            border-color: var(--accent);
            box-shadow: 0 0 0 2px rgba(79, 142, 247, 0.2);
            transform: scale(1.05);
          }
        }

        .user-details {
          display: flex;
          flex-direction: column;
          gap: 0.15rem;
          min-width: 0;

          .user-name {
            font-weight: 600;
            font-size: 0.95rem;
            color: var(--text-primary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }

          .user-email {
            font-size: 0.78rem;
            color: var(--text-secondary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }
        }
      }

      .btn-share {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(124, 92, 252, 0.12);
        color: #a78bfa;
        border: 1px solid rgba(124, 92, 252, 0.25);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .share-text { display: inline; }

        &:hover {
          background: rgba(124, 92, 252, 0.22);
          border-color: rgba(124, 92, 252, 0.45);
          color: #c4b5fd;
          transform: translateY(-1px);
        }
      }

      .btn-settings {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(79, 142, 247, 0.08);
        color: var(--accent);
        border: 1px solid rgba(79, 142, 247, 0.2);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        text-decoration: none;
        transition: all 0.2s;
        white-space: nowrap;

        .settings-text { display: inline; }

        &:hover {
          background: rgba(79, 142, 247, 0.16);
          border-color: rgba(79, 142, 247, 0.4);
          transform: translateY(-1px);
        }
      }

      .btn-logout {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.5rem;
        padding: 0.5rem 1rem;
        background: var(--accent);
        color: #fff;
        border: none;
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .logout-icon {
          font-size: 1rem;
        }

        &:hover {
          background: var(--accent-hover);
          transform: translateY(-2px);
          box-shadow: 0 4px 12px rgba(79, 142, 247, 0.3);
        }

        &:active {
          transform: translateY(0);
        }
      }
    }
  }

  @media (max-width: 768px) {
    padding: 0.8rem 1rem;
    flex-wrap: wrap;
    gap: 0.75rem;

    .nav-left .app-brand {
      font-size: 1.1rem;
    }

    .nav-right .user-menu {
      gap: 0.75rem;
      padding: 0.4rem 0.8rem;

      .user-info .avatar-wrapper {
        width: 36px;
        height: 36px;
      }

      .user-details {
        display: none;
      }

      .btn-share .share-text {
        display: none;
      }

      .btn-settings .settings-text {
        display: none;
      }

      .btn-logout {
        padding: 0.4rem 0.8rem;
        font-size: 0.78rem;

        .logout-text {
          display: none;
        }
      }
    }
  }
}

// ── Shared helpers ──────────────────────────────────────────────────────────
%card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
}

%section-heading {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin-bottom: 1.25rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;

  &::before {
    content: '';
    display: inline-block;
    width: 3px;
    height: 1em;
    border-radius: 2px;
    background: var(--accent);
  }
}

// ── Sortable table header ───────────────────────────────────────────────────
th.sortable {
  cursor: pointer;
  user-select: none;
  white-space: nowrap;

  &::after {
    content: ' ⇅';
    font-size: 0.7em;
    opacity: 0.35;
    transition: opacity 0.15s;
  }

  &:hover::after { opacity: 0.7; }

  &.sort-asc::after  { content: ' ▲'; opacity: 0.85; color: var(--accent); }
  &.sort-desc::after { content: ' ▼'; opacity: 0.85; color: var(--accent); }

  &:hover { color: var(--accent); }
}

// ── Dashboard shell ─────────────────────────────────────────────────────────
.dashboard-container {
  padding: 2rem 2.5rem;
  max-width: 1700px;
  margin: 0 auto;

  // Loading & error states
  .loading, .error {
    text-align: center;
    padding: 4rem 2rem;
    font-size: 1rem;
    color: var(--text-secondary);

    button {
      margin-top: 1.25rem;
      padding: 0.6rem 1.75rem;
      background: var(--accent);
      color: #fff;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-weight: 600;
      transition: background 0.2s;

      &:hover { background: var(--accent-hover); }
    }
  }

  .error {
    @extend %card;
    color: var(--negative);
    border-color: rgba(240, 82, 82, 0.3);
    background: rgba(240, 82, 82, 0.06);
  }

  // ── Dashboard content ──────────────────────────────────────────────────────
  .dashboard-content {

    // ── HEADER ────────────────────────────────────────────────────────────────
    .dashboard-header {
      margin-bottom: 2.5rem;

      h1 {
        font-size: 1.65rem;
        font-weight: 800;
        letter-spacing: -0.03em;
        color: var(--text-primary);
        margin-bottom: 1.75rem;
        display: flex;
        align-items: center;
        gap: 0.75rem;

        &::after {
          content: '';
          flex: 1;
          height: 1px;
          background: var(--border);
        }
      }

      // Metric cards grid
      .metrics-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 1rem;
        margin-bottom: 1.5rem;

        .metric-card {
          @extend %card;
          padding: 1.35rem 1.5rem;
          position: relative;
          overflow: hidden;
          transition: transform 0.18s, box-shadow 0.18s;

          &::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2px;
            background: var(--border-light);
            transition: background 0.2s;
          }

          &:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 28px rgba(0,0,0,0.55);
            &::before { background: var(--accent); }
          }

          .metric-label {
            font-size: 0.72rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .exclamation-mark {
              display: inline-flex;
              align-items: center;
              justify-content: center;
              width: 1.15rem;
              height: 1.15rem;
              background: var(--negative);
              color: #fff;
              border-radius: 50%;
              font-size: 0.7rem;
              font-weight: 700;
              flex-shrink: 0;
            }
          }

          .metric-value {
            font-size: 1.65rem;
            font-weight: 800;
            letter-spacing: -0.03em;
            color: var(--text-primary);
            margin-bottom: 0.25rem;
            font-variant-numeric: tabular-nums;
          }

          .metric-percent {
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--text-secondary);
          }

          .price-unavailable-message {
            font-size: 0.75rem;
            color: var(--negative);
            margin-top: 0.6rem;
            font-style: italic;
            background: var(--negative-bg);
            padding: 0.35rem 0.6rem;
            border-radius: 5px;
          }

          // Total Holdings – blue gradient hero card
          &.total {
            background: linear-gradient(135deg, #1a3a6e 0%, #0f224d 100%);
            border-color: rgba(79, 142, 247, 0.3);

            &::before { background: var(--accent); }

            .metric-label { color: rgba(228, 234, 245, 0.6); }
            .metric-value { color: #fff; font-size: 1.9rem; }
          }

          &.positive {
            .metric-value, .metric-percent { color: var(--positive); }
            &::before { background: var(--positive); }
          }

          &.negative {
            .metric-value, .metric-percent { color: var(--negative); }
            &::before { background: var(--negative); }
          }
        }
      }

      .action-buttons {
        display: flex;
        gap: 0.75rem;

        .btn {
          padding: 0.55rem 1.35rem;
          font-size: 0.88rem;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          font-weight: 600;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;
            box-shadow: 0 0 0 0 var(--accent-glow);

            &:hover {
              background: var(--accent-hover);
              box-shadow: 0 0 0 4px var(--accent-glow);
            }
          }
        }
      }
    }

    // ── PROJECTION SECTION ─────────────────────────────────────────────────
    .projection-section {
      @extend %card;
      padding: 1.75rem;
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Parameter inputs row
      .projection-params {
        display: flex;
        flex-wrap: wrap;
        align-items: flex-end;
        gap: 1rem;
        margin-bottom: 1.75rem;
        padding: 1.25rem;
        background: var(--bg-surface);
        border: 1px solid var(--border);
        border-radius: 8px;

        .param-group {
          display: flex;
          flex-direction: column;
          gap: 0.35rem;

          label {
            font-size: 0.68rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.07em;
          }

          input[type='number'] {
            width: 130px;
            padding: 0.5rem 0.7rem;
            border: 1px solid var(--border-light);
            border-radius: 7px;
            font-size: 0.9rem;
            color: var(--text-primary);
            background: var(--bg-input);
            transition: border-color 0.18s, box-shadow 0.18s;
            font-variant-numeric: tabular-nums;

            &:focus {
              outline: none;
              border-color: var(--accent);
              box-shadow: 0 0 0 3px var(--accent-glow);
            }
          }

          &.checkbox-group {
            justify-content: flex-end;

            .checkbox-label {
              display: flex;
              align-items: center;
              gap: 0.5rem;
              font-size: 0.82rem;
              font-weight: 500;
              color: var(--text-secondary);
              text-transform: none;
              letter-spacing: normal;
              cursor: pointer;
              white-space: nowrap;

              input[type='checkbox'] {
                width: 16px;
                height: 16px;
                accent-color: var(--accent);
                cursor: pointer;
              }
            }
          }

          &.start-amount-group {
            .start-amount-input-row {
              display: flex;
              align-items: center;
              gap: 0.4rem;

              input[type='number'] {
                width: 130px;
              }

              .btn-copy-portfolio {
                flex-shrink: 0;
                display: flex;
                align-items: center;
                justify-content: center;
                width: 32px;
                height: 32px;
                padding: 0;
                background: var(--bg-elevated);
                border: 1px solid var(--border-light);
                border-radius: 7px;
                font-size: 0.9rem;
                cursor: pointer;
                transition: all 0.18s;
                color: var(--text-secondary);

                &:hover {
                  background: rgba(79, 142, 247, 0.12);
                  border-color: var(--accent);
                  color: var(--accent);
                  transform: scale(1.1);
                }

                &:active {
                  transform: scale(0.96);
                }
              }
            }

            .start-amount-hint {
              font-size: 0.65rem;
              color: var(--text-muted);
              font-style: italic;
              margin-top: 0.15rem;
              display: block;
            }
          }
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }

          &.btn-secondary {
            background: transparent;
            border: 1px solid var(--accent);
            color: var(--accent);

            &:hover:not(:disabled) { background: rgba(79, 142, 247, 0.10); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }

        .save-version-row {
          display: flex;
          align-items: center;
          gap: 0.5rem;
          align-self: flex-end;

          .version-name-input {
            height: 36px;
            padding: 0.3rem 0.75rem;
            background: var(--bg-elevated);
            border: 1px solid var(--border-light);
            border-radius: 7px;
            color: var(--text-primary);
            font-size: 0.85rem;
            min-width: 160px;
            transition: border-color 0.18s;

            &::placeholder { color: var(--text-muted); }

            &:focus {
              outline: none;
              border-color: var(--accent);
            }
          }

          .btn { align-self: unset; }
        }

        // Tax section grouping
        .tax-section {
          width: 100%;
          padding: 0.75rem 0 0.25rem 0;

          .tax-section-header {
            font-size: 0.72rem;
            font-weight: 700;
            color: var(--accent);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .sia-tooltip {
              font-size: 0.85rem;
              cursor: help;
              opacity: 0.7;
              transition: opacity 0.18s;

              &:hover {
                opacity: 1;
              }
            }
          }

          .tax-section-fields {
            display: flex;
            flex-wrap: wrap;
            align-items: flex-end;
            gap: 1rem;
          }
        }

        .tax-section-separator {
          width: 100%;
          border-top: 1px dashed var(--border);
          margin: 0.25rem 0;
        }
      }

      // Default-version banner (top of params box)
      .params-default-banner {
        width: 100%;
        padding: 0.55rem 0.9rem;
        background: rgba(248, 155, 41, 0.07);
        border: 1px solid rgba(248, 155, 41, 0.22);
        border-left: 3px solid #f89b29;
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);

        strong { color: #f89b29; font-weight: 700; }
      }

      // Tab nav
      .projection-tab-nav {
        display: flex;
        gap: 0;
        align-items: center;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }

        // Right-aligned default version badge
        .default-version-badge {
          margin-left: auto;
          padding: 0.22rem 0.75rem;
          background: rgba(248, 155, 41, 0.10);
          border: 1px solid rgba(248, 155, 41, 0.28);
          border-radius: 999px;
          font-size: 0.76rem;
          color: #f89b29;
          white-space: nowrap;
          flex-shrink: 0;

          strong { color: #f89b29; font-weight: 700; }
        }
      }

      // Params-link hint bar (Graph & Table tabs)
      .params-link-hint {
        width: 100%;
        padding: 0.5rem 0.9rem;
        margin-bottom: 1rem;
        background: rgba(79, 142, 247, 0.06);
        border: 1px solid rgba(79, 142, 247, 0.14);
        border-left: 3px solid var(--accent);
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);
        box-sizing: border-box;

        strong { color: var(--text-primary); font-weight: 600; }
        em { font-style: normal; font-weight: 600; color: var(--accent); }

        // Version-specific variant (amber)
        &.params-link-hint--versioned {
          background: rgba(248, 155, 41, 0.06);
          border-color: rgba(248, 155, 41, 0.18);
          border-left-color: #f89b29;

          strong { color: #f89b29; }
          em     { color: var(--accent); }
        }
      }

      .tab-panel { /* intentionally bare */ }

      .projection-chart-wrapper {
        height: 380px;
        position: relative;
      }

      .projection-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Data table
      .projection-table-wrapper {
        overflow-x: auto;
        border-radius: 7px;
        border: 1px solid var(--border);

        .table-controls {
          display: flex;
          align-items: center;
          padding: 0.6rem 0.9rem;
          border-bottom: 1px solid var(--border);
          background: var(--bg-elevated);

          .show-sia-checkbox {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            font-size: 0.82rem;
            font-weight: 500;
            color: var(--text-secondary);
            cursor: pointer;

            input[type='checkbox'] {
              width: 16px;
              height: 16px;
              accent-color: #2ec4b6;
              cursor: pointer;
            }
          }
        }
      }

      .projection-table {
        // ...existing projection-table styles...
        width: 100%;
        border-collapse: collapse;
        font-size: 0.77rem;

        thead {
          background: var(--bg-elevated);
          border-bottom: 1px solid var(--border);

          th {
            padding: 0.65rem 0.9rem;
            text-align: left;
            font-weight: 600;
            color: var(--text-muted);
            white-space: nowrap;
            text-transform: uppercase;
            font-size: 0.68rem;
            letter-spacing: 0.06em;
          }
        }

        tbody tr {
          border-bottom: 1px solid var(--border);
          transition: background 0.15s;

          &:last-child { border-bottom: none; }
          &:hover { background: var(--bg-elevated); }
        }

        td {
          padding: 0.55rem 0.9rem;

          &.year-col {
            font-weight: 700;
            color: var(--accent);
          }

          &.value-col {
            font-family: 'Monaco', 'Courier New', monospace;
            text-align: right;
            color: var(--text-secondary);
          }

          &.buys-col { color: var(--accent-purple); }

          &.profit-col {
            font-weight: 600;
            &.positive { color: var(--positive); }
            &.negative { color: var(--negative); }
          }

          &.eoy-col {
            font-weight: 700;
            color: var(--text-primary);
          }

          &.inflation-col { color: #f89b29; }

          &.tax-col {
            position: relative;

            &.tax-due {
              color: var(--negative);
              font-weight: 600;
            }

            .exit-tax-badge {
              display: inline-block;
              margin-left: 0.3rem;
              padding: 0.1rem 0.3rem;
              background: var(--accent-purple);
              color: #fff;
              border-radius: 3px;
              font-size: 0.62rem;
              font-weight: 700;
              vertical-align: middle;
              cursor: help;
            }
          }

          &.after-tax-col {
            font-weight: 700;
            color: var(--accent-cyan);
          }

          &.after-tax-inflation-col {
            font-weight: 700;
            color: var(--text-secondary);
          }

          &.sia-col {
            font-weight: 600;
            color: #2ec4b6;
          }
        }

        .sia-col-header {
          color: #2ec4b6 !important;
          border-left: 2px solid rgba(46, 196, 182, 0.25);
        }
      }

      // ── Versions tab ──────────────────────────────────────────────────────
      .versions-panel {
        .versions-layout {
          display: flex;
          flex-direction: column;
          gap: 1.75rem;

          .versions-table-container {
            width: 100%;
            overflow-x: auto;

            .no-versions-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 1rem 0;
              font-size: 0.88rem;
            }

            .versions-table {
              width: 100%;
              border-collapse: collapse;
              font-size: 0.78rem;

              thead {
                background: var(--bg-elevated);
                border-bottom: 1px solid var(--border);

                th {
                  padding: 0.5rem 0.75rem;
                  text-align: left;
                  font-weight: 600;
                  color: var(--text-muted);
                  white-space: nowrap;
                  text-transform: uppercase;
                  font-size: 0.66rem;
                  letter-spacing: 0.06em;
                }
              }

              tbody tr {
                border-bottom: 1px solid var(--border);
                transition: background 0.15s;

                &:last-child { border-bottom: none; }
                &:hover { background: var(--bg-elevated); cursor: pointer; }

                &.version-selected td {
                  background: rgba(79, 142, 247, 0.08);
                }

                &.version-default td {
                  background: rgba(248, 155, 41, 0.05);
                }
              }

              td {
                padding: 0.45rem 0.75rem;
                color: var(--text-secondary);
                white-space: nowrap;

                &.version-check-col {
                  text-align: center;
                  width: 36px;

                  input[type='checkbox'] {
                    accent-color: var(--accent);
                    width: 14px;
                    height: 14px;
                    cursor: pointer;
                  }
                }

                &.version-num-col {
                  color: var(--text-primary);
                  font-size: 0.82rem;
                  display: flex;
                  align-items: center;
                  gap: 0.4rem;
                  flex-wrap: wrap;

                  .default-badge {
                    display: inline-flex;
                    align-items: center;
                    font-size: 0.68rem;
                    font-weight: 600;
                    color: #f89b29;
                    background: rgba(248, 155, 41, 0.12);
                    border: 1px solid rgba(248, 155, 41, 0.3);
                    border-radius: 999px;
                    padding: 0.1rem 0.45rem;
                    white-space: nowrap;
                  }
                }

                &.version-date-col {
                  font-size: 0.76rem;
                  color: var(--text-muted);
                }

                &.version-stat-col {
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.76rem;
                  text-align: right;
                }

                &.version-bool-col {
                  text-align: center;
                  font-weight: 700;
                  font-family: inherit;
                  color: var(--positive);
                }

                &.version-delete-col {
                  text-align: center;
                  width: 72px;
                  white-space: nowrap;
                }
              }

              .btn-set-default {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.5;
                margin-right: 0.15rem;

                &:hover:not(:disabled) {
                  background: rgba(248, 155, 41, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.3;
                }
              }

              .btn-delete-version {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.6;

                &:hover:not(:disabled) {
                  background: rgba(240, 82, 82, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.35;
                }
              }

              .delete-confirm-inline {
                display: flex;
                align-items: center;
                gap: 0.2rem;

                .btn-confirm-yes {
                  background: rgba(240, 82, 82, 0.2);
                  border: 1px solid rgba(240, 82, 82, 0.5);
                  color: #f05252;
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(240, 82, 82, 0.4); }
                  &:disabled { opacity: 0.4; cursor: not-allowed; }
                }

                .btn-confirm-no {
                  background: rgba(141, 160, 191, 0.1);
                  border: 1px solid rgba(141, 160, 191, 0.3);
                  color: #8da0bf;
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(141, 160, 191, 0.25); }
                }
              }
            }
          }

          .versions-chart-container {
            width: 100%;
            min-height: 540px;
            position: relative;

            canvas {
              width: 100% !important;
              height: 540px !important;
            }

            .versions-chart-hint {
              font-size: 0.8rem;
              color: var(--text-muted);
              margin-bottom: 0.85rem;
              padding: 0.45rem 0.75rem;
              background: var(--bg-surface);
              border-radius: 6px;
              border: 1px solid var(--border);
              display: inline-block;

              strong { color: var(--accent); }
            }

            .no-selection-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 4rem 1rem;
              text-align: center;
              font-size: 0.88rem;
            }
          }
        }
      }
    }

    // ── ALLOCATION SECTION ────────────────────────────────────────────────
    .allocation-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .allocation-content {
        @extend %card;
        display: flex;
        gap: 2.5rem;
        align-items: flex-start;
        padding: 1.75rem;

        .pie-wrapper {
          flex: 0 0 280px;
          height: 280px;
          position: relative;
        }

        .allocation-legend {
          flex: 1;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
          gap: 0.75rem;
          align-content: start;

          .legend-item {
            display: flex;
            align-items: flex-start;
            gap: 0.65rem;
            padding: 0.75rem;
            border-radius: 8px;
            background: var(--bg-surface);
            border: 1px solid var(--border);
            transition: border-color 0.18s, box-shadow 0.18s;

            &:hover {
              border-color: var(--accent);
              box-shadow: 0 0 0 1px var(--accent-glow);
            }

            .legend-color {
              flex-shrink: 0;
              width: 13px;
              height: 13px;
              border-radius: 3px;
              margin-top: 4px;
            }

            .legend-details {
              display: flex;
              flex-direction: column;
              gap: 0.15rem;
              min-width: 0;

              .legend-ticker {
                font-weight: 700;
                font-size: 0.88rem;
                color: var(--accent);
              }

              .legend-name {
                font-size: 0.74rem;
                color: var(--text-muted);
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }

              .legend-metrics {
                display: flex;
                align-items: center;
                gap: 0.4rem;
                margin-top: 0.2rem;

                .legend-amount {
                  font-weight: 600;
                  font-size: 0.88rem;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                .legend-percent {
                  font-size: 0.8rem;
                  color: var(--accent-purple);
                  font-weight: 600;
                  background: rgba(124, 92, 252, 0.12);
                  border-radius: 4px;
                  padding: 1px 6px;
                }
              }
            }
          }
        }
      }
    }

    // ── HOLDINGS SECTION ──────────────────────────────────────────────────
    .holdings-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .action-buttons {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        margin-bottom: 1.25rem;

        .readonly-notice {
          font-size: 0.85rem;
          color: #f89b29;
          padding: 0.45rem 0.9rem;
          background: rgba(248, 155, 41, 0.08);
          border: 1px solid rgba(248, 155, 41, 0.2);
          border-radius: 7px;
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }
      }

      // Tab nav (same pattern)
      .holdings-tab-nav {
        display: flex;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      // Evolution chart
      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot   { background: #f05252; border: 2px solid #c0392b; }
          &.sell-dot  { background: #f08252; border: 2px solid #c96035; margin-left: 0.25rem; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      // Period filter buttons
      .evolution-period-nav {
        display: flex;
        gap: 0.5rem;
        flex-wrap: wrap;
        margin-bottom: 1rem;

        .period-btn {
          padding: 0.35rem 0.9rem;
          border-radius: 999px;
          border: 1px solid var(--border);
          background: transparent;
          color: var(--text-secondary);
          font-size: 0.82rem;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.18s;

          &:hover {
            border-color: var(--accent);
            color: var(--accent);
          }

          &.active {
            background: var(--accent);
            border-color: var(--accent);
            color: #fff;
            font-weight: 600;
          }
        }
      }

      .evolution-no-data {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Holdings table
      .table-wrapper {
        overflow-x: auto;
        border-radius: var(--radius);
        border: 1px solid var(--border);
        background: var(--bg-card);

        .holdings-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.88rem;

          thead {
            background: var(--bg-elevated);
            border-bottom: 1px solid var(--border);

            th {
              padding: 0.85rem 1rem;
              text-align: left;
              font-weight: 600;
              color: var(--text-muted);
              white-space: nowrap;
              text-transform: uppercase;
              font-size: 0.68rem;
              letter-spacing: 0.06em;
              border-right: 1px solid var(--border);

              &:last-child { border-right: none; }
            }

            .periods-header th {
              border-bottom: 1px solid var(--border);
              padding: 0.45rem 1rem;
              font-size: 0.65rem;
            }
          }

          tbody {
            tr.holding-row {
              border-bottom: 1px solid var(--border);
              transition: background 0.15s;
              border-left: 3px solid transparent;

              &:hover { background: var(--bg-elevated); }

              &.price-unavailable {
                border-left-color: var(--negative);
                background: var(--negative-bg);
              }

              td {
                padding: 0.85rem 1rem;
                border-right: 1px solid var(--border);

                &:last-child { border-right: none; }

                &.ticker {
                  font-weight: 700;
                  color: var(--accent);
                  font-size: 0.95rem;
                }

                &.quantity, &.price {
                  text-align: right;
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.85rem;
                  color: var(--text-secondary);
                }


                &.total-value {
                  text-align: right;
                  font-weight: 700;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                &.positive {
                  color: var(--positive);
                  font-weight: 600;
                  background: var(--positive-bg);
                }

                &.negative {
                  color: var(--negative);
                  font-weight: 600;
                  background: var(--negative-bg);
                }

                .gain-loss {
                  display: flex;
                  flex-direction: column;
                  align-items: flex-end;
                  gap: 0.2rem;
                  font-variant-numeric: tabular-nums;

                  .percent {
                    font-size: 0.78rem;
                    opacity: 0.75;
                  }
                }

                &.actions {
                  text-align: center;
                  white-space: nowrap;

                  .btn-link {
                    background: none;
                    border: 1px solid var(--border-light);
                    color: var(--accent);
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;
                    margin-right: 0.25rem;

                    &:hover {
                      background: var(--accent-glow);
                      border-color: var(--accent);
                    }
                  }

                  .btn-sell-action {
                    background: rgba(240, 130, 82, 0.1);
                    border: 1px solid rgba(240, 130, 82, 0.3);
                    color: #f08252;
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;

                    &:hover {
                      background: rgba(240, 130, 82, 0.2);
                      border-color: #f08252;
                    }
                  }
                }

                &.deemed-disposal-cell {
                  text-align: center;
                  white-space: nowrap;

                  .deemed-disposal-date {
                    display: inline-flex;
                    align-items: center;
                    gap: 0.3rem;
                    font-size: 0.82rem;
                    font-weight: 600;
                    color: #f89b29;
                    cursor: help;
                    position: relative;

                    // Tooltip
                    &::after {
                      content: attr(data-tooltip);
                      position: absolute;
                      bottom: calc(100% + 8px);
                      left: 50%;
                      transform: translateX(-50%);
                      background: #172040;
                      color: #c9d6ea;
                      border: 1px solid #1f2e4a;
                      border-radius: 8px;
                      padding: 0.6rem 0.8rem;
                      font-size: 0.78rem;
                      font-weight: 400;
                      line-height: 1.4;
                      white-space: normal;
                      width: 260px;
                      text-align: center;
                      box-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
                      opacity: 0;
                      pointer-events: none;
                      transition: opacity 0.18s ease;
                      z-index: 100;
                    }

                    &::before {
                      content: '';
                      position: absolute;
                      bottom: calc(100% + 2px);
                      left: 50%;
                      transform: translateX(-50%);
                      border: 6px solid transparent;
                      border-top-color: #1f2e4a;
                      opacity: 0;
                      pointer-events: none;
                      transition: opacity 0.18s ease;
                      z-index: 101;
                    }

                    &:hover::after,
                    &:hover::before {
                      opacity: 1;
                    }
                  }

                  .deemed-disposal-na {
                    color: var(--text-muted);
                    font-size: 0.82rem;
                  }
                }
              }
            }
          }
        }

        // Holdings table header: Deemed Disposal column
        .deemed-disposal-th {
          white-space: nowrap;

          .col-info-icon {
            margin-left: 0.3rem;
            cursor: help;
            font-size: 0.8rem;
            opacity: 0.7;
          }
        }
      }
    }
  }
}

// ── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 768px) {
  .dashboard-container {
    padding: 1rem;

    .dashboard-content {
      .dashboard-header h1 { font-size: 1.3rem; }

      .allocation-section .allocation-content {
        flex-direction: column;
        align-items: center;

        .pie-wrapper {
          flex: 0 0 220px;
          height: 220px;
          width: 220px;
        }

        .allocation-legend {
          grid-template-columns: 1fr 1fr;
          width: 100%;
        }
      }

      .holdings-section .table-wrapper {
        font-size: 0.8rem;

        .holdings-table {
          thead th { padding: 0.6rem 0.5rem; }
          tbody td { padding: 0.6rem 0.5rem; }
        }
      }
    }
  }
}

// ── TAX YEAR SUMMARY ─────────────────────────────────────────────────────────
.tax-summary-section {
  background: var(--card-bg, #141e34);
  border: 1px solid rgba(255, 255, 255, 0.07);
  border-radius: 14px;
  margin-bottom: 2rem;
  overflow: hidden;

  .tax-summary-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1.2rem 1.8rem;
    cursor: pointer;
    user-select: none;
    transition: background 0.15s;

    &:hover { background: rgba(255, 255, 255, 0.025); }

    h2 {
      margin: 0;
      font-size: 1.15rem;
      color: #e4eaf5;
      display: flex;
      align-items: center;
      gap: 0.75rem;
    }

    .collapse-chevron {
      font-size: 0.85rem;
      color: #8da0bf;
      transition: transform 0.2s;
      &.open { transform: rotate(180deg); }
    }
  }

  .tax-summary-badge {
    font-size: 0.72rem;
    font-weight: 600;
    padding: 0.2rem 0.6rem;
    border-radius: 20px;
    background: rgba(79, 142, 247, 0.15);
    color: #4f8ef7;
    border: 1px solid rgba(79, 142, 247, 0.25);

    &--none {
      background: rgba(141, 160, 191, 0.1);
      color: #8da0bf;
      border-color: rgba(141, 160, 191, 0.2);
    }
  }

  .tax-summary-body {
    padding: 0 1.8rem 1.8rem;
    border-top: 1px solid rgba(255, 255, 255, 0.06);
  }

  .tax-year-controls {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 1rem 0;
    flex-wrap: wrap;

    label {
      font-size: 0.88rem;
      color: #8da0bf;
      font-weight: 600;
    }

    select {
      background: #1b2843;
      border: 1px solid rgba(255, 255, 255, 0.12);
      border-radius: 7px;
      color: #e4eaf5;
      font-size: 0.9rem;
      padding: 0.35rem 0.75rem;
      cursor: pointer;
      &:focus { outline: 2px solid #4f8ef7; }
    }

    .tax-year-hint {
      font-size: 0.78rem;
      color: #5e7494;
      font-style: italic;
    }
  }

  .tax-summary-loading {
    padding: 1.5rem 0;
    color: #8da0bf;
    font-size: 0.9rem;
  }

  .tax-no-data {
    padding: 1.5rem 0;
    color: #5e7494;
    font-size: 0.9rem;
  }

  // Summary totals cards
  .tax-totals-grid {
    display: flex;
    gap: 1rem;
    margin: 1rem 0 1.5rem;
    flex-wrap: wrap;
  }

  .tax-total-card {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.07);
    border-radius: 10px;
    padding: 1rem 1.4rem;
    min-width: 180px;

    &--note {
      border-color: rgba(248, 155, 41, 0.3);
      background: rgba(248, 155, 41, 0.05);
    }
  }

  .tax-total-label {
    font-size: 0.78rem;
    color: #8da0bf;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 0.4rem;
  }

  .tax-total-value {
    font-size: 1.25rem;
    font-weight: 700;
    color: #e4eaf5;

    &.positive { color: #34d399; }
    &.negative { color: #f05252; }
    &.tax-due  { color: #f89b29; }
  }

  .tax-missing-rates-msg {
    font-size: 0.83rem;
    color: #f89b29;
    a {
      color: #4f8ef7;
      text-decoration: underline;
      &:hover { color: #7cb5ff; }
    }
  }

  // Per-sell table
  .tax-table-wrapper {
    overflow-x: auto;
  }

  .tax-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.87rem;

    th, td {
      padding: 0.65rem 0.8rem;
      text-align: left;
      border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    }

    th {
      font-size: 0.75rem;
      text-transform: uppercase;
      letter-spacing: 0.04em;
      color: #5e7494;
      font-weight: 600;
      white-space: nowrap;
    }

    tbody tr {
      transition: background 0.12s;
      &:hover { background: rgba(255, 255, 255, 0.025); }

      &.tax-row-gain { border-left: 3px solid rgba(52, 211, 153, 0.4); }
      &.tax-row-loss { border-left: 3px solid rgba(240, 82, 82, 0.4); }
    }

    tfoot .tax-total-row {
      background: rgba(255, 255, 255, 0.03);
      td { border-top: 2px solid rgba(255, 255, 255, 0.1); color: #e4eaf5; }
    }

    td.price { white-space: nowrap; }
    td.quantity { white-space: nowrap; font-family: monospace; font-size: 0.85rem; }

    .positive { color: #34d399; }
    .negative { color: #f05252; }
    .tax-due  { color: #f89b29; }
    .muted    { color: #5e7494; }
  }

  .tax-asset-col {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
  }

  .tax-etf-name {
    font-size: 0.75rem;
    color: #8da0bf;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 180px;
  }

  .tax-type-chip {
    font-size: 0.65rem;
    padding: 0.1rem 0.4rem;
    border-radius: 4px;
    background: rgba(79, 142, 247, 0.12);
    color: #4f8ef7;
    border: 1px solid rgba(79, 142, 247, 0.2);
    width: fit-content;
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }

  .tax-pct-badge {
    font-size: 0.78rem;
    padding: 0.15rem 0.45rem;
    background: rgba(248, 155, 41, 0.12);
    color: #f89b29;
    border-radius: 5px;
    border: 1px solid rgba(248, 155, 41, 0.25);
    white-space: nowrap;
  }

  @media (max-width: 768px) {
    .tax-summary-header { padding: 1rem 1.2rem; }
    .tax-summary-body { padding: 0 1.2rem 1.2rem; }
    .tax-totals-grid { flex-direction: column; }
    .tax-total-card { min-width: unset; }
    .tax-table { font-size: 0.8rem; th, td { padding: 0.5rem 0.5rem; } }
  }
}

import { Component, OnInit, OnDestroy, AfterViewChecked, ChangeDetectionStrategy, ChangeDetectorRef, ElementRef, ViewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterModule } from '@angular/router';
import { ApiService, DashboardDto, HoldingDto, ProjectionResultDto, ProjectionSettingsDto, PortfolioEvolutionDto, ProjectionVersionSummaryDto, ProjectionVersionDetailDto, ProjectionDataPointDto, SaveVersionRequestDto } from '../../services/api.service';
import { AuthService, CurrentUser } from '../../services/auth.service';
import { AddTransactionModalComponent } from '../../components/add-transaction-modal/add-transaction-modal.component';
import { BuyHistoryModalComponent } from '../../components/buy-history-modal/buy-history-modal.component';
import { ShareProfileModalComponent } from '../../components/share-profile-modal/share-profile-modal.component';
import { SharingContextService } from '../../services/sharing-context.service';
import { HttpErrorResponse } from '@angular/common/http';
import {
  Chart, ArcElement, Tooltip, Legend, PieController,
  LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler,
  type ChartData
} from 'chart.js';

Chart.register(ArcElement, Tooltip, Legend, PieController, LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler);

const PIE_COLORS = [
  '#4f8ef7', '#7c5cfc', '#06d6d0', '#14d990', '#f89b29',
  '#f05252', '#fa709a', '#a78bfa', '#34d399', '#fbbf24',
  '#60a5fa', '#c084fc', '#2dd4bf', '#86efac', '#fcd34d',
];

// Shared dark-theme Chart.js defaults
const DARK_SCALE_DEFAULTS = {
  grid:  { color: 'rgba(31, 46, 74, 0.8)' },
  ticks: { color: '#8da0bf' },
  title: { color: '#8da0bf' },
  border: { color: 'rgba(31,46,74,0.5)' },
};

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterModule, AddTransactionModalComponent, BuyHistoryModalComponent, ShareProfileModalComponent],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class DashboardComponent implements OnInit, OnDestroy, AfterViewChecked {
  dashboard: DashboardDto | null = null;
  loading = true;
  error: string | null = null;

  showAddTransactionModal = false;
  showBuyHistoryModal = false;
  selectedHoldingId: number | null = null;
  showShareModal = false;

  // Add-transaction modal context
  addTransactionInitialType: 'Buy' | 'Sell' = 'Buy';
  addTransactionTicker: string | null = null;
  addTransactionAvailableQty: number | null = null;

  @ViewChild('allocationChart') allocationChartRef!: ElementRef<HTMLCanvasElement>;
  private pieChart: Chart | null = null;
  private chartRendered = false;

  // Projection
  projection: ProjectionResultDto | null = null;
  projectionSettings: ProjectionSettingsDto = {
    yearlyReturnPercent: 7,
    monthlyBuyAmount: 500,
    annualBuyIncreasePercent: 3,
    projectionYears: 10,
    inflationPercent: 2,
    cgtPercent: 38,
    exitTaxPercent: 38,
    excludePreExistingFromTax: false,
    siaAnnualPercent: 0,
    startAmount: null,
  };
  projectionLoading = false;
  projectionSaving = false;
  showSiaNumbers = false;
  activeProjectionTab: 'chart' | 'table' | 'versions' = 'chart';
  currentYear = new Date().getFullYear();

  @ViewChild('projectionChart') projectionChartRef!: ElementRef<HTMLCanvasElement>;
  private lineChart: Chart | null = null;
  private projectionChartRendered = false;

  // Projection versions
  projectionVersions: ProjectionVersionSummaryDto[] = [];
  versionsLoading = false;
  versionSaving = false;
  newVersionName = '';
  versionDeleting: Set<number> = new Set();
  versionSettingDefault: Set<number> = new Set();
  confirmDeleteId: number | null = null;
  selectedVersionIds: Set<number> = new Set();
  versionCompareData: Map<number, ProjectionDataPointDto[]> = new Map();
  versionsCompareChartRendered = false;
  /** Name of the default version currently driving the params/graph/table (null = saved settings). */
  defaultVersionName: string | null = null;

  // Versions table sort
  versionsSortCol = 'savedAt';
  versionsSortDir: 'asc' | 'desc' = 'desc';

  get sortedVersions(): ProjectionVersionSummaryDto[] {
    const list = [...this.projectionVersions];
    const dir = this.versionsSortDir === 'asc' ? 1 : -1;
    return list.sort((a, b) => {
      let av: any, bv: any;
      switch (this.versionsSortCol) {
        case 'name':        av = a.versionName?.toLowerCase();              bv = b.versionName?.toLowerCase(); break;
        case 'savedAt':     av = a.savedAt;                                 bv = b.savedAt; break;
        case 'startAmount': av = a.settings.startAmount ?? 0;               bv = b.settings.startAmount ?? 0; break;
        case 'return':      av = a.settings.yearlyReturnPercent;             bv = b.settings.yearlyReturnPercent; break;
        case 'monthly':     av = a.settings.monthlyBuyAmount;               bv = b.settings.monthlyBuyAmount; break;
        case 'buyInc':      av = a.settings.annualBuyIncreasePercent;        bv = b.settings.annualBuyIncreasePercent; break;
        case 'years':       av = a.settings.projectionYears;                bv = b.settings.projectionYears; break;
        case 'inflation':   av = a.settings.inflationPercent;               bv = b.settings.inflationPercent; break;
        case 'cgt':         av = a.settings.cgtPercent;                     bv = b.settings.cgtPercent; break;
        case 'exitTax':     av = a.settings.exitTaxPercent;                 bv = b.settings.exitTaxPercent; break;
        case 'sia':         av = a.settings.siaAnnualPercent;               bv = b.settings.siaAnnualPercent; break;
        default: return 0;
      }
      if (av < bv) return -dir;
      if (av > bv) return dir;
      return 0;
    });
  }

  sortVersionsBy(col: string): void {
    if (this.versionsSortCol === col) {
      this.versionsSortDir = this.versionsSortDir === 'asc' ? 'desc' : 'asc';
    } else {
      this.versionsSortCol = col;
      this.versionsSortDir = 'asc';
    }
    this.cdr.markForCheck();
  }

  @ViewChild('versionsCompareChart') versionsCompareChartRef!: ElementRef<HTMLCanvasElement>;
  private versionsCompareChart: Chart | null = null;

  // Holdings tabs
  activeHoldingsTab: 'table' | 'evolution' = 'table';
  portfolioEvolution: PortfolioEvolutionDto | null = null;
  evolutionLoading = false;
  evolutionPeriod: 'all' | 'year' | 'month' | 'week' = 'all';

  // Holdings table sort
  holdingsSortCol = '';
  holdingsSortDir: 'asc' | 'desc' = 'asc';

  get sortedHoldings(): HoldingDto[] {
    if (!this.dashboard?.holdings) return [];
    if (!this.holdingsSortCol) return this.dashboard.holdings;
    const list = [...this.dashboard.holdings];
    const dir = this.holdingsSortDir === 'asc' ? 1 : -1;
    return list.sort((a, b) => {
      let av: any, bv: any;
      switch (this.holdingsSortCol) {
        case 'ticker':       av = a.ticker?.toLowerCase();                   bv = b.ticker?.toLowerCase(); break;
        case 'etfName':      av = a.etfName?.toLowerCase();                  bv = b.etfName?.toLowerCase(); break;
        case 'quantity':     av = a.quantity;                                bv = b.quantity; break;
        case 'avgCost':      av = a.averageCost;                             bv = b.averageCost; break;
        case 'currentPrice': av = a.currentPrice;                            bv = b.currentPrice; break;
        case 'totalValue':   av = a.totalValue;                              bv = b.totalValue; break;
        case 'daily':        av = a.dailyMetrics.gainLossEur;                bv = b.dailyMetrics.gainLossEur; break;
        case 'weekly':       av = a.weeklyMetrics.gainLossEur;               bv = b.weeklyMetrics.gainLossEur; break;
        case 'monthly':      av = a.monthlyMetrics.gainLossEur;              bv = b.monthlyMetrics.gainLossEur; break;
        case 'ytd':          av = a.ytdMetrics.gainLossEur;                  bv = b.ytdMetrics.gainLossEur; break;
        default: return 0;
      }
      if (av < bv) return -dir;
      if (av > bv) return dir;
      return 0;
    });
  }

  sortHoldingsBy(col: string): void {
    if (this.holdingsSortCol === col) {
      this.holdingsSortDir = this.holdingsSortDir === 'asc' ? 'desc' : 'asc';
    } else {
      this.holdingsSortCol = col;
      this.holdingsSortDir = 'asc';
    }
    this.cdr.markForCheck();
  }

  @ViewChild('evolutionChart') evolutionChartRef!: ElementRef<HTMLCanvasElement>;
  private evolutionChart: Chart | null = null;
  private evolutionChartRendered = false;

  get filteredEvolutionPoints() {
    const points = this.portfolioEvolution?.dataPoints;
    if (!points?.length) return [];
    if (this.evolutionPeriod === 'all') return points;

    const now = new Date();
    let cutoff: Date;

    if (this.evolutionPeriod === 'year') {
      cutoff = new Date(now.getFullYear(), 0, 1);
    } else if (this.evolutionPeriod === 'month') {
      cutoff = new Date(now.getFullYear(), now.getMonth(), 1);
    } else {
      // week: last 7 days (Mon–Sun of current week)
      const day = now.getDay(); // 0=Sun
      const diff = (day === 0 ? -6 : 1 - day);
      cutoff = new Date(now.getFullYear(), now.getMonth(), now.getDate() + diff);
    }

    const cutoffStr = cutoff.toISOString().slice(0, 10);
    return points.filter(p => p.date >= cutoffStr);
  }

  get allocationSlices(): { ticker: string; etfName: string; value: number; percent: number; color: string }[] {
    if (!this.dashboard?.holdings?.length) return [];
    const total = this.dashboard.holdings.reduce((sum, h) => sum + h.totalValue, 0);
    return this.dashboard.holdings.map((h, i) => ({
      ticker: h.ticker,
      etfName: h.etfName,
      value: h.totalValue,
      percent: total > 0 ? (h.totalValue / total) * 100 : 0,
      color: PIE_COLORS[i % PIE_COLORS.length],
    }));
  }

  constructor(private apiService: ApiService, private cdr: ChangeDetectorRef, public auth: AuthService, public sharingCtx: SharingContextService) {}

  ngOnInit(): void {
    console.log('Dashboard component initialized');
    this.loadDashboard();
    this.initProjection();
    this.loadPortfolioEvolution();
  }

  onShareModalClosed(): void {
    this.showShareModal = false;
    this.cdr.markForCheck();
  }

  onStartedViewingAs(): void {
    // Immediately clear stale data so the user sees loading state right away
    this.dashboard = null;
    this.projection = null;
    this.portfolioEvolution = null;
    this.defaultVersionName = null;
    this.loading = true;
    this.projectionLoading = true;
    this.projectionVersions = [];
    this.chartRendered = false;
    this.projectionChartRendered = false;
    this.evolutionChartRendered = false;
    this.pieChart?.destroy(); this.pieChart = null;
    this.lineChart?.destroy(); this.lineChart = null;
    this.evolutionChart?.destroy(); this.evolutionChart = null;
    this.cdr.detectChanges();
    this.loadDashboard();
    this.initProjection();
    this.loadPortfolioEvolution();
  }

  stopViewingAs(): void {
    this.sharingCtx.stopViewing();
    // Immediately clear stale data so the user sees loading state right away
    this.dashboard = null;
    this.projection = null;
    this.portfolioEvolution = null;
    this.defaultVersionName = null;
    this.loading = true;
    this.projectionLoading = true;
    this.projectionVersions = [];
    this.chartRendered = false;
    this.projectionChartRendered = false;
    this.evolutionChartRendered = false;
    this.pieChart?.destroy(); this.pieChart = null;
    this.lineChart?.destroy(); this.lineChart = null;
    this.evolutionChart?.destroy(); this.evolutionChart = null;
    this.cdr.detectChanges();
    this.loadDashboard();
    this.initProjection();
    this.loadPortfolioEvolution();
  }

  ngAfterViewChecked(): void {
    if (this.dashboard && !this.loading && !this.chartRendered && this.allocationChartRef?.nativeElement) {
      this.chartRendered = true;
      this.renderPieChart();
    }
    if (this.projection && !this.projectionLoading && !this.projectionChartRendered && this.projectionChartRef?.nativeElement) {
      this.projectionChartRendered = true;
      this.renderLineChart();
    }
    if (this.portfolioEvolution && !this.evolutionLoading && !this.evolutionChartRendered && this.evolutionChartRef?.nativeElement) {
      this.evolutionChartRendered = true;
      this.renderEvolutionChart();
    }
    if (
      this.activeProjectionTab === 'versions' &&
      !this.versionsCompareChartRendered &&
      this.selectedVersionIds.size > 0 &&
      this.versionsCompareChartRef?.nativeElement
    ) {
      this.versionsCompareChartRendered = true;
      this.renderVersionsCompareChart();
    }
  }

  ngOnDestroy(): void {
    this.pieChart?.destroy();
    this.lineChart?.destroy();
    this.evolutionChart?.destroy();
    this.versionsCompareChart?.destroy();
  }

  private renderPieChart(): void {
    this.pieChart?.destroy();
    const slices = this.allocationSlices;
    if (!slices.length) return;

    const ctx = this.allocationChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    this.pieChart = new Chart(ctx, {
      type: 'pie',
      data: {
        labels: slices.map(s => s.ticker),
        datasets: [{
          data: slices.map(s => s.value),
          backgroundColor: slices.map(s => s.color),
          borderWidth: 2,
          borderColor: '#111d35',
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (ctx) => {
                const slice = slices[ctx.dataIndex];
                return ` ${slice.ticker}: ${this.formatCurrency(slice.value)} (${slice.percent.toFixed(1)}%)`;
              }
            }
          }
        }
      }
    });
  }

  private renderLineChart(): void {
    this.lineChart?.destroy();
    const points = this.projection?.dataPoints;
    if (!points?.length) return;

    const ctx = this.projectionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    const datasets: any[] = [
      {
        label: 'Projected Portfolio Value',
        data: points.map(p => p.totalAmount),
        borderColor: '#4f8ef7',
        backgroundColor: 'rgba(79, 142, 247, 0.10)',
        fill: true,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#4f8ef7',
      },
      {
        label: 'Amount corrected by inflation',
        data: points.map(p => p.inflationCorrectedAmount),
        borderColor: '#f05252',
        backgroundColor: 'rgba(240, 82, 82, 0.07)',
        fill: true,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#f05252',
        borderDash: [6, 3],
      },
      {
        label: 'Projected after taxes',
        data: points.map(p => p.afterTaxTotalAmount),
        borderColor: '#4d6080',
        backgroundColor: 'rgba(77, 96, 128, 0.06)',
        fill: false,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#4d6080',
        borderDash: [4, 4],
      },
      {
        label: 'After Tax Balance Inflation-Corrected',
        data: points.map(p => p.afterTaxInflationCorrectedAmount),
        borderColor: '#f89b29',
        backgroundColor: 'rgba(248, 155, 41, 0.07)',
        fill: false,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#f89b29',
        borderDash: [8, 3],
      }
    ];

    // Add SIA datasets only when SIA % is configured
    if (this.projectionSettings.siaAnnualPercent > 0) {
      datasets.push(
        {
          label: 'Projected after tax (SIA)',
          data: points.map(p => p.afterTaxSia ?? 0),
          borderColor: '#2ec4b6',
          backgroundColor: 'rgba(46, 196, 182, 0.07)',
          fill: false,
          tension: 0.35,
          pointRadius: 5,
          pointHoverRadius: 7,
          pointBackgroundColor: '#2ec4b6',
          borderDash: [6, 4],
        },
        {
          label: 'After tax inflation-corrected (SIA)',
          data: points.map(p => p.afterTaxInflationCorrectedSia ?? 0),
          borderColor: '#9b5de5',
          backgroundColor: 'rgba(155, 93, 229, 0.07)',
          fill: false,
          tension: 0.35,
          pointRadius: 5,
          pointHoverRadius: 7,
          pointBackgroundColor: '#9b5de5',
          borderDash: [10, 4],
        }
      );
    }

    this.lineChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.year.toString()),
        datasets,
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Year', font: { weight: 'bold' }, color: '#8da0bf' }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: {
            display: true,
            position: 'top',
            labels: { usePointStyle: true, padding: 20, color: '#8da0bf' }
          },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (tooltipCtx) => ` ${tooltipCtx.dataset.label}: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  /** Called on init / view-switch. Loads versions first; if a default is set, calculates projection from it. */
  private initProjection(): void {
    this.projectionLoading = true;
    this.projectionChartRendered = false;
    this.lineChart?.destroy();
    this.lineChart = null;
    this.cdr.markForCheck();

    this.apiService.getProjectionVersions().subscribe({
      next: (versions) => {
        this.projectionVersions = versions;
        const defaultVersion = versions.find(v => v.isDefault) ?? null;

        if (defaultVersion) {
          this.defaultVersionName = defaultVersion.versionName;
          this.projectionSettings = { ...defaultVersion.settings };
          // Calculate a fresh projection using the default version's settings (no DB write)
          this.apiService.calculateProjection(defaultVersion.settings).subscribe({
            next: (result) => {
              this.projection = result;
              this.projectionLoading = false;
              this.cdr.markForCheck();
            },
            error: () => {
              // Fallback: load from saved settings
              this.defaultVersionName = null;
              this.loadProjection();
            }
          });
        } else {
          this.defaultVersionName = null;
          this.loadProjection();
        }
      },
      error: () => {
        // If versions fail to load, fall back to normal projection load
        this.loadProjection();
      }
    });
  }

  loadProjection(): void {
    this.projectionLoading = true;
    this.projectionChartRendered = false;
    this.lineChart?.destroy();
    this.lineChart = null;
    this.apiService.getProjection().subscribe({
      next: (data) => {
        this.projection = data;
        this.projectionSettings = { ...data.settings };
        this.projectionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err: HttpErrorResponse) => {
        console.error('Error loading projection:', err);
        if (err.status === 403 && this.sharingCtx.isViewingAsOther()) {
          this.sharingCtx.stopViewing();
        }
        this.projectionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  saveProjectionSettings(): void {
    this.projectionSaving = true;
    this.apiService.saveProjectionSettings(this.projectionSettings).subscribe({
      next: () => {
        this.projectionSaving = false;
        // User has manually applied custom settings — clear the default version badge
        this.defaultVersionName = null;
        this.projectionChartRendered = false;
        this.lineChart?.destroy();
        this.lineChart = null;
        this.loadProjection();
      },
      error: (err) => {
        console.error('Error saving projection settings:', err);
        this.projectionSaving = false;
        this.cdr.markForCheck();
      }
    });
  }

  setProjectionTab(tab: 'chart' | 'table' | 'versions'): void {
    this.activeProjectionTab = tab;
    if (tab === 'chart') {
      this.projectionChartRendered = false;
      this.lineChart?.destroy();
      this.lineChart = null;
    }
    // Versions are already eagerly loaded in initProjection(); only reload if empty (e.g. after error)
    if (tab === 'versions' && this.projectionVersions.length === 0 && !this.versionsLoading) {
      this.loadProjectionVersions();
    }
    this.cdr.markForCheck();
  }

  saveNewVersion(): void {
    if (!this.newVersionName.trim()) return;
    this.versionSaving = true;
    const request: SaveVersionRequestDto = {
      versionName: this.newVersionName.trim(),
      settings: this.projectionSettings,
    };
    this.apiService.saveProjectionVersion(request).subscribe({
      next: (v) => {
        this.versionSaving = false;
        this.newVersionName = '';
        this.projectionVersions = [...this.projectionVersions, v];
        // Cache the frozen data points so comparison works immediately without an extra fetch
        if (v.dataPoints?.length) {
          this.versionCompareData.set(v.id, v.dataPoints);
        }
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error saving projection version:', err);
        this.versionSaving = false;
        this.cdr.markForCheck();
      }
    });
  }

  loadProjectionVersions(): void {
    this.versionsLoading = true;
    this.apiService.getProjectionVersions().subscribe({
      next: (data) => {
        this.projectionVersions = data;
        this.versionsLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading projection versions:', err);
        this.versionsLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  deleteVersion(versionId: number): void {
    if (this.confirmDeleteId !== versionId) {
      this.confirmDeleteId = versionId;
      this.cdr.markForCheck();
      return;
    }
    this.confirmDeleteId = null;
    this.versionDeleting = new Set(this.versionDeleting).add(versionId);
    this.cdr.markForCheck();
    this.apiService.deleteProjectionVersion(versionId).subscribe({
      next: () => {
        this.projectionVersions = this.projectionVersions.filter(v => v.id !== versionId);
        const nextDeleting = new Set(this.versionDeleting);
        nextDeleting.delete(versionId);
        this.versionDeleting = nextDeleting;
        if (this.selectedVersionIds.has(versionId)) {
          const nextSelected = new Set(this.selectedVersionIds);
          nextSelected.delete(versionId);
          this.selectedVersionIds = nextSelected;
          this.versionCompareData.delete(versionId);
          this.rebuildVersionsCompareChart();
        }
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error deleting projection version:', err);
        const nextDeleting = new Set(this.versionDeleting);
        nextDeleting.delete(versionId);
        this.versionDeleting = nextDeleting;
        this.cdr.markForCheck();
      }
    });
  }

  cancelDelete(): void {
    this.confirmDeleteId = null;
    this.cdr.markForCheck();
  }

  setDefaultVersion(versionId: number): void {
    this.versionSettingDefault = new Set(this.versionSettingDefault).add(versionId);
    this.cdr.markForCheck();
    this.apiService.setDefaultProjectionVersion(versionId).subscribe({
      next: () => {
        // Update local list: unset all defaults, then set the target
        this.projectionVersions = this.projectionVersions.map(v => ({
          ...v,
          isDefault: v.id === versionId,
        }));
        const next = new Set(this.versionSettingDefault);
        next.delete(versionId);
        this.versionSettingDefault = next;
        // Apply the newly-set default version to params + graph
        const newDefault = this.projectionVersions.find(v => v.id === versionId);
        if (newDefault) {
          this.defaultVersionName = newDefault.versionName;
          this.projectionSettings = { ...newDefault.settings };
          this.projectionChartRendered = false;
          this.lineChart?.destroy();
          this.lineChart = null;
          this.apiService.calculateProjection(newDefault.settings).subscribe({
            next: (result) => { this.projection = result; this.cdr.markForCheck(); },
            error: () => this.cdr.markForCheck()
          });
        }
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error setting default version:', err);
        const next = new Set(this.versionSettingDefault);
        next.delete(versionId);
        this.versionSettingDefault = next;
        this.cdr.markForCheck();
      }
    });
  }

  toggleVersionSelection(versionId: number): void {
    const next = new Set(this.selectedVersionIds);
    if (next.has(versionId)) {
      next.delete(versionId);
      this.selectedVersionIds = next;
      this.rebuildVersionsCompareChart();
    } else {
      next.add(versionId);
      this.selectedVersionIds = next;
      // Use the pre-loaded (frozen) data points from the version summary — no extra API call needed.
      if (!this.versionCompareData.has(versionId)) {
        const version = this.projectionVersions.find(v => v.id === versionId);
        if (version?.dataPoints?.length) {
          this.versionCompareData.set(versionId, version.dataPoints);
          this.rebuildVersionsCompareChart();
        } else {
          // Fallback: fetch detail if data points weren't included (e.g. older saved version)
          this.apiService.getProjectionVersionDetail(versionId).subscribe({
            next: (detail) => {
              this.versionCompareData.set(versionId, detail.dataPoints);
              this.rebuildVersionsCompareChart();
            },
            error: (err) => console.error('Error loading version detail:', err)
          });
        }
      } else {
        this.rebuildVersionsCompareChart();
      }
    }
  }

  private rebuildVersionsCompareChart(): void {
    this.versionsCompareChartRendered = false;
    this.versionsCompareChart?.destroy();
    this.versionsCompareChart = null;
    this.cdr.markForCheck();
  }

  private renderVersionsCompareChart(): void {
    this.versionsCompareChart?.destroy();
    if (this.selectedVersionIds.size === 0) return;

    const ctx = this.versionsCompareChartRef?.nativeElement?.getContext('2d');
    if (!ctx) return;

    // Each metric has its own colour family; each version gets a different shade of that family
    const LINE_TYPE_CONFIG: { key: keyof ProjectionDataPointDto; label: string; dash: number[]; shades: string[] }[] = [
      { key: 'totalAmount',                       label: 'Projected Portfolio Value',             dash: [],      shades: ['#4f8ef7', '#2563d4', '#7cb5ff', '#1a47a0'] },
      { key: 'inflationCorrectedAmount',          label: 'Inflation Corrected',                   dash: [6, 3],  shades: ['#f05252', '#b91c1c', '#f87171', '#7f1d1d'] },
      { key: 'afterTaxTotalAmount',               label: 'After Taxes',                           dash: [4, 4],  shades: ['#4d6080', '#2d4565', '#6d80a0', '#1d2f45'] },
      { key: 'afterTaxInflationCorrectedAmount',  label: 'After Tax + Inflation Corrected',       dash: [8, 3],  shades: ['#f89b29', '#c27416', '#fbba60', '#7c4a0a'] },
      { key: 'afterTaxSia',                       label: 'After Tax (SIA)',                       dash: [6, 4],  shades: ['#2ec4b6', '#178077', '#5de0d4', '#0e5550'] },
      { key: 'afterTaxInflationCorrectedSia',     label: 'After Tax + Inflation Corrected (SIA)', dash: [10, 4], shades: ['#9b5de5', '#6d28d9', '#bf8af7', '#4c1d95'] },
    ];

    const selectedIds = Array.from(this.selectedVersionIds);
    const datasets: any[] = [];

    selectedIds.forEach((id, versionIndex) => {
      if (!this.versionCompareData.has(id)) return;
      const version = this.projectionVersions.find(v => v.id === id);
      const dataPoints = this.versionCompareData.get(id) ?? [];

      LINE_TYPE_CONFIG.forEach((lineType, lineIndex) => {
        // Skip SIA lines when this version has no meaningful SIA data
        if (lineType.key === 'afterTaxSia' || lineType.key === 'afterTaxInflationCorrectedSia') {
          const hasSia = dataPoints.some(p => ((p as any)[lineType.key] ?? 0) > 0);
          if (!hasSia) return;
        }

        const data = dataPoints.map(p => (p as any)[lineType.key] ?? 0);
        // Colour = metric family hue, shade = version index
        const color = lineType.shades[versionIndex % lineType.shades.length];
        datasets.push({
          label: `${version?.versionName ?? `#${id}`} — ${lineType.label}`,
          data,
          borderColor: color,
          backgroundColor: color + '18',
          fill: false,
          tension: 0.35,
          pointRadius: 4,
          pointHoverRadius: 6,
          pointBackgroundColor: color,
          borderDash: lineType.dash,
          borderWidth: lineIndex === 0 ? 2.5 : 1.5,
          hidden: lineIndex > 0, // only "Projected Portfolio Value" visible by default
        });
      });
    });

    if (datasets.length === 0) return;

    const firstId = selectedIds.find(id => this.versionCompareData.has(id))!;
    const labels = (this.versionCompareData.get(firstId) ?? []).map(p => p.year.toString());

    this.versionsCompareChart = new Chart(ctx, {
      type: 'line',
      data: { labels, datasets },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Year', font: { weight: 'bold' }, color: '#8da0bf' }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: {
            display: true,
            position: 'top',
            labels: { usePointStyle: true, padding: 14, color: '#8da0bf', font: { size: 11 } }
          },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (tooltipCtx) =>
                ` ${tooltipCtx.dataset.label}: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  setEvolutionPeriod(period: 'all' | 'year' | 'month' | 'week'): void {
    this.evolutionPeriod = period;
    this.evolutionChartRendered = false;
    this.evolutionChart?.destroy();
    this.evolutionChart = null;
    this.cdr.markForCheck();
  }

  private renderEvolutionChart(): void {
    this.evolutionChart?.destroy();
    const points = this.filteredEvolutionPoints;
    if (!points?.length) return;

    const ctx = this.evolutionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    // Build per-point arrays for dynamic point styling
    const pointRadii       = points.map(p => (p.hasBuy || p.hasSell ? 8 : 3));
    const pointColors      = points.map(p => p.hasSell ? '#f08252' : p.hasBuy ? '#f05252' : '#4f8ef7');
    const pointBorderColors = points.map(p => p.hasSell ? '#c96035' : p.hasBuy ? '#c0392b' : '#4f8ef7');
    const pointBorderWidths = points.map(p => (p.hasBuy || p.hasSell ? 2 : 1));
    const pointHoverRadii  = points.map(p => (p.hasBuy || p.hasSell ? 10 : 5));

    this.evolutionChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.date),
        datasets: [
          {
            label: 'Portfolio Value',
            data: points.map(p => p.totalValue),
            borderColor: '#4f8ef7',
            backgroundColor: 'rgba(79, 142, 247, 0.08)',
            fill: true,
            tension: 0.25,
            pointRadius: pointRadii,
            pointHoverRadius: pointHoverRadii,
            pointBackgroundColor: pointColors,
            pointBorderColor: pointBorderColors,
            pointBorderWidth: pointBorderWidths,
          }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        interaction: { mode: 'index', intersect: false },
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Date', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              maxTicksLimit: 20,
              maxRotation: 45,
            }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              title: (items) => {
                const idx = items[0].dataIndex;
                const pt = points[idx];
                const tags = [];
                if (pt.hasBuy)  tags.push(' Buy recorded');
                if (pt.hasSell) tags.push(' Sell recorded');
                return tags.length ? `${pt.date}  ${tags.join('  ')}` : pt.date;
              },
              label: (tooltipCtx) =>
                ` Portfolio: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  loadPortfolioEvolution(): void {
    this.evolutionLoading = true;
    this.evolutionChartRendered = false;
    this.evolutionChart?.destroy();
    this.evolutionChart = null;
    this.apiService.getPortfolioEvolution().subscribe({
      next: (data) => {
        this.portfolioEvolution = data;
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading portfolio evolution:', err);
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  setHoldingsTab(tab: 'table' | 'evolution'): void {
    this.activeHoldingsTab = tab;
    if (tab === 'evolution') {
      this.evolutionChartRendered = false;
      this.evolutionChart?.destroy();
      this.evolutionChart = null;
    }
    this.cdr.markForCheck();
  }

  loadDashboard(): void {
    console.log('Loading dashboard...');
    this.loading = true;
    this.error = null;
    this.chartRendered = false;
    this.pieChart?.destroy();
    this.pieChart = null;
    this.apiService.getDashboard().subscribe({
      next: (data: DashboardDto) => {
        console.log('Dashboard data received:', data);
        this.dashboard = data;
        this.loading = false;
        this.cdr.markForCheck();
      },
      error: (err: HttpErrorResponse) => {
        console.error('Error loading dashboard:', err);
        if (err.status === 403 && this.sharingCtx.isViewingAsOther()) {
          // Share was revoked or invalid – return to own portfolio
          this.sharingCtx.stopViewing();
          this.error = 'Access to this shared portfolio is no longer available.';
          this.loadDashboard();
        } else {
          this.error = 'Failed to load dashboard. Please ensure the API is running.';
        }
        this.loading = false;
        this.cdr.markForCheck();
      }
    });
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('de-IE', {
      style: 'currency',
      currency: 'EUR',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(value);
  }

  formatPercent(value: number): string {
    return value >= 0 ? `+${value.toFixed(2)}%` : `${value.toFixed(2)}%`;
  }

  formatQuantity(value: number): string {
    return value.toFixed(4);
  }

  /** Format an ISO date string (YYYY-MM-DD) to dd/MM/yyyy for display. */
  formatDate(isoDate: string | null): string {
    if (!isoDate) return '—';
    const [year, month, day] = isoDate.split('-');
    return `${day}/${month}/${year}`;
  }

  /** Tooltip text for the Deemed Disposal Due column. */
  deemedDisposalTooltip(isoDate: string | null): string {
    if (!isoDate) return '';
    const formatted = this.formatDate(isoDate);
    return `Deemed Disposal will be calculated on ${formatted}. The taxable amount depends on the profit at that date — it cannot be determined in advance.`;
  }

  getMetricsClass(gainLossEur: number): string {
    return gainLossEur >= 0 ? 'positive' : 'negative';
  }

  onAddTransactionClick(): void {
    this.addTransactionInitialType = 'Buy';
    this.addTransactionTicker = null;
    this.addTransactionAvailableQty = null;
    this.showAddTransactionModal = true;
  }

  onSellClick(holding: HoldingDto): void {
    this.addTransactionInitialType = 'Sell';
    this.addTransactionTicker = holding.ticker;
    this.addTransactionAvailableQty = holding.quantity;
    this.showAddTransactionModal = true;
  }

  onTransactionAdded(): void {
    this.showAddTransactionModal = false;
    this.loadDashboard();
  }

  onTransactionCancelled(): void {
    this.showAddTransactionModal = false;
  }

  onBuyHistoryClick(holdingId: number): void {
    this.selectedHoldingId = holdingId;
    this.showBuyHistoryModal = true;
  }

  onHistoryModalClosed(): void {
    this.showBuyHistoryModal = false;
    this.selectedHoldingId = null;
  }

  onHistoryChanged(): void {
    // A transaction was deleted — reload portfolio data so holdings & metrics stay in sync
    this.loadDashboard();
    this.loadProjection();
  }


  copyPortfolioTotal(): void {
    if (this.dashboard) {
      this.projectionSettings.startAmount = Math.round(this.dashboard.header.totalHoldingsAmount);
      this.cdr.markForCheck();
    }
  }

}

import { Component, OnInit, OnDestroy, AfterViewChecked, ChangeDetectionStrategy, ChangeDetectorRef, ElementRef, ViewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterModule } from '@angular/router';
import { ApiService, DashboardDto, HoldingDto, ProjectionResultDto, ProjectionSettingsDto, PortfolioEvolutionDto, ProjectionVersionSummaryDto, ProjectionVersionDetailDto, ProjectionDataPointDto, SaveVersionRequestDto, TaxYearSummaryDto, TaxSellEntryDto } from '../../services/api.service';
import { AuthService, CurrentUser } from '../../services/auth.service';
import { AddTransactionModalComponent } from '../../components/add-transaction-modal/add-transaction-modal.component';
import { BuyHistoryModalComponent } from '../../components/buy-history-modal/buy-history-modal.component';
import { ShareProfileModalComponent } from '../../components/share-profile-modal/share-profile-modal.component';
import { SharingContextService } from '../../services/sharing-context.service';
import { HttpErrorResponse } from '@angular/common/http';
import {
  Chart, ArcElement, Tooltip, Legend, PieController,
  LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler,
  type ChartData
} from 'chart.js';

Chart.register(ArcElement, Tooltip, Legend, PieController, LineController, LineElement, PointElement, LinearScale, CategoryScale, Filler);

const PIE_COLORS = [
  '#4f8ef7', '#7c5cfc', '#06d6d0', '#14d990', '#f89b29',
  '#f05252', '#fa709a', '#a78bfa', '#34d399', '#fbbf24',
  '#60a5fa', '#c084fc', '#2dd4bf', '#86efac', '#fcd34d',
];

// Shared dark-theme Chart.js defaults
const DARK_SCALE_DEFAULTS = {
  grid:  { color: 'rgba(31, 46, 74, 0.8)' },
  ticks: { color: '#8da0bf' },
  title: { color: '#8da0bf' },
  border: { color: 'rgba(31,46,74,0.5)' },
};

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterModule, AddTransactionModalComponent, BuyHistoryModalComponent, ShareProfileModalComponent],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class DashboardComponent implements OnInit, OnDestroy, AfterViewChecked {
  dashboard: DashboardDto | null = null;
  loading = true;
  error: string | null = null;

  showAddTransactionModal = false;
  showBuyHistoryModal = false;
  selectedHoldingId: number | null = null;
  showShareModal = false;

  // Add-transaction modal context
  addTransactionInitialType: 'Buy' | 'Sell' = 'Buy';
  addTransactionTicker: string | null = null;
  addTransactionAvailableQty: number | null = null;

  @ViewChild('allocationChart') allocationChartRef!: ElementRef<HTMLCanvasElement>;
  private pieChart: Chart | null = null;
  private chartRendered = false;

  // Projection
  projection: ProjectionResultDto | null = null;
  projectionSettings: ProjectionSettingsDto = {
    yearlyReturnPercent: 7,
    monthlyBuyAmount: 500,
    annualBuyIncreasePercent: 3,
    projectionYears: 10,
    inflationPercent: 2,
    cgtPercent: 38,
    exitTaxPercent: 38,
    excludePreExistingFromTax: false,
    siaAnnualPercent: 0,
    startAmount: null,
  };
  projectionLoading = false;
  projectionSaving = false;
  showSiaNumbers = false;
  activeProjectionTab: 'chart' | 'table' | 'versions' = 'chart';
  currentYear = new Date().getFullYear();

  @ViewChild('projectionChart') projectionChartRef!: ElementRef<HTMLCanvasElement>;
  private lineChart: Chart | null = null;
  private projectionChartRendered = false;

  // Projection versions
  projectionVersions: ProjectionVersionSummaryDto[] = [];
  versionsLoading = false;
  versionSaving = false;
  newVersionName = '';
  versionDeleting: Set<number> = new Set();
  versionSettingDefault: Set<number> = new Set();
  confirmDeleteId: number | null = null;
  selectedVersionIds: Set<number> = new Set();
  versionCompareData: Map<number, ProjectionDataPointDto[]> = new Map();
  versionsCompareChartRendered = false;
  /** Name of the default version currently driving the params/graph/table (null = saved settings). */
  defaultVersionName: string | null = null;

  // Versions table sort
  versionsSortCol = 'savedAt';
  versionsSortDir: 'asc' | 'desc' = 'desc';

  get sortedVersions(): ProjectionVersionSummaryDto[] {
    const list = [...this.projectionVersions];
    const dir = this.versionsSortDir === 'asc' ? 1 : -1;
    return list.sort((a, b) => {
      let av: any, bv: any;
      switch (this.versionsSortCol) {
        case 'name':        av = a.versionName?.toLowerCase();              bv = b.versionName?.toLowerCase(); break;
        case 'savedAt':     av = a.savedAt;                                 bv = b.savedAt; break;
        case 'startAmount': av = a.settings.startAmount ?? 0;               bv = b.settings.startAmount ?? 0; break;
        case 'return':      av = a.settings.yearlyReturnPercent;             bv = b.settings.yearlyReturnPercent; break;
        case 'monthly':     av = a.settings.monthlyBuyAmount;               bv = b.settings.monthlyBuyAmount; break;
        case 'buyInc':      av = a.settings.annualBuyIncreasePercent;        bv = b.settings.annualBuyIncreasePercent; break;
        case 'years':       av = a.settings.projectionYears;                bv = b.settings.projectionYears; break;
        case 'inflation':   av = a.settings.inflationPercent;               bv = b.settings.inflationPercent; break;
        case 'cgt':         av = a.settings.cgtPercent;                     bv = b.settings.cgtPercent; break;
        case 'exitTax':     av = a.settings.exitTaxPercent;                 bv = b.settings.exitTaxPercent; break;
        case 'sia':         av = a.settings.siaAnnualPercent;               bv = b.settings.siaAnnualPercent; break;
        default: return 0;
      }
      if (av < bv) return -dir;
      if (av > bv) return dir;
      return 0;
    });
  }

  sortVersionsBy(col: string): void {
    if (this.versionsSortCol === col) {
      this.versionsSortDir = this.versionsSortDir === 'asc' ? 'desc' : 'asc';
    } else {
      this.versionsSortCol = col;
      this.versionsSortDir = 'asc';
    }
    this.cdr.markForCheck();
  }

  @ViewChild('versionsCompareChart') versionsCompareChartRef!: ElementRef<HTMLCanvasElement>;
  private versionsCompareChart: Chart | null = null;

  // Holdings tabs
  activeHoldingsTab: 'table' | 'evolution' = 'table';
  portfolioEvolution: PortfolioEvolutionDto | null = null;
  evolutionLoading = false;
  evolutionPeriod: 'all' | 'year' | 'month' | 'week' = 'all';

  // Holdings table sort
  holdingsSortCol = '';
  holdingsSortDir: 'asc' | 'desc' = 'asc';

  get sortedHoldings(): HoldingDto[] {
    if (!this.dashboard?.holdings) return [];
    if (!this.holdingsSortCol) return this.dashboard.holdings;
    const list = [...this.dashboard.holdings];
    const dir = this.holdingsSortDir === 'asc' ? 1 : -1;
    return list.sort((a, b) => {
      let av: any, bv: any;
      switch (this.holdingsSortCol) {
        case 'ticker':       av = a.ticker?.toLowerCase();                   bv = b.ticker?.toLowerCase(); break;
        case 'etfName':      av = a.etfName?.toLowerCase();                  bv = b.etfName?.toLowerCase(); break;
        case 'quantity':     av = a.quantity;                                bv = b.quantity; break;
        case 'avgCost':      av = a.averageCost;                             bv = b.averageCost; break;
        case 'currentPrice': av = a.currentPrice;                            bv = b.currentPrice; break;
        case 'totalValue':   av = a.totalValue;                              bv = b.totalValue; break;
        case 'daily':        av = a.dailyMetrics.gainLossEur;                bv = b.dailyMetrics.gainLossEur; break;
        case 'weekly':       av = a.weeklyMetrics.gainLossEur;               bv = b.weeklyMetrics.gainLossEur; break;
        case 'monthly':      av = a.monthlyMetrics.gainLossEur;              bv = b.monthlyMetrics.gainLossEur; break;
        case 'ytd':          av = a.ytdMetrics.gainLossEur;                  bv = b.ytdMetrics.gainLossEur; break;
        default: return 0;
      }
      if (av < bv) return -dir;
      if (av > bv) return dir;
      return 0;
    });
  }

  sortHoldingsBy(col: string): void {
    if (this.holdingsSortCol === col) {
      this.holdingsSortDir = this.holdingsSortDir === 'asc' ? 'desc' : 'asc';
    } else {
      this.holdingsSortCol = col;
      this.holdingsSortDir = 'asc';
    }
    this.cdr.markForCheck();
  }

  @ViewChild('evolutionChart') evolutionChartRef!: ElementRef<HTMLCanvasElement>;
  private evolutionChart: Chart | null = null;
  private evolutionChartRendered = false;

  get filteredEvolutionPoints() {
    const points = this.portfolioEvolution?.dataPoints;
    if (!points?.length) return [];
    if (this.evolutionPeriod === 'all') return points;

    const now = new Date();
    let cutoff: Date;

    if (this.evolutionPeriod === 'year') {
      cutoff = new Date(now.getFullYear(), 0, 1);
    } else if (this.evolutionPeriod === 'month') {
      cutoff = new Date(now.getFullYear(), now.getMonth(), 1);
    } else {
      // week: last 7 days (Mon–Sun of current week)
      const day = now.getDay(); // 0=Sun
      const diff = (day === 0 ? -6 : 1 - day);
      cutoff = new Date(now.getFullYear(), now.getMonth(), now.getDate() + diff);
    }

    const cutoffStr = cutoff.toISOString().slice(0, 10);
    return points.filter(p => p.date >= cutoffStr);
  }

  get allocationSlices(): { ticker: string; etfName: string; value: number; percent: number; color: string }[] {
    if (!this.dashboard?.holdings?.length) return [];
    const total = this.dashboard.holdings.reduce((sum, h) => sum + h.totalValue, 0);
    return this.dashboard.holdings.map((h, i) => ({
      ticker: h.ticker,
      etfName: h.etfName,
      value: h.totalValue,
      percent: total > 0 ? (h.totalValue / total) * 100 : 0,
      color: PIE_COLORS[i % PIE_COLORS.length],
    }));
  }

  constructor(private apiService: ApiService, private cdr: ChangeDetectorRef, public auth: AuthService, public sharingCtx: SharingContextService) {}

  ngOnInit(): void {
    console.log('Dashboard component initialized');
    this.loadDashboard();
    this.initProjection();
    this.loadPortfolioEvolution();
    this.loadTaxYears();
  }

  onShareModalClosed(): void {
    this.showShareModal = false;
    this.cdr.markForCheck();
  }

  onStartedViewingAs(): void {
    // Immediately clear stale data so the user sees loading state right away
    this.dashboard = null;
    this.projection = null;
    this.portfolioEvolution = null;
    this.defaultVersionName = null;
    this.loading = true;
    this.projectionLoading = true;
    this.projectionVersions = [];
    this.taxYears = [];
    this.taxSummary = null;
    this.taxSummaryExpanded = false;
    this.chartRendered = false;
    this.projectionChartRendered = false;
    this.evolutionChartRendered = false;
    this.pieChart?.destroy(); this.pieChart = null;
    this.lineChart?.destroy(); this.lineChart = null;
    this.evolutionChart?.destroy(); this.evolutionChart = null;
    this.cdr.detectChanges();
    this.loadDashboard();
    this.initProjection();
    this.loadPortfolioEvolution();
    this.loadTaxYears();
  }

  stopViewingAs(): void {
    this.sharingCtx.stopViewing();
    // Immediately clear stale data so the user sees loading state right away
    this.dashboard = null;
    this.projection = null;
    this.portfolioEvolution = null;
    this.defaultVersionName = null;
    this.loading = true;
    this.projectionLoading = true;
    this.projectionVersions = [];
    this.taxYears = [];
    this.taxSummary = null;
    this.taxSummaryExpanded = false;
    this.chartRendered = false;
    this.projectionChartRendered = false;
    this.evolutionChartRendered = false;
    this.pieChart?.destroy(); this.pieChart = null;
    this.lineChart?.destroy(); this.lineChart = null;
    this.evolutionChart?.destroy(); this.evolutionChart = null;
    this.cdr.detectChanges();
    this.loadDashboard();
    this.initProjection();
    this.loadPortfolioEvolution();
    this.loadTaxYears();
  }

  ngAfterViewChecked(): void {
    if (this.dashboard && !this.loading && !this.chartRendered && this.allocationChartRef?.nativeElement) {
      this.chartRendered = true;
      this.renderPieChart();
    }
    if (this.projection && !this.projectionLoading && !this.projectionChartRendered && this.projectionChartRef?.nativeElement) {
      this.projectionChartRendered = true;
      this.renderLineChart();
    }
    if (this.portfolioEvolution && !this.evolutionLoading && !this.evolutionChartRendered && this.evolutionChartRef?.nativeElement) {
      this.evolutionChartRendered = true;
      this.renderEvolutionChart();
    }
    if (
      this.activeProjectionTab === 'versions' &&
      !this.versionsCompareChartRendered &&
      this.selectedVersionIds.size > 0 &&
      this.versionsCompareChartRef?.nativeElement
    ) {
      this.versionsCompareChartRendered = true;
      this.renderVersionsCompareChart();
    }
  }

  ngOnDestroy(): void {
    this.pieChart?.destroy();
    this.lineChart?.destroy();
    this.evolutionChart?.destroy();
    this.versionsCompareChart?.destroy();
  }

  private renderPieChart(): void {
    this.pieChart?.destroy();
    const slices = this.allocationSlices;
    if (!slices.length) return;

    const ctx = this.allocationChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    this.pieChart = new Chart(ctx, {
      type: 'pie',
      data: {
        labels: slices.map(s => s.ticker),
        datasets: [{
          data: slices.map(s => s.value),
          backgroundColor: slices.map(s => s.color),
          borderWidth: 2,
          borderColor: '#111d35',
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (ctx) => {
                const slice = slices[ctx.dataIndex];
                return ` ${slice.ticker}: ${this.formatCurrency(slice.value)} (${slice.percent.toFixed(1)}%)`;
              }
            }
          }
        }
      }
    });
  }

  private renderLineChart(): void {
    this.lineChart?.destroy();
    const points = this.projection?.dataPoints;
    if (!points?.length) return;

    const ctx = this.projectionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    const datasets: any[] = [
      {
        label: 'Projected Portfolio Value',
        data: points.map(p => p.totalAmount),
        borderColor: '#4f8ef7',
        backgroundColor: 'rgba(79, 142, 247, 0.10)',
        fill: true,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#4f8ef7',
      },
      {
        label: 'Amount corrected by inflation',
        data: points.map(p => p.inflationCorrectedAmount),
        borderColor: '#f05252',
        backgroundColor: 'rgba(240, 82, 82, 0.07)',
        fill: true,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#f05252',
        borderDash: [6, 3],
      },
      {
        label: 'Projected after taxes',
        data: points.map(p => p.afterTaxTotalAmount),
        borderColor: '#4d6080',
        backgroundColor: 'rgba(77, 96, 128, 0.06)',
        fill: false,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#4d6080',
        borderDash: [4, 4],
      },
      {
        label: 'After Tax Balance Inflation-Corrected',
        data: points.map(p => p.afterTaxInflationCorrectedAmount),
        borderColor: '#f89b29',
        backgroundColor: 'rgba(248, 155, 41, 0.07)',
        fill: false,
        tension: 0.35,
        pointRadius: 5,
        pointHoverRadius: 7,
        pointBackgroundColor: '#f89b29',
        borderDash: [8, 3],
      }
    ];

    // Add SIA datasets only when SIA % is configured
    if (this.projectionSettings.siaAnnualPercent > 0) {
      datasets.push(
        {
          label: 'Projected after tax (SIA)',
          data: points.map(p => p.afterTaxSia ?? 0),
          borderColor: '#2ec4b6',
          backgroundColor: 'rgba(46, 196, 182, 0.07)',
          fill: false,
          tension: 0.35,
          pointRadius: 5,
          pointHoverRadius: 7,
          pointBackgroundColor: '#2ec4b6',
          borderDash: [6, 4],
        },
        {
          label: 'After tax inflation-corrected (SIA)',
          data: points.map(p => p.afterTaxInflationCorrectedSia ?? 0),
          borderColor: '#9b5de5',
          backgroundColor: 'rgba(155, 93, 229, 0.07)',
          fill: false,
          tension: 0.35,
          pointRadius: 5,
          pointHoverRadius: 7,
          pointBackgroundColor: '#9b5de5',
          borderDash: [10, 4],
        }
      );
    }

    this.lineChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.year.toString()),
        datasets,
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Year', font: { weight: 'bold' }, color: '#8da0bf' }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: {
            display: true,
            position: 'top',
            labels: { usePointStyle: true, padding: 20, color: '#8da0bf' }
          },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (tooltipCtx) => ` ${tooltipCtx.dataset.label}: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  /** Called on init / view-switch. Loads versions first; if a default is set, calculates projection from it. */
  private initProjection(): void {
    this.projectionLoading = true;
    this.projectionChartRendered = false;
    this.lineChart?.destroy();
    this.lineChart = null;
    this.cdr.markForCheck();

    this.apiService.getProjectionVersions().subscribe({
      next: (versions) => {
        this.projectionVersions = versions;
        const defaultVersion = versions.find(v => v.isDefault) ?? null;

        if (defaultVersion) {
          this.defaultVersionName = defaultVersion.versionName;
          this.projectionSettings = { ...defaultVersion.settings };
          // Calculate a fresh projection using the default version's settings (no DB write)
          this.apiService.calculateProjection(defaultVersion.settings).subscribe({
            next: (result) => {
              this.projection = result;
              this.projectionLoading = false;
              this.cdr.markForCheck();
            },
            error: () => {
              // Fallback: load from saved settings
              this.defaultVersionName = null;
              this.loadProjection();
            }
          });
        } else {
          this.defaultVersionName = null;
          this.loadProjection();
        }
      },
      error: () => {
        // If versions fail to load, fall back to normal projection load
        this.loadProjection();
      }
    });
  }

  loadProjection(): void {
    this.projectionLoading = true;
    this.projectionChartRendered = false;
    this.lineChart?.destroy();
    this.lineChart = null;
    this.apiService.getProjection().subscribe({
      next: (data) => {
        this.projection = data;
        this.projectionSettings = { ...data.settings };
        this.projectionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err: HttpErrorResponse) => {
        console.error('Error loading projection:', err);
        if (err.status === 403 && this.sharingCtx.isViewingAsOther()) {
          this.sharingCtx.stopViewing();
        }
        this.projectionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  saveProjectionSettings(): void {
    this.projectionSaving = true;
    this.apiService.saveProjectionSettings(this.projectionSettings).subscribe({
      next: () => {
        this.projectionSaving = false;
        // User has manually applied custom settings — clear the default version badge
        this.defaultVersionName = null;
        this.projectionChartRendered = false;
        this.lineChart?.destroy();
        this.lineChart = null;
        this.loadProjection();
      },
      error: (err) => {
        console.error('Error saving projection settings:', err);
        this.projectionSaving = false;
        this.cdr.markForCheck();
      }
    });
  }

  setProjectionTab(tab: 'chart' | 'table' | 'versions'): void {
    this.activeProjectionTab = tab;
    if (tab === 'chart') {
      this.projectionChartRendered = false;
      this.lineChart?.destroy();
      this.lineChart = null;
    }
    // Versions are already eagerly loaded in initProjection(); only reload if empty (e.g. after error)
    if (tab === 'versions' && this.projectionVersions.length === 0 && !this.versionsLoading) {
      this.loadProjectionVersions();
    }
    this.cdr.markForCheck();
  }

  saveNewVersion(): void {
    if (!this.newVersionName.trim()) return;
    this.versionSaving = true;
    const request: SaveVersionRequestDto = {
      versionName: this.newVersionName.trim(),
      settings: this.projectionSettings,
    };
    this.apiService.saveProjectionVersion(request).subscribe({
      next: (v) => {
        this.versionSaving = false;
        this.newVersionName = '';
        this.projectionVersions = [...this.projectionVersions, v];
        // Cache the frozen data points so comparison works immediately without an extra fetch
        if (v.dataPoints?.length) {
          this.versionCompareData.set(v.id, v.dataPoints);
        }
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error saving projection version:', err);
        this.versionSaving = false;
        this.cdr.markForCheck();
      }
    });
  }

  loadProjectionVersions(): void {
    this.versionsLoading = true;
    this.apiService.getProjectionVersions().subscribe({
      next: (data) => {
        this.projectionVersions = data;
        this.versionsLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading projection versions:', err);
        this.versionsLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  deleteVersion(versionId: number): void {
    if (this.confirmDeleteId !== versionId) {
      this.confirmDeleteId = versionId;
      this.cdr.markForCheck();
      return;
    }
    this.confirmDeleteId = null;
    this.versionDeleting = new Set(this.versionDeleting).add(versionId);
    this.cdr.markForCheck();
    this.apiService.deleteProjectionVersion(versionId).subscribe({
      next: () => {
        this.projectionVersions = this.projectionVersions.filter(v => v.id !== versionId);
        const nextDeleting = new Set(this.versionDeleting);
        nextDeleting.delete(versionId);
        this.versionDeleting = nextDeleting;
        if (this.selectedVersionIds.has(versionId)) {
          const nextSelected = new Set(this.selectedVersionIds);
          nextSelected.delete(versionId);
          this.selectedVersionIds = nextSelected;
          this.versionCompareData.delete(versionId);
          this.rebuildVersionsCompareChart();
        }
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error deleting projection version:', err);
        const nextDeleting = new Set(this.versionDeleting);
        nextDeleting.delete(versionId);
        this.versionDeleting = nextDeleting;
        this.cdr.markForCheck();
      }
    });
  }

  cancelDelete(): void {
    this.confirmDeleteId = null;
    this.cdr.markForCheck();
  }

  setDefaultVersion(versionId: number): void {
    this.versionSettingDefault = new Set(this.versionSettingDefault).add(versionId);
    this.cdr.markForCheck();
    this.apiService.setDefaultProjectionVersion(versionId).subscribe({
      next: () => {
        // Update local list: unset all defaults, then set the target
        this.projectionVersions = this.projectionVersions.map(v => ({
          ...v,
          isDefault: v.id === versionId,
        }));
        const next = new Set(this.versionSettingDefault);
        next.delete(versionId);
        this.versionSettingDefault = next;
        // Apply the newly-set default version to params + graph
        const newDefault = this.projectionVersions.find(v => v.id === versionId);
        if (newDefault) {
          this.defaultVersionName = newDefault.versionName;
          this.projectionSettings = { ...newDefault.settings };
          this.projectionChartRendered = false;
          this.lineChart?.destroy();
          this.lineChart = null;
          this.apiService.calculateProjection(newDefault.settings).subscribe({
            next: (result) => { this.projection = result; this.cdr.markForCheck(); },
            error: () => this.cdr.markForCheck()
          });
        }
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error setting default version:', err);
        const next = new Set(this.versionSettingDefault);
        next.delete(versionId);
        this.versionSettingDefault = next;
        this.cdr.markForCheck();
      }
    });
  }

  toggleVersionSelection(versionId: number): void {
    const next = new Set(this.selectedVersionIds);
    if (next.has(versionId)) {
      next.delete(versionId);
      this.selectedVersionIds = next;
      this.rebuildVersionsCompareChart();
    } else {
      next.add(versionId);
      this.selectedVersionIds = next;
      // Use the pre-loaded (frozen) data points from the version summary — no extra API call needed.
      if (!this.versionCompareData.has(versionId)) {
        const version = this.projectionVersions.find(v => v.id === versionId);
        if (version?.dataPoints?.length) {
          this.versionCompareData.set(versionId, version.dataPoints);
          this.rebuildVersionsCompareChart();
        } else {
          // Fallback: fetch detail if data points weren't included (e.g. older saved version)
          this.apiService.getProjectionVersionDetail(versionId).subscribe({
            next: (detail) => {
              this.versionCompareData.set(versionId, detail.dataPoints);
              this.rebuildVersionsCompareChart();
            },
            error: (err) => console.error('Error loading version detail:', err)
          });
        }
      } else {
        this.rebuildVersionsCompareChart();
      }
    }
  }

  private rebuildVersionsCompareChart(): void {
    this.versionsCompareChartRendered = false;
    this.versionsCompareChart?.destroy();
    this.versionsCompareChart = null;
    this.cdr.markForCheck();
  }

  private renderVersionsCompareChart(): void {
    this.versionsCompareChart?.destroy();
    if (this.selectedVersionIds.size === 0) return;

    const ctx = this.versionsCompareChartRef?.nativeElement?.getContext('2d');
    if (!ctx) return;

    // Each metric has its own colour family; each version gets a different shade of that family
    const LINE_TYPE_CONFIG: { key: keyof ProjectionDataPointDto; label: string; dash: number[]; shades: string[] }[] = [
      { key: 'totalAmount',                       label: 'Projected Portfolio Value',             dash: [],      shades: ['#4f8ef7', '#2563d4', '#7cb5ff', '#1a47a0'] },
      { key: 'inflationCorrectedAmount',          label: 'Inflation Corrected',                   dash: [6, 3],  shades: ['#f05252', '#b91c1c', '#f87171', '#7f1d1d'] },
      { key: 'afterTaxTotalAmount',               label: 'After Taxes',                           dash: [4, 4],  shades: ['#4d6080', '#2d4565', '#6d80a0', '#1d2f45'] },
      { key: 'afterTaxInflationCorrectedAmount',  label: 'After Tax + Inflation Corrected',       dash: [8, 3],  shades: ['#f89b29', '#c27416', '#fbba60', '#7c4a0a'] },
      { key: 'afterTaxSia',                       label: 'After Tax (SIA)',                       dash: [6, 4],  shades: ['#2ec4b6', '#178077', '#5de0d4', '#0e5550'] },
      { key: 'afterTaxInflationCorrectedSia',     label: 'After Tax + Inflation Corrected (SIA)', dash: [10, 4], shades: ['#9b5de5', '#6d28d9', '#bf8af7', '#4c1d95'] },
    ];

    const selectedIds = Array.from(this.selectedVersionIds);
    const datasets: any[] = [];

    selectedIds.forEach((id, versionIndex) => {
      if (!this.versionCompareData.has(id)) return;
      const version = this.projectionVersions.find(v => v.id === id);
      const dataPoints = this.versionCompareData.get(id) ?? [];

      LINE_TYPE_CONFIG.forEach((lineType, lineIndex) => {
        // Skip SIA lines when this version has no meaningful SIA data
        if (lineType.key === 'afterTaxSia' || lineType.key === 'afterTaxInflationCorrectedSia') {
          const hasSia = dataPoints.some(p => ((p as any)[lineType.key] ?? 0) > 0);
          if (!hasSia) return;
        }

        const data = dataPoints.map(p => (p as any)[lineType.key] ?? 0);
        // Colour = metric family hue, shade = version index
        const color = lineType.shades[versionIndex % lineType.shades.length];
        datasets.push({
          label: `${version?.versionName ?? `#${id}`} — ${lineType.label}`,
          data,
          borderColor: color,
          backgroundColor: color + '18',
          fill: false,
          tension: 0.35,
          pointRadius: 4,
          pointHoverRadius: 6,
          pointBackgroundColor: color,
          borderDash: lineType.dash,
          borderWidth: lineIndex === 0 ? 2.5 : 1.5,
          hidden: lineIndex > 0, // only "Projected Portfolio Value" visible by default
        });
      });
    });

    if (datasets.length === 0) return;

    const firstId = selectedIds.find(id => this.versionCompareData.has(id))!;
    const labels = (this.versionCompareData.get(firstId) ?? []).map(p => p.year.toString());

    this.versionsCompareChart = new Chart(ctx, {
      type: 'line',
      data: { labels, datasets },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Year', font: { weight: 'bold' }, color: '#8da0bf' }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: {
            display: true,
            position: 'top',
            labels: { usePointStyle: true, padding: 14, color: '#8da0bf', font: { size: 11 } }
          },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              label: (tooltipCtx) =>
                ` ${tooltipCtx.dataset.label}: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  setEvolutionPeriod(period: 'all' | 'year' | 'month' | 'week'): void {
    this.evolutionPeriod = period;
    this.evolutionChartRendered = false;
    this.evolutionChart?.destroy();
    this.evolutionChart = null;
    this.cdr.markForCheck();
  }

  private renderEvolutionChart(): void {
    this.evolutionChart?.destroy();
    const points = this.filteredEvolutionPoints;
    if (!points?.length) return;

    const ctx = this.evolutionChartRef.nativeElement.getContext('2d');
    if (!ctx) return;

    // Build per-point arrays for dynamic point styling
    const pointRadii       = points.map(p => (p.hasBuy || p.hasSell ? 8 : 3));
    const pointColors      = points.map(p => p.hasSell ? '#f08252' : p.hasBuy ? '#f05252' : '#4f8ef7');
    const pointBorderColors = points.map(p => p.hasSell ? '#c96035' : p.hasBuy ? '#c0392b' : '#4f8ef7');
    const pointBorderWidths = points.map(p => (p.hasBuy || p.hasSell ? 2 : 1));
    const pointHoverRadii  = points.map(p => (p.hasBuy || p.hasSell ? 10 : 5));

    this.evolutionChart = new Chart(ctx, {
      type: 'line',
      data: {
        labels: points.map(p => p.date),
        datasets: [
          {
            label: 'Portfolio Value',
            data: points.map(p => p.totalValue),
            borderColor: '#4f8ef7',
            backgroundColor: 'rgba(79, 142, 247, 0.08)',
            fill: true,
            tension: 0.25,
            pointRadius: pointRadii,
            pointHoverRadius: pointHoverRadii,
            pointBackgroundColor: pointColors,
            pointBorderColor: pointBorderColors,
            pointBorderWidth: pointBorderWidths,
          }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        interaction: { mode: 'index', intersect: false },
        scales: {
          x: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Date', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              maxTicksLimit: 20,
              maxRotation: 45,
            }
          },
          y: {
            ...DARK_SCALE_DEFAULTS,
            title: { display: true, text: 'Total Value (€)', font: { weight: 'bold' }, color: '#8da0bf' },
            ticks: {
              color: '#8da0bf',
              callback: (value) => `€${Number(value).toLocaleString('de-IE', { maximumFractionDigits: 0 })}`
            }
          }
        },
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#172040',
            borderColor: '#1f2e4a',
            borderWidth: 1,
            titleColor: '#e4eaf5',
            bodyColor: '#8da0bf',
            callbacks: {
              title: (items) => {
                const idx = items[0].dataIndex;
                const pt = points[idx];
                const tags = [];
                if (pt.hasBuy)  tags.push(' Buy recorded');
                if (pt.hasSell) tags.push(' Sell recorded');
                return tags.length ? `${pt.date}  ${tags.join('  ')}` : pt.date;
              },
              label: (tooltipCtx) =>
                ` Portfolio: ${this.formatCurrency(tooltipCtx.parsed.y as number)}`
            }
          }
        }
      }
    });
  }

  loadPortfolioEvolution(): void {
    this.evolutionLoading = true;
    this.evolutionChartRendered = false;
    this.evolutionChart?.destroy();
    this.evolutionChart = null;
    this.apiService.getPortfolioEvolution().subscribe({
      next: (data) => {
        this.portfolioEvolution = data;
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      },
      error: (err) => {
        console.error('Error loading portfolio evolution:', err);
        this.evolutionLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  setHoldingsTab(tab: 'table' | 'evolution'): void {
    this.activeHoldingsTab = tab;
    if (tab === 'evolution') {
      this.evolutionChartRendered = false;
      this.evolutionChart?.destroy();
      this.evolutionChart = null;
    }
    this.cdr.markForCheck();
  }

  loadDashboard(): void {
    console.log('Loading dashboard...');
    this.loading = true;
    this.error = null;
    this.chartRendered = false;
    this.pieChart?.destroy();
    this.pieChart = null;
    this.apiService.getDashboard().subscribe({
      next: (data: DashboardDto) => {
        console.log('Dashboard data received:', data);
        this.dashboard = data;
        this.loading = false;
        this.cdr.markForCheck();
      },
      error: (err: HttpErrorResponse) => {
        console.error('Error loading dashboard:', err);
        if (err.status === 403 && this.sharingCtx.isViewingAsOther()) {
          // Share was revoked or invalid – return to own portfolio
          this.sharingCtx.stopViewing();
          this.error = 'Access to this shared portfolio is no longer available.';
          this.loadDashboard();
        } else {
          this.error = 'Failed to load dashboard. Please ensure the API is running.';
        }
        this.loading = false;
        this.cdr.markForCheck();
      }
    });
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('de-IE', {
      style: 'currency',
      currency: 'EUR',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(value);
  }

  formatPercent(value: number): string {
    return value >= 0 ? `+${value.toFixed(2)}%` : `${value.toFixed(2)}%`;
  }

  formatQuantity(value: number): string {
    return value.toFixed(4);
  }

  /** Format an ISO date string (YYYY-MM-DD) to dd/MM/yyyy for display. */
  formatDate(isoDate: string | null): string {
    if (!isoDate) return '—';
    const [year, month, day] = isoDate.split('-');
    return `${day}/${month}/${year}`;
  }

  /** Tooltip text for the Deemed Disposal Due column. */
  deemedDisposalTooltip(isoDate: string | null): string {
    if (!isoDate) return '';
    const formatted = this.formatDate(isoDate);
    return `Deemed Disposal will be calculated on ${formatted}. The taxable amount depends on the profit at that date — it cannot be determined in advance.`;
  }

  getMetricsClass(gainLossEur: number): string {
    return gainLossEur >= 0 ? 'positive' : 'negative';
  }

  onAddTransactionClick(): void {
    this.addTransactionInitialType = 'Buy';
    this.addTransactionTicker = null;
    this.addTransactionAvailableQty = null;
    this.showAddTransactionModal = true;
  }

  onSellClick(holding: HoldingDto): void {
    this.addTransactionInitialType = 'Sell';
    this.addTransactionTicker = holding.ticker;
    this.addTransactionAvailableQty = holding.quantity;
    this.showAddTransactionModal = true;
  }

  onTransactionAdded(): void {
    this.showAddTransactionModal = false;
    this.loadDashboard();
    if (this.taxSummaryExpanded) {
      this.taxSummary = null;
      this.loadTaxSummary();
    }
    this.loadTaxYears();
  }

  onTransactionCancelled(): void {
    this.showAddTransactionModal = false;
  }

  onBuyHistoryClick(holdingId: number): void {
    this.selectedHoldingId = holdingId;
    this.showBuyHistoryModal = true;
  }

  onHistoryModalClosed(): void {
    this.showBuyHistoryModal = false;
    this.selectedHoldingId = null;
  }

  onHistoryChanged(): void {
    // A transaction was deleted — reload portfolio data so holdings & metrics stay in sync
    this.loadDashboard();
    this.loadProjection();
    // Refresh tax summary if the panel is open
    if (this.taxSummaryExpanded) {
      this.taxSummary = null;
      this.loadTaxSummary();
    }
    this.loadTaxYears();
  }


  copyPortfolioTotal(): void {
    if (this.dashboard) {
      this.projectionSettings.startAmount = Math.round(this.dashboard.header.totalHoldingsAmount);
      this.cdr.markForCheck();
    }
  }

  // ── Tax Year Summary ────────────────────────────────────────────────────────

  taxYears: number[] = [];
  selectedTaxYear: number = new Date().getFullYear();
  taxSummary: TaxYearSummaryDto | null = null;
  taxSummaryLoading = false;
  taxSummaryExpanded = false;

  loadTaxYears(): void {
    this.apiService.getTaxYears().subscribe({
      next: (years) => {
        this.taxYears = years;
        if (years.length > 0 && !years.includes(this.selectedTaxYear)) {
          this.selectedTaxYear = years[0];
        }
        this.cdr.markForCheck();
      },
      error: () => this.cdr.markForCheck()
    });
  }

  toggleTaxSummary(): void {
    this.taxSummaryExpanded = !this.taxSummaryExpanded;
    if (this.taxSummaryExpanded && this.taxSummary === null) {
      this.loadTaxSummary();
    }
    this.cdr.markForCheck();
  }

  onTaxYearChange(): void {
    this.taxSummary = null;
    this.loadTaxSummary();
  }

  loadTaxSummary(): void {
    this.taxSummaryLoading = true;
    this.cdr.markForCheck();
    this.apiService.getTaxSummary(this.selectedTaxYear).subscribe({
      next: (data) => {
        this.taxSummary = data;
        this.taxSummaryLoading = false;
        this.cdr.markForCheck();
      },
      error: () => {
        this.taxSummaryLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

}

